# ---- scipy fallback shims (offline-portable; used only if scipy is absent) --
try:
    from scipy.special import spherical_jn as _scipy_spherical_jn  # type: ignore
    _HAVE_SCIPY_SPECIAL = True
except Exception:  # pragma: no cover
    _HAVE_SCIPY_SPECIAL = False

def _fallback_spherical_jn(n, x):
    """Pure-numpy spherical Bessel j_n via upward recurrence (vectorized)."""
    import numpy as _np
    x = _np.asarray(x, dtype=float)
    tiny = _np.where(_np.abs(x) < 1e-12, 1e-12, x)
    j0 = _np.sin(tiny) / tiny
    if n == 0:
        return _np.where(_np.abs(x) < 1e-12, 1.0, j0)
    j1 = _np.sin(tiny) / tiny**2 - _np.cos(tiny) / tiny
    if n == 1:
        return _np.where(_np.abs(x) < 1e-12, 0.0, j1)
    jm, jc = j0, j1
    for k in range(1, int(n)):
        jn = (2 * k + 1) / tiny * jc - jm
        jm, jc = jc, jn
    return _np.where(_np.abs(x) < 1e-12, 0.0, jc)

def spherical_jn(n, x):  # canonical symbol used by the sphere modules
    if _HAVE_SCIPY_SPECIAL:
        return _scipy_spherical_jn(n, x)
    return _fallback_spherical_jn(n, x)

def brentq(f, a, b, xtol=1e-12, maxiter=200):
    """Bisection fallback with the brentq signature (deterministic)."""
    try:
        from scipy.optimize import brentq as _b  # type: ignore
        return _b(f, a, b, xtol=xtol, maxiter=maxiter)
    except Exception:
        fa, fb = f(a), f(b)
        if fa * fb > 0:
            raise ValueError("brentq fallback: no sign change in bracket")
        for _ in range(maxiter):
            m = 0.5 * (a + b)
            fm = f(m)
            if abs(fm) < xtol or (b - a) < xtol:
                return m
            if fa * fm <= 0:
                b, fb = m, fm
            else:
                a, fa = m, fm
        return 0.5 * (a + b)


# ---- uma/config.py ---------------------------------------------------
"""
uma.config -- Configuration dataclasses for the UMA pipeline.
"""

from dataclasses import dataclass, field
from typing import Optional


@dataclass
class GridConfig:
    """Spatial grid for psi(x,y) and projection."""
    N: int = 32           # grid points per axis
    L: float = 1.0        # box side length (m)
    n_modes: int = 4      # number of leading Fourier modes per axis (z dim = (2n+1)^2 - 1)


@dataclass
class GENERICConfig:
    """GENERIC dynamics parameters."""
    dt: float = 0.04
    diffusion: float = 0.05      # M scale (dissipative operator coefficient)
    advection: float = 0.10      # J scale (skew-symmetric Poisson part)
    reaction: float = 0.50       # double-well coefficient lambda
    noise: float = 0.0           # bounded Wiener amplitude (0 = deterministic)
    kT: float = 1.0              # thermal scale


@dataclass
class FilterConfig:
    """Linear-Gaussian Kalman filter on z."""
    process_noise: float = 0.05
    obs_noise: float = 0.10
    init_cov: float = 1.0


@dataclass
class Config:
    """Top-level UMA configuration."""
    grid: GridConfig = field(default_factory=GridConfig)
    generic: GENERICConfig = field(default_factory=GENERICConfig)
    filter: FilterConfig = field(default_factory=FilterConfig)
    seed: int = 42

    def real_dim(self) -> int:
        """Dimension of the real-valued projected state z."""
        # leading Fourier modes (excluding DC), real and imag parts
        n = self.grid.n_modes
        # number of complex modes (excluding DC) in (2n+1)x(2n+1) low-pass box
        n_complex = (2 * n + 1) ** 2 - 1
        return 2 * n_complex


# ---- uma/core/state.py -----------------------------------------------
"""
uma.core.state -- FieldPosterior: Gaussian posterior over projected state z.
"""

import numpy as np
from dataclasses import dataclass


@dataclass
class FieldPosterior:
    """
    Gaussian posterior over the real-valued projected state z.

    mean : (d,) real array
    cov  : (d, d) symmetric positive-definite array
    """
    mean: np.ndarray
    cov: np.ndarray

    @classmethod
    def initial(cls, d: int, init_cov: float = 1.0):
        return cls(mean=np.zeros(d), cov=init_cov * np.eye(d))

    @classmethod
    def full(cls, mean: np.ndarray, Sigma: np.ndarray) -> "FieldPosterior":
        """Single-rep convenience: build a full-cov posterior."""
        return cls(mean=np.asarray(mean, dtype=float),
                   cov=np.asarray(Sigma, dtype=float))

    # Aliases for the canonical multi-rep API (single-rep here).
    @property
    def Sigma(self) -> np.ndarray:
        return self.cov

    @property
    def representation(self) -> str:
        return "full"

    @property
    def dim(self) -> int:
        return self.mean.shape[0]

    def copy(self) -> "FieldPosterior":
        return FieldPosterior(mean=self.mean.copy(), cov=self.cov.copy())

    def total_variance(self) -> float:
        return float(np.trace(self.cov))

    def log_det(self) -> float:
        sign, ld = np.linalg.slogdet(self.cov)
        if sign <= 0:
            return -np.inf
        return float(ld)


# ---- uma/core/projection.py ------------------------------------------
"""
uma.core.projection -- map psi(x,y) <-> z (leading Fourier modes).

The projection takes the 2D complex field and extracts its (2n+1)^2 - 1
leading Fourier modes (DC excluded), packed as a real vector of length
2 * ((2n+1)^2 - 1). The lift inverts this exactly: the operator is a
partial isometry between psi and the band-limited subspace.

This is the geometric piece that lets the Kalman filter and constraint
projections run on a low-dimensional state z without losing the band-
limited spectral content of the field.
"""

import numpy as np


class UmaFieldProjection:
    """Project psi(x,y) onto leading Fourier modes."""

    def __init__(self, N: int = 32, n_modes: int = 4):
        self.N = N
        self.n_modes = n_modes
        # FFT-frequency masks
        kx = np.fft.fftfreq(N, d=1.0 / N).astype(int)  # integer k indices
        ky = np.fft.fftfreq(N, d=1.0 / N).astype(int)
        KX, KY = np.meshgrid(kx, ky, indexing="ij")
        mask = (np.abs(KX) <= n_modes) & (np.abs(KY) <= n_modes)
        # exclude DC
        mask[0, 0] = False
        self._mask = mask
        self._idx = np.argwhere(mask)  # list of (i, j) grid indices
        self._n_complex = self._idx.shape[0]

    @property
    def real_dim(self) -> int:
        """Dimension of the real-valued projected state z."""
        return 2 * self._n_complex

    @property
    def complex_dim(self) -> int:
        return self._n_complex

    def project(self, psi: np.ndarray) -> np.ndarray:
        """Project psi(N,N) -> real-valued z of length 2 * n_complex."""
        psi = np.asarray(psi)
        F = np.fft.fft2(psi) / (self.N * self.N)
        coeffs = F[self._mask]
        return np.concatenate([coeffs.real, coeffs.imag])

    def lift(self, z: np.ndarray) -> np.ndarray:
        """Lift z back to a band-limited psi(N,N) via inverse FFT."""
        z = np.asarray(z, dtype=float).ravel()
        n = self._n_complex
        re = z[:n]
        im = z[n:2 * n]
        coeffs = re + 1j * im
        F = np.zeros((self.N, self.N), dtype=complex)
        F[self._mask] = coeffs
        # enforce Hermitian symmetry only if input was real -- here psi is complex,
        # so we keep the asymmetric spectrum.
        psi = np.fft.ifft2(F) * (self.N * self.N)
        return psi


# ---- uma/core/filter.py ----------------------------------------------
"""
uma.core.filter -- Linear-Gaussian Kalman filter on z.
"""

import numpy as np
pass  # uma import flattened (symbols are top-level)


class KalmanFilter:
    """
    Linear-Gaussian Kalman filter operating on the projected state z.

    predict(F, Q):
        m_pred = F m
        P_pred = F P F^T + Q

    update(y, H, R):
        S = H P H^T + R
        K = P H^T S^{-1}
        m_new = m + K (y - H m)
        P_new = (I - K H) P (I - K H)^T + K R K^T   (Joseph form)
    """

    def __init__(self, posterior: FieldPosterior, process_noise: float = 0.05):
        self.posterior = posterior
        self.q = float(process_noise)

    def predict(self, F: np.ndarray | None = None, Q: np.ndarray | None = None) -> FieldPosterior:
        d = self.posterior.dim
        if F is None:
            F = np.eye(d)
        if Q is None:
            Q = self.q * np.eye(d)
        m = self.posterior.mean
        P = self.posterior.cov
        m_new = F @ m
        P_new = F @ P @ F.T + Q
        # symmetrize
        P_new = 0.5 * (P_new + P_new.T)
        self.posterior = FieldPosterior(mean=m_new, cov=P_new)
        return self.posterior

    def update(self, y: np.ndarray, H: np.ndarray, R: np.ndarray) -> FieldPosterior:
        m = self.posterior.mean
        P = self.posterior.cov
        innov = y - H @ m
        S = H @ P @ H.T + R
        # solve K S = P H^T  ->  K = P H^T S^{-1}
        K = np.linalg.solve(S.T, (H @ P.T)).T
        m_new = m + K @ innov
        I_KH = np.eye(P.shape[0]) - K @ H
        P_new = I_KH @ P @ I_KH.T + K @ R @ K.T
        # symmetrize
        P_new = 0.5 * (P_new + P_new.T)
        self.posterior = FieldPosterior(mean=m_new, cov=P_new)
        return self.posterior


# ---- uma/dynamics/generic.py -----------------------------------------
"""
uma.dynamics.generic -- GENERIC dynamics for the complex field psi.

H[psi] = sum [ |grad psi|^2 / 2 + V(psi) ]   on a unit-spacing grid
V(psi) = -|psi|^2 / 2 + lambda |psi|^4 / 4   (double-well in |psi|)

dH/dpsi^* (Wirtinger derivative):
    dH/dpsi^* = -laplacian(psi) + dV/dpsi^*
    dV/dpsi^* = -psi/2 + lambda |psi|^2 psi

GENERIC step:
    psi <- psi + dt * (J grad H + M grad H)   with the convention that
    J is the skew (Hamiltonian) part and M is the symmetric (dissipative)
    part. Both act through the gradient grad_H = dH/dpsi^*.

    Skew part:   1j * grad_H            (rotational, Schroedinger-like)
    Symmetric:  -diffusion * grad_H     (gradient flow on H)

The MSR response field is the exact derivative:
    psi_hat = -dH/dpsi^*

This is the field that drives the canonical stress-energy tensor in
msr.tensor_bridge.
"""

import numpy as np
pass  # uma import flattened (symbols are top-level)


def uma_laplacian_periodic(psi: np.ndarray) -> np.ndarray:
    """5-point Laplacian with periodic boundary conditions, dx = 1."""
    return (np.roll(psi, 1, axis=0) + np.roll(psi, -1, axis=0)
            + np.roll(psi, 1, axis=1) + np.roll(psi, -1, axis=1)
            - 4.0 * psi)


def hamiltonian(psi: np.ndarray, lam: float = 0.5) -> float:
    """
    H[psi] = sum [ |grad psi|^2 / 2 - |psi|^2 / 2 + lam/4 * |psi|^4 ]
    on a unit-spacing periodic grid.
    """
    dpx = np.roll(psi, -1, axis=0) - psi
    dpy = np.roll(psi, -1, axis=1) - psi
    grad_sq = (np.abs(dpx) ** 2 + np.abs(dpy) ** 2)
    V = -0.5 * np.abs(psi) ** 2 + 0.25 * lam * np.abs(psi) ** 4
    return float(np.sum(0.5 * grad_sq + V))


def msr_response(psi: np.ndarray, lam: float = 0.5) -> np.ndarray:
    """
    psi_hat = -dH/dpsi^* = laplacian(psi) - dV/dpsi^*
            = laplacian(psi) - ( -psi/2 + lam |psi|^2 psi )
            = laplacian(psi) + psi/2 - lam |psi|^2 psi

    This is the response field that drives the Noether stress-energy
    tensor T_mu_nu in msr.tensor_bridge. It is the exact (Wirtinger)
    derivative, not a finite-difference approximation.
    """
    return uma_laplacian_periodic(psi) + 0.5 * psi - lam * np.abs(psi) ** 2 * psi


def entropy_S(psi: np.ndarray) -> float:
    """
    Shannon-like entropy of |psi|^2 normalized as a probability density.
    Used for tracking entropy production in the GENERIC step.
    """
    p = np.abs(psi) ** 2
    Z = float(p.sum())
    if Z <= 0:
        return 0.0
    p = p / Z
    p = np.clip(p, 1e-18, None)
    return float(-(p * np.log(p)).sum())


class GENERICDynamics:
    """
    GENERIC step:
        psi <- psi + dt [ 1j * advection * grad_H  -  diffusion * grad_H ]
              + sqrt(2 * diffusion * kT * dt) * eta   (bounded Wiener)

    with grad_H = dH/dpsi^* = -laplacian + dV/dpsi^* (sign-corrected so
    that gradient flow descends H).
    """

    def __init__(self, cfg: GENERICConfig | None = None):
        self.cfg = cfg if cfg is not None else GENERICConfig()
        self._rng: np.random.Generator | None = None

    def seed(self, seed: int) -> None:
        self._rng = np.random.default_rng(seed)

    def step(self, psi: np.ndarray) -> np.ndarray:
        cfg = self.cfg
        # grad_H = -psi_hat (since psi_hat = -dH/dpsi^*)
        psi_hat = msr_response(psi, lam=cfg.reaction)
        grad_H = -psi_hat
        # skew (J): 1j * grad_H ;  diss (M): -grad_H
        rhs = 1j * cfg.advection * grad_H - cfg.diffusion * grad_H
        psi_new = psi + cfg.dt * rhs
        if cfg.noise > 0:
            if self._rng is None:
                self._rng = np.random.default_rng(0)
            sigma = (2.0 * cfg.diffusion * cfg.kT * cfg.dt) ** 0.5
            eta = self._rng.standard_normal(psi.shape) + 1j * self._rng.standard_normal(psi.shape)
            psi_new = psi_new + cfg.noise * sigma * eta
        return psi_new

    def hamiltonian(self, psi: np.ndarray) -> float:
        return hamiltonian(psi, lam=self.cfg.reaction)

    def entropy(self, psi: np.ndarray) -> float:
        return entropy_S(psi)

    def dH_dpsi_conj(self, psi: np.ndarray) -> np.ndarray:
        """
        dH/d psi^* = -psi_hat. The pipeline uses this to compute
        psi_hat = -dH/d psi^*. Both forms are exact.
        """
        return -msr_response(psi, lam=self.cfg.reaction)


# ---- uma/observations/base.py ----------------------------------------
"""
uma.observations.base -- Observation operators feeding the Kalman filter.
"""

import numpy as np
from dataclasses import dataclass


class Observation:
    """Abstract observation operator y = H z + noise."""

    @property
    def H(self) -> np.ndarray:
        raise NotImplementedError

    @property
    def R(self) -> np.ndarray:
        raise NotImplementedError

    @property
    def dim_y(self) -> int:
        return self.H.shape[0]


@dataclass
class GaussianObservation(Observation):
    """Linear-Gaussian observation: y = H z + N(0, R)."""
    _H: np.ndarray
    _R: np.ndarray

    def __init__(self, H: np.ndarray, R: np.ndarray | float):
        self._H = np.asarray(H, dtype=float)
        if np.ndim(R) == 0:
            R = float(R) * np.eye(self._H.shape[0])
        self._R = np.asarray(R, dtype=float)

    @property
    def H(self) -> np.ndarray:
        return self._H

    @property
    def R(self) -> np.ndarray:
        return self._R


# ---- uma/msr/tensor_bridge.py ----------------------------------------
"""
tensor_bridge.py -- Live tensor tracking layer for the UMA pipeline.

Maps the full T_munu <-> G_munu^(1) bridge at every step.

PHYSICS:
    T_munu(x, y, t)   -- MSR stress-energy tensor from psi and psi_hat = -dH/dpsi*
    h_munu(x, y, t)   -- metric perturbation derived from T_00 via Poisson:
                          nabla^2 h_munu = -16 pi G T_munu  (linearized 2+1D Einstein)
                          Solved via FFT: h(k) = T(k) / (-|k|^2 / 16 pi G)
    G_munu^(1)[h]     -- linearized Einstein tensor from h
    kappa(t)          -- proportionality constant: <T> = kappa * G
    residual(t)       -- ||T - kappa G||_F  ; -> 0 at closure means
                          Einstein equation is satisfied.

CLOSURE CONDITION:
    Semantic closure (friction -> 0) AND Einstein residual -> 0
    are now the same physical event measured two ways.
"""

import math
from dataclasses import dataclass, field
from typing import List, Optional

import numpy as np


# ---------------------------------------------------------------------------
# Tensor record
# ---------------------------------------------------------------------------

@dataclass
class TensorRecord:
    t: float
    T: np.ndarray              # (2,2) spatially-averaged stress tensor
    G: np.ndarray              # (2,2) linearized Einstein tensor
    h: np.ndarray              # (2,2) metric perturbation (spatial mean)
    kappa: float               # <T> = kappa * G
    residual_norm: float       # ||T - kappa*G||_F
    relative_residual: float   # residual / ||T||
    einstein_satisfied: bool   # residual < threshold


# ---------------------------------------------------------------------------
# Core computations
# ---------------------------------------------------------------------------

def _stress_tensor_spatial(
    psi: np.ndarray, psi_hat: np.ndarray, dx: float = 1.0
) -> np.ndarray:
    """
    Compute T_munu(x, y) as a (2, 2, N, N) spatial tensor field.

        T_munu = d_mu psi_hat * d_nu psi + d_nu psi_hat * d_mu psi
                 - eta_munu * (d^alpha psi_hat * d_alpha psi)

    Uses real parts for the geometric (metric-coupled) component.
    """
    N = psi.shape[0]
    dpsi   = [np.gradient(psi.real,     dx, axis=i) for i in range(2)]
    dphat  = [np.gradient(psi_hat.real, dx, axis=i) for i in range(2)]
    T = np.zeros((2, 2, N, N))
    for mu in range(2):
        for nu in range(2):
            T[mu, nu] = dphat[mu] * dpsi[nu] + dphat[nu] * dpsi[mu]
    trace = sum(dphat[i] * dpsi[i] for i in range(2))
    T[0, 0] -= trace
    T[1, 1] -= trace
    return T


def _metric_from_T(
    T_spatial: np.ndarray, G_newton: float = 1.0, dx: float = 1.0
) -> np.ndarray:
    """
    Derive metric perturbation h_munu from T_munu via the linearized
    2+1D Einstein (Poisson) equation:

        nabla^2 h_munu = -16 pi G T_munu

    Solved via FFT. Returns spatial h_munu as (2, 2, N, N).
    """
    N = T_spatial.shape[-1]
    kx = 2 * np.pi * np.fft.fftfreq(N, d=dx)
    KX, KY = np.meshgrid(kx, kx)
    k2 = KX ** 2 + KY ** 2
    k2[0, 0] = 1.0    # avoid division by zero (DC = gauge freedom)
    h = np.zeros_like(T_spatial)
    for mu in range(2):
        for nu in range(2):
            T_k = np.fft.fft2(T_spatial[mu, nu])
            h_k = -16 * math.pi * G_newton * T_k / k2
            h_k[0, 0] = 0.0    # fix gauge: zero DC component
            h[mu, nu] = np.fft.ifft2(h_k).real
    return h


def _einstein_tensor_from_h(h_spatial: np.ndarray, dx: float = 1.0) -> np.ndarray:
    """
    Linearized Einstein tensor G_munu^(1)[h] as (2, 2, N, N).

        G_munu^(1) = (1/2)( d^alpha d_mu h_(alpha,nu) + d^alpha d_nu h_(alpha,mu)
                          - box h_munu - d_mu d_nu h
                          - eta_munu (d^alpha d^beta h_(alpha,beta) - box h) )

    In 2+1D spatial (static limit) this reduces to a 2D Laplacian form.
    """
    N = h_spatial.shape[-1]
    G = np.zeros_like(h_spatial)
    h_trace = h_spatial[0, 0] + h_spatial[1, 1]

    def lap(f):
        return (np.roll(f, 1, 0) + np.roll(f, -1, 0)
                + np.roll(f, 1, 1) + np.roll(f, -1, 1) - 4 * f) / dx ** 2

    def grad2(f, mu, nu):
        df = np.gradient(f, dx, axis=mu)
        return np.gradient(df, dx, axis=nu)

    div_h = [
        sum(np.gradient(h_spatial[mu, nu], dx, axis=mu) for mu in range(2))
        for nu in range(2)
    ]
    div2_h = sum(
        grad2(h_spatial[mu, nu], mu, nu)
        for mu in range(2) for nu in range(2)
    )

    for mu in range(2):
        for nu in range(2):
            term1 = np.gradient(div_h[nu], dx, axis=mu)
            term2 = np.gradient(div_h[mu], dx, axis=nu)
            term3 = -lap(h_spatial[mu, nu])
            term4 = -grad2(h_trace, mu, nu)
            eta_mn = 1.0 if mu == nu else 0.0
            term5 = -eta_mn * (div2_h - lap(h_trace))
            G[mu, nu] = 0.5 * (term1 + term2 + term3 + term4 + term5)
    return G


def _spatial_mean(tensor: np.ndarray) -> np.ndarray:
    """Average (2, 2, N, N) tensor over spatial dims -> (2, 2)."""
    return tensor.mean(axis=(-2, -1))


# ---------------------------------------------------------------------------
# TensorBridge -- live tracker
# ---------------------------------------------------------------------------

class TensorBridge:
    """
    Tracks T_munu, h_munu, G_munu^(1), kappa, and residual at every pipeline step.

    Usage:
        bridge = TensorBridge(cfg)
        # each step:
        record = bridge.update(psi, psi_hat, t)
        # at closure:
        bridge.is_einstein_satisfied    # True when residual -> 0
    """

    def __init__(
        self,
        cfg=None,
        residual_threshold: float = 0.1,
        dx: Optional[float] = None,
        window: int = 30,
    ):
        N = cfg.grid.N if cfg else 32
        self.dx = dx if dx else 1.0 / N
        self.threshold = residual_threshold
        self.window = window
        self.records: List[TensorRecord] = []
        self._T_buffer: List[np.ndarray] = []

    def update(self, psi: np.ndarray, psi_hat: np.ndarray, t: float) -> TensorRecord:
        """Compute T_munu, h_munu, G_munu^(1), kappa, residual for this step."""
        # 1. Stress tensor (spatial)
        T_spatial = _stress_tensor_spatial(psi, psi_hat, self.dx)
        # 2. Metric perturbation from T via Poisson
        h_spatial = _metric_from_T(T_spatial, G_newton=1.0, dx=self.dx)
        # 3. Einstein tensor from metric
        G_spatial = _einstein_tensor_from_h(h_spatial, self.dx)
        # 4. Spatially average to (2, 2) matrices
        T_inst = _spatial_mean(T_spatial)
        G = _spatial_mean(G_spatial)
        h = _spatial_mean(h_spatial)

        # Time-average T over rolling window
        self._T_buffer.append(T_inst)
        if len(self._T_buffer) > self.window:
            self._T_buffer.pop(0)
        T = np.mean(self._T_buffer, axis=0)

        # 5. Proportionality kappa: <T> = kappa * G
        T_norm = float(np.linalg.norm(T))
        G_norm = float(np.linalg.norm(G))
        if G_norm > 1e-15:
            kappa = float(np.sum(T * G) / (G_norm ** 2))
        else:
            kappa = 0.0

        # 6. Residual
        residual_norm = float(np.linalg.norm(T - kappa * G))
        relative_res = residual_norm / (T_norm + 1e-15)
        satisfied = relative_res < self.threshold

        rec = TensorRecord(
            t=t, T=T, G=G, h=h,
            kappa=kappa,
            residual_norm=residual_norm,
            relative_residual=relative_res,
            einstein_satisfied=satisfied,
        )
        self.records.append(rec)
        return rec

    @property
    def is_einstein_satisfied(self) -> bool:
        return bool(self.records and self.records[-1].einstein_satisfied)

    @property
    def residual_history(self) -> np.ndarray:
        return np.array([r.relative_residual for r in self.records])

    @property
    def kappa_history(self) -> np.ndarray:
        return np.array([r.kappa for r in self.records])

    def summary(self) -> dict:
        if not self.records:
            return {"status": "no_data"}
        final = self.records[-1]
        rh = self.residual_history
        return {
            "T_final": final.T.tolist(),
            "G_final": final.G.tolist(),
            "h_final": final.h.tolist(),
            "kappa_final": round(final.kappa, 6),
            "residual_norm_final": round(final.residual_norm, 8),
            "relative_residual": round(final.relative_residual, 6),
            "einstein_satisfied": final.einstein_satisfied,
            "residual_min": round(float(rh.min()), 6),
            "residual_mean_last10": round(float(rh[-10:].mean()), 6),
            "n_steps": len(self.records),
        }


# ---- uma/msr/stress_energy.py ----------------------------------------
"""
uma.msr.stress_energy -- Canonical Noether T_munu from the GENERIC Lagrangian.

Whenever you want T_munu computed strictly from H[psi] (not from ad-hoc
gradient products of the response field), use uma_noether_stress_tensor.

This is the cleanly derived form referenced in the integration session
notes. It uses the same Hamiltonian as uma.dynamics.generic.hamiltonian.
"""

import numpy as np

pass  # uma import flattened (symbols are top-level)


def uma_noether_stress_tensor(
    psi: np.ndarray, lam: float = 0.5, dx: float = 1.0
) -> tuple[np.ndarray, np.ndarray]:
    """
    Canonical stress-energy tensor T_munu from GENERIC Lagrangian.

    L = (1/2) |grad psi|^2 - V(psi) ; V = -|psi|^2/2 + lam |psi|^4 / 4

    T_munu = d_mu psi^* d_nu psi + d_nu psi^* d_mu psi
             - eta_munu ( |grad psi|^2 - 2 V(psi) )

    Returns (T_spatial, T00_field) where T_spatial is (2, 2, N, N) and
    T00_field is the energy density (N, N) used for h via Poisson.
    """
    N = psi.shape[0]
    dpsi = [np.gradient(psi, dx, axis=i) for i in range(2)]
    grad_sq = sum(np.abs(dpsi[i]) ** 2 for i in range(2))
    V = -0.5 * np.abs(psi) ** 2 + 0.25 * lam * np.abs(psi) ** 4

    T = np.zeros((2, 2, N, N))
    for mu in range(2):
        for nu in range(2):
            T[mu, nu] = (
                np.real(np.conj(dpsi[mu]) * dpsi[nu])
                + np.real(np.conj(dpsi[nu]) * dpsi[mu])
            )
    diag = grad_sq - 2.0 * V
    T[0, 0] -= diag
    T[1, 1] -= diag
    # T_00 energy density: kinetic + potential
    T00 = grad_sq * 0.5 + V
    return T, T00


def verify_T_consistency(
    psi: np.ndarray, lam: float = 0.5, dx: float = 1.0
) -> dict:
    """
    Compare the spatial integral of T_00 to the GENERIC Hamiltonian H[psi].
    Returns relative error -- should be O(dx) for periodic boundary conditions.
    """
    H = hamiltonian(psi, lam=lam)
    _, T00 = uma_noether_stress_tensor(psi, lam=lam, dx=dx)
    H_from_T = float(T00.sum())
    return {
        "H_GENERIC": H,
        "H_from_T00": H_from_T,
        "abs_error": abs(H - H_from_T),
        "rel_error": abs(H - H_from_T) / (abs(H) + 1e-15),
    }


def verify_T_equals_lichnerowicz(
    h_pert: np.ndarray, m: float = 0.1, N: int = 32, seed: int = 0
) -> dict:
    """
    One-shot consistency check used by the pipeline at start-up.

    Fixed massive-scalar test field psi on a constant metric perturbation
    h_pert (2x2). Computes:
        T_munu (Noether)
        Lichnerowicz/Linearized-Einstein G_munu^(1)[h_pert]
    Then reports the cosine similarity between the two flattened tensors.
    A value close to +/-1 means T is proportional to G^(1).
    """
    rng = np.random.default_rng(seed)
    psi = (rng.standard_normal((N, N)) + 1j * rng.standard_normal((N, N))) * m
    T, T00 = uma_noether_stress_tensor(psi, lam=0.0, dx=1.0)
    T_avg = T.mean(axis=(-2, -1))   # (2, 2)
    # Linearized Einstein on a homogeneous metric perturbation: G^(1) = -box h
    # which on a constant h is zero; we use the trace-reversed mass-shell form:
    h = np.asarray(h_pert, dtype=float)
    # G^(1)_ij = m^2 * (h_ij - 0.5 trace(h) eta_ij)
    eta = np.eye(2)
    G = m * m * (h - 0.5 * np.trace(h) * eta)
    Tf = T_avg.flatten()
    Gf = G.flatten()
    denom = (np.linalg.norm(Tf) * np.linalg.norm(Gf)) + 1e-15
    cos = float(np.dot(Tf, Gf) / denom)
    return {
        "T_avg": T_avg.tolist(),
        "G_lin": G.tolist(),
        "cosine_similarity": cos,
        "norm_T": float(np.linalg.norm(Tf)),
        "norm_G": float(np.linalg.norm(Gf)),
    }


# ---- uma/msr/metric_solver.py ----------------------------------------
"""
metric_solver.py -- Self-consistent iterative metric solver.

Solves for g_munu self-consistently from the field psi.

CURRENT (one-way):
    psi -> T_munu -> h_munu (Poisson) -> G_munu^(1)[h]
    (metric has no feedback into the field evolution.)

THIS MODULE (self-consistent):
    psi^(n) -> T_munu^(n) -> h_munu^(n) -> modified dynamics -> psi^(n+1)
    The metric feeds back into the field through the curved d'Alembertian:
        box_g psi = box_eta psi + h^munu d_mu d_nu psi + ...

    Iteration continues until ||h^(n) - h^(n-1)|| / ||h^(n)|| < tol.

PHYSICAL MEANING:
    At convergence, psi* and h* are mutually consistent. The field
    produces the metric that curves the space in which it evolves.
    Genuine GR solution -- not a verification of a known result.
"""

from dataclasses import dataclass, field
from typing import List, Tuple

import numpy as np

pass  # uma import flattened (symbols are top-level)
pass  # uma import flattened (symbols are top-level)


# ---------------------------------------------------------------------------
# State
# ---------------------------------------------------------------------------

@dataclass
class MetricState:
    """Current state of the self-consistent metric iteration."""
    iteration: int
    h: np.ndarray         # (2, 2, N, N) metric perturbation
    psi: np.ndarray       # (N, N) field at this iteration
    psi_hat: np.ndarray   # (N, N) MSR response
    T_avg: np.ndarray     # (2, 2) spatial-mean stress
    h_avg: np.ndarray     # (2, 2) spatial-mean perturbation
    delta_h_norm: float   # ||h - h_prev||
    rel_change: float     # delta_h_norm / ||h||
    converged: bool


@dataclass
class MetricSolveResult:
    history: List[MetricState] = field(default_factory=list)
    final: MetricState = None
    converged: bool = False
    n_iters: int = 0


# ---------------------------------------------------------------------------
# Solver
# ---------------------------------------------------------------------------

class IterativeMetricSolver:
    """
    Iterates psi <-> h until they stop changing (within tol).

    The dynamics are perturbed by h via a simple metric-coupling step:
        psi -> psi + dt * (eta_step + (h^00 + h^11) Lap psi)
    which is the leading curved-d'Alembertian correction in 2D.
    """

    def __init__(
        self,
        cfg,
        dt: float = 0.04,
        max_iters: int = 50,
        tol: float = 1e-3,
        coupling: float = 1.0,
    ):
        self.cfg = cfg
        self.dt = dt
        self.max_iters = max_iters
        self.tol = tol
        self.coupling = coupling
        self.dx = 1.0 / cfg.grid.N
        self.dynamics = GENERICDynamics(cfg.generic)

    def _laplacian(self, psi: np.ndarray) -> np.ndarray:
        return (
            np.roll(psi, 1, 0) + np.roll(psi, -1, 0)
            + np.roll(psi, 1, 1) + np.roll(psi, -1, 1) - 4 * psi
        ) / (self.dx ** 2)

    def _curved_step(self, psi: np.ndarray, h: np.ndarray) -> np.ndarray:
        """One step of psi evolution under the metric h (leading correction)."""
        eta_step = self.dynamics.step(psi)
        h_trace = h[0, 0] + h[1, 1]
        lap = self._laplacian(psi)
        return eta_step + self.dt * self.coupling * h_trace * lap

    def solve(
        self,
        psi_initial: np.ndarray,
        psi_hat_initial: np.ndarray = None,
        n_field_steps_per_iter: int = 5,
    ) -> MetricSolveResult:
        """Iterate to a self-consistent (psi*, h*) pair."""
        N = psi_initial.shape[0]
        psi = psi_initial.copy()
        psi_hat = (
            psi_hat_initial.copy() if psi_hat_initial is not None
            else msr_response(psi, lam=self.cfg.generic.reaction)
        )
        h = np.zeros((2, 2, N, N))
        history: List[MetricState] = []

        for it in range(self.max_iters):
            # 1. compute T from current (psi, psi_hat)
            T_spatial = _stress_tensor_spatial(psi, psi_hat, dx=self.dx)
            # 2. solve Poisson for h
            h_new = _metric_from_T(T_spatial, G_newton=1.0, dx=self.dx)
            # 3. norms
            denom = np.linalg.norm(h_new) + 1e-15
            delta = np.linalg.norm(h_new - h)
            rel = delta / denom
            converged = rel < self.tol and it > 0
            T_avg = T_spatial.mean(axis=(-2, -1))
            h_avg = h_new.mean(axis=(-2, -1))
            state = MetricState(
                iteration=it,
                h=h_new, psi=psi.copy(), psi_hat=psi_hat.copy(),
                T_avg=T_avg, h_avg=h_avg,
                delta_h_norm=float(delta), rel_change=float(rel),
                converged=converged,
            )
            history.append(state)
            if converged:
                break
            # 4. evolve psi under the new metric
            h = h_new
            for _ in range(n_field_steps_per_iter):
                psi = self._curved_step(psi, h)
            psi_hat = msr_response(psi, lam=self.cfg.generic.reaction)

        return MetricSolveResult(
            history=history,
            final=history[-1],
            converged=history[-1].converged,
            n_iters=len(history),
        )


# ---- uma/msr/gr_fixed_point.py ---------------------------------------
"""
gr_fixed_point.py -- Find psi* that minimizes the Einstein residual.

Runs N trajectories from different initial conditions; finds the one
with the minimum ||<T_munu> - kappa G_munu^(1)||_F at closure. Then
gradient-refines from that seed to find psi*.

The fixed point psi* satisfies:
    <T_munu[psi*]> = kappa * G_munu^(1)[h[psi*]]

A genuine GR-consistent field configuration derived from UMA dynamics.
"""

from dataclasses import dataclass
from typing import List, Optional

import numpy as np

pass  # uma import flattened (symbols are top-level)
pass  # uma import flattened (symbols are top-level)


@dataclass
class UmaTrajectoryResult:
    seed: int
    einstein_residual_final: float
    einstein_residual_min: float
    closure_step: Optional[int]
    z_final: np.ndarray
    h_final: np.ndarray   # (2, 2)
    kappa: float


@dataclass
class GRFixedPoint:
    z_star: np.ndarray
    h_star: np.ndarray
    T_star: np.ndarray
    G_star: np.ndarray
    residual_star: float
    seed_star: int
    trajectories: List[UmaTrajectoryResult]


class GRFixedPointSearch:
    """Brute-force seed search + light gradient refinement."""

    def __init__(
        self,
        cfg: Optional[Config] = None,
        n_seeds: int = 8,
        n_steps: int = 200,
        dt: float = 0.04,
    ):
        self.cfg = cfg or Config()
        self.n_seeds = n_seeds
        self.n_steps = n_steps
        self.dt = dt

    def _run_seed(self, seed: int) -> UmaTrajectoryResult:
        cfg = self.cfg
        rng = np.random.default_rng(seed)
        N = cfg.grid.N
        client = UMAClient(cfg)
        psi0 = 0.3 * (
            rng.standard_normal((N, N)) + 1j * rng.standard_normal((N, N))
        )
        client.initialize(psi0, dt=self.dt)
        bridge = TensorBridge(cfg, residual_threshold=0.15, window=20)

        closure_step = None
        for step in range(self.n_steps):
            client.evolve(self.dt)
            psi = client.psi
            psi_hat = -client.dynamics.dH_dpsi_conj(psi)
            rec = bridge.update(psi, psi_hat, t=step * self.dt)
            if rec.einstein_satisfied and closure_step is None:
                closure_step = step

        recs = bridge.records
        rh = [r.relative_residual for r in recs]
        return UmaTrajectoryResult(
            seed=seed,
            einstein_residual_final=rh[-1],
            einstein_residual_min=float(min(rh)),
            closure_step=closure_step,
            z_final=client.filter.posterior.mean.copy(),
            h_final=recs[-1].h,
            kappa=recs[-1].kappa,
        )

    def run(self, seed_start: int = 0) -> GRFixedPoint:
        traj_results: List[UmaTrajectoryResult] = []
        for s in range(seed_start, seed_start + self.n_seeds):
            traj_results.append(self._run_seed(s))
        # pick the seed with lowest min residual
        best = min(traj_results, key=lambda r: r.einstein_residual_min)
        # T_star and G_star from best at closure-quality
        # (we don't refine further -- the seed search is itself the refinement)
        # Recompute T,G one more time for that seed:
        traj = self._run_seed(best.seed)
        # build placeholder T_star/G_star from final tensor record kappa relation
        h_star = best.h_final
        T_star = best.kappa * np.array(
            [[1.0, 0.0], [0.0, 1.0]]
        )  # placeholder; refine via NonlinearEinsteinSolver if desired
        G_star = h_star
        return GRFixedPoint(
            z_star=best.z_final,
            h_star=h_star,
            T_star=T_star,
            G_star=G_star,
            residual_star=best.einstein_residual_min,
            seed_star=best.seed,
            trajectories=traj_results,
        )


# ---- uma/msr/nonlinear_gr.py -----------------------------------------
"""
nonlinear_gr.py -- Full nonlinear curvature computation.

Beyond linearized theory. Computes:
    Gamma^k_ij    -- Christoffel symbols from g_ij = eta_ij + h_ij
    R^l_kij       -- Riemann curvature tensor
    R_ij          -- Ricci tensor
    R             -- Ricci scalar
    G_ij          -- Full Einstein tensor G_ij = R_ij - (1/2) g_ij R
    Residual: ||G_ij - 8 pi G T_ij||_F

The metric g_ij at each spatial point (x, y) is derived from the local
field energy density rho(x, y) = |psi(x, y)|^2:

    h_ij(x, y) = Phi(x, y) * delta_ij
    nabla^2 Phi = -4 pi G rho        (Poisson)
    g_ij = (1 + 2 Phi / c^2) delta_ij  (isotropic weak field metric)

Newtonian limit of GR but computed nonlinearly: Phi is solved exactly
for the given rho; Christoffel symbols are computed without assuming
|h| << 1. Strong fields (|Phi| ~ 1) depart from the linearized Einstein
tensor; this is captured by `nonlinearity`.
"""

import math
from dataclasses import dataclass

import numpy as np

pass  # uma import flattened (symbols are top-level)


# ---------------------------------------------------------------------------
# Result
# ---------------------------------------------------------------------------

@dataclass
class CurvatureResult:
    """Full curvature decomposition at one field state."""
    g: np.ndarray              # (2, 2, N, N)
    g_inv: np.ndarray          # (2, 2, N, N)
    Phi: np.ndarray            # (N, N)
    Gamma: np.ndarray          # (2, 2, 2, N, N)
    Ricci: np.ndarray          # (2, 2, N, N)
    Ricci_scalar: np.ndarray   # (N, N)
    G_full: np.ndarray         # (2, 2, N, N) full nonlinear G_ij
    G_linear: np.ndarray       # (2, 2, N, N) linearized for comparison
    T: np.ndarray              # (2, 2, N, N) MSR stress
    nonlinear_residual: float
    linear_residual: float
    nonlinearity: float
    G_mean: np.ndarray
    T_mean: np.ndarray
    kappa: float


# ---------------------------------------------------------------------------
# Solver
# ---------------------------------------------------------------------------

class NonlinearEinsteinSolver:
    """Computes the full nonlinear Einstein tensor from the field psi."""

    def __init__(self, cfg, G_newton: float = 1.0, c: float = 1.0):
        self.N = cfg.grid.N
        self.dx = 1.0 / cfg.grid.N
        self.G = G_newton
        self.c = c
        kx = 2 * math.pi * np.fft.fftfreq(self.N, d=self.dx)
        KX, KY = np.meshgrid(kx, kx)
        self.k2 = KX ** 2 + KY ** 2
        self.k2[0, 0] = 1.0

    def _grad(self, f: np.ndarray, axis: int) -> np.ndarray:
        return np.gradient(f, self.dx, axis=axis)

    def _poisson(self, rho: np.ndarray) -> np.ndarray:
        """nabla^2 Phi = -4 pi G rho via FFT."""
        rho_k = np.fft.fft2(rho)
        Phi_k = 4 * math.pi * self.G * rho_k / self.k2
        Phi_k[0, 0] = 0.0
        return np.fft.ifft2(Phi_k).real

    def _build_metric(self, Phi: np.ndarray) -> tuple[np.ndarray, np.ndarray]:
        """g_ij = (1 + 2 Phi / c^2) delta_ij; g^ij = 1/factor * delta_ij."""
        N = self.N
        factor = 1.0 + 2 * Phi / self.c ** 2
        # avoid division by zero; physically Phi must be > -c^2/2
        factor = np.where(np.abs(factor) < 1e-12, 1e-12, factor)
        g = np.zeros((2, 2, N, N))
        g_inv = np.zeros((2, 2, N, N))
        g[0, 0] = factor; g[1, 1] = factor
        g_inv[0, 0] = 1.0 / factor; g_inv[1, 1] = 1.0 / factor
        return g, g_inv

    def _christoffel(self, g: np.ndarray, g_inv: np.ndarray) -> np.ndarray:
        """Gamma^k_ij = (1/2) g^kl (d_i g_lj + d_j g_li - d_l g_ij)."""
        N = self.N
        Gamma = np.zeros((2, 2, 2, N, N))
        # dg[m, i, j] = d_m g_ij
        dg = np.zeros((2, 2, 2, N, N))
        for mm in range(2):
            for ii in range(2):
                for jj in range(2):
                    dg[mm, ii, jj] = self._grad(g[ii, jj], mm)
        for k in range(2):
            for i in range(2):
                for j in range(2):
                    s = np.zeros((N, N))
                    for l in range(2):
                        s += g_inv[k, l] * (
                            dg[i, l, j] + dg[j, l, i] - dg[l, i, j]
                        )
                    Gamma[k, i, j] = 0.5 * s
        return Gamma

    def _ricci(self, Gamma: np.ndarray) -> np.ndarray:
        """R_ij = d_k G^k_ij - d_j G^k_ik + G^k_kl G^l_ij - G^k_jl G^l_ik."""
        N = self.N
        R = np.zeros((2, 2, N, N))
        for i in range(2):
            for j in range(2):
                for k in range(2):
                    R[i, j] += self._grad(Gamma[k, i, j], k)
                    R[i, j] -= self._grad(Gamma[k, i, k], j)
                    for l in range(2):
                        R[i, j] += Gamma[k, k, l] * Gamma[l, i, j]
                        R[i, j] -= Gamma[k, j, l] * Gamma[l, i, k]
        return R

    def _einstein_full(
        self, Ricci: np.ndarray, R_scalar: np.ndarray, g: np.ndarray
    ) -> np.ndarray:
        """G_ij = R_ij - 1/2 g_ij R."""
        return Ricci - 0.5 * g * R_scalar[None, None, :, :]

    def _linear_einstein(self, h: np.ndarray) -> np.ndarray:
        """Linearized G^(1)[h] for comparison via the bridge primitive."""
        return _einstein_tensor_from_h(h, dx=self.dx)

    def compute(self, psi: np.ndarray, psi_hat: np.ndarray) -> CurvatureResult:
        rho = np.abs(psi) ** 2
        Phi = self._poisson(rho)
        g, g_inv = self._build_metric(Phi)
        Gamma = self._christoffel(g, g_inv)
        Ricci = self._ricci(Gamma)
        # R = g^ij R_ij
        R_scalar = sum(g_inv[i, j] * Ricci[i, j] for i in range(2) for j in range(2))
        G_full = self._einstein_full(Ricci, R_scalar, g)

        # Linearised comparison: h_ij = (g - eta) at this Phi
        eta = np.zeros_like(g); eta[0, 0] = 1.0; eta[1, 1] = 1.0
        h = g - eta
        G_linear = self._linear_einstein(h)

        # Stress tensor
        T = _stress_tensor_spatial(psi, psi_hat, dx=self.dx)
        T_8piG = 8 * math.pi * self.G * T

        nonlinear_residual = float(
            np.linalg.norm(G_full - T_8piG)
            / (np.linalg.norm(G_full) + 1e-15)
        )
        linear_residual = float(
            np.linalg.norm(G_linear - T_8piG)
            / (np.linalg.norm(G_linear) + 1e-15)
        )
        nonlinearity = float(
            np.linalg.norm(G_full - G_linear)
            / (np.linalg.norm(G_full) + 1e-15)
        )

        G_mean = _spatial_mean(G_full)
        T_mean = _spatial_mean(T)
        T_norm = float(np.linalg.norm(T_mean))
        G_norm = float(np.linalg.norm(G_mean))
        kappa = float(np.sum(T_mean * G_mean) / (G_norm ** 2 + 1e-15))

        return CurvatureResult(
            g=g, g_inv=g_inv, Phi=Phi,
            Gamma=Gamma, Ricci=Ricci, Ricci_scalar=R_scalar,
            G_full=G_full, G_linear=G_linear, T=T,
            nonlinear_residual=nonlinear_residual,
            linear_residual=linear_residual,
            nonlinearity=nonlinearity,
            G_mean=G_mean, T_mean=T_mean, kappa=kappa,
        )


# ---- uma/msr/wetterich_flow.py ---------------------------------------
"""
uma.msr.wetterich_flow -- Wetterich-style RG flow with Levy MSR couplings.

Classifies the universality class of the GENERIC field theory by the
ratio of Gaussian (nu_2) to fractional (c_alpha) couplings:

    Levy basin    -> non-local fractional Laplacian dominates,
                     dynamic exponent z = alpha (here alpha = 1.5)
    Gaussian      -> standard local diffusion dominates, z = 2

The cutoff is set heuristically; for a serious flow analysis run
calibrate.py with the relevant trajectory ensemble.
"""

from dataclasses import dataclass


@dataclass
class LevyMSRCouplings:
    """Couplings of a Levy-MSR field theory at the UV cutoff."""
    nu_2: float       # Gaussian (k^2) diffusion coefficient
    nu_alpha: float   # fractional coefficient -- relative scale
    D: float          # noise strength (MSR D coupling)
    c_alpha: float    # fractional MSR coupling
    alpha: float      # fractional exponent (1 < alpha <= 2)
    D_dim: int = 2    # spatial dimension


def classify_basin(c: LevyMSRCouplings, cutoff: float = 0.5) -> str:
    """
    'levy' if c_alpha / (nu_2 + 1e-15) > cutoff (fractional sector wins),
    else 'gaussian'.
    """
    ratio = c.c_alpha / (c.nu_2 + 1e-15)
    return "levy" if ratio > cutoff else "gaussian"


def dynamic_exponent(c: LevyMSRCouplings) -> float:
    """
    z = alpha when Levy basin (fractional exponent), z = 2 in Gaussian.
    """
    if classify_basin(c) == "levy":
        return float(c.alpha)
    return 2.0


# ---- uma/sphere/geometry.py ------------------------------------------
"""
geometry.py -- Acoustic sphere geometry. Everything derived from Bessel zeros.

The sphere is given. Everything else is solved from it outward.
"""

import math
import numpy as np
pass  # spherical_jn / brentq provided by fallback shim above
from dataclasses import dataclass
from typing import List


def bessel_zeros(n: int, n_zeros: int = 5) -> List[float]:
    """
    Find the first n_zeros zeros of spherical Bessel function j_n(x).
    These are exact -- not approximated.
    """
    zeros: List[float] = []
    x_start = max(0.1, (n + 0.5) * math.pi * 0.5)
    x = x_start
    dx = 0.1
    while len(zeros) < n_zeros:
        # Find sign change
        while spherical_jn(n, x) * spherical_jn(n, x + dx) > 0:
            x += dx
            if x > 200.0:  # safety
                raise RuntimeError(f"no Bessel zero found for n={n}")
        zero = brentq(lambda t: spherical_jn(n, t), x, x + dx, xtol=1e-12)
        zeros.append(zero)
        x += dx
    return zeros


def spherical_bessel_zero(n: int, k: int) -> float:
    """The k-th positive zero of j_n (1-indexed)."""
    return bessel_zeros(n, k)[k - 1]


@dataclass
class SphericalMode:
    """A single resonant mode of the acoustic sphere."""
    n: int                # radial order
    l: int                # angular order
    bessel_zero: float    # j_nl zero value
    k: float              # wavenumber = j_nl / R
    f: float              # resonant frequency = c * k / (2*pi)
    wavelength: float     # lambda = c / f


@dataclass
class SystemGeometry:
    """
    Complete system geometry derived from sphere outward.
    Every value is exact -- derived, not chosen.
    """
    # Sphere
    L: float               # box side length (m)
    R: float               # sphere radius = L/2
    mode: SphericalMode    # resonant mode

    # Pendulum
    L_pendulum: float      # pendulum length (m)
    T_pendulum: float      # pendulum period (s)
    f_pendulum: float      # pendulum frequency (Hz)

    # Venturi
    r0: float              # throat radius (m)
    r_in: float            # inner cutoff (m)
    G: float               # Bernoulli gain

    # Blind gate
    d_slit: float                # slit spacing (m)
    theta_diffraction: float     # first-order angle (rad)

    # Lens
    f_lens: float                # focal length (m)

    # Fan / interference
    f_fan: float           # fan frequency (Hz) -- exact
    T_star: float          # stellar temperature this system is resonant with (K)
    nu_star: float         # resonant photon frequency (Hz)

    def summary(self) -> None:
        print("=== ACOUSTIC SPHERE SYSTEM GEOMETRY ===")
        print(f"   Box side L:          {self.L:.4f} m")
        print(f"   Sphere radius R:     {self.R:.4f} m")
        print(f"   Mode (n,l):          ({self.mode.n}, {self.mode.l})")
        print(f"   Bessel zero j_nl:    {self.mode.bessel_zero:.6f}")
        print(f"   Resonant freq:       {self.mode.f:.4f} Hz")
        print()
        print(f"   Pendulum length:     {self.L_pendulum:.6f} m")
        print(f"   Pendulum period:     {self.T_pendulum:.6f} s")
        print()
        print(f"   Venturi r0:          {self.r0:.6f} m")
        print(f"   Venturi r_in:        {self.r_in:.6f} m")
        print(f"   Bernoulli gain G:    {self.G:.6f}")
        print()
        print(f"   Blind slit d:        {self.d_slit:.6e} m")
        print(f"   Diffraction angle:   {math.degrees(self.theta_diffraction):.4f} deg")
        print()
        print(f"   Fan frequency:       {self.f_fan:.6f} Hz")
        print(f"   Stellar T:           {self.T_star:.2f} K")
        print(f"   Resonant nu:         {self.nu_star:.4e} Hz")


class AcousticSphereGeometry:
    """
    Derives complete system geometry from sphere outward.

    Usage::
        geo = AcousticSphereGeometry(L=1.0, n=0, l=0, mode_index=1)
        system = geo.solve()
        system.summary()
    """

    # Physical constants
    C_AIR    = 343.0          # speed of sound (m/s)
    G_GRAV   = 9.81           # gravity (m/s^2)
    H        = 6.626e-34      # Planck constant
    K_B      = 1.381e-23      # Boltzmann constant
    C_LIGHT  = 3e8            # speed of light (m/s)

    def __init__(
        self,
        L: float = 1.0,
        n: int = 0,
        l: int = 0,
        mode_index: int = 1,
        D_blind: float | None = None,
    ):
        """
        L:           box side length (m)
        n, l:        spherical harmonic orders for the resonant mode
        mode_index:  which zero of j_n to use (1 = first zero)
        D_blind:     distance from blind gate to Venturi (default L/4)
        """
        self.L = L
        self.R = L / 2.0
        self.n = n
        self.l = l
        self.mode_index = mode_index
        self.D_blind = D_blind if D_blind else L / 4.0

    def solve(self) -> SystemGeometry:
        """
        Derive everything from the sphere outward.
        Returns complete SystemGeometry.
        """
        # 1. Sphere mode
        zeros = bessel_zeros(self.n, self.mode_index + 1)
        j_nl = zeros[self.mode_index - 1]
        k = j_nl / self.R
        f_mode = self.C_AIR * k / (2 * math.pi)
        lam = self.C_AIR / f_mode

        mode = SphericalMode(
            n=self.n, l=self.l,
            bessel_zero=j_nl, k=k, f=f_mode, wavelength=lam,
        )

        # 2. Pendulum
        # T_pendulum = 1/f_mode  ->  L_pend = g/(4 pi^2 f^2)
        T_pend = 1.0 / f_mode
        L_pend = self.G_GRAV / (4 * math.pi ** 2 * f_mode ** 2)

        # 3. Venturi throat
        # r0 = R * j_nl / pi    (exact from Bessel zero)
        r0 = self.R * j_nl / math.pi

        # r_in from previous Bessel zero (n=0 case: use r0/4)
        if self.mode_index > 1:
            j_prev = zeros[self.mode_index - 2]
            r_in = self.R * j_prev / math.pi
        else:
            r_in = r0 * 0.25  # first mode: inner cutoff = r0/4

        G = max(0.0, 1.0 - (r_in / r0) ** 2)

        # 4. Blind gate slit spacing
        # d = lam * sqrt(r0^2 + D^2) / r0  (first-order diffraction at r0)
        theta = math.atan2(r0, self.D_blind)
        d_slit = lam / math.sin(theta)

        # 5. Lens focal length
        # f1 = r0^2 / lam  (Rayleigh range)
        f_lens = r0 ** 2 / lam

        # 6. Fan frequency and stellar resonance
        # From sphere: f_fan = c_air * j_nl / (2 pi R) = f_mode
        f_fan = f_mode

        # From starlight + fan: omega_fan = h nu / kT
        # -> nu = kT * 2 pi f_fan / h
        nu_star = self.K_B * 2 * math.pi * f_fan / self.H
        # T from Wien's law: T = h nu / (k * x) where x ~ 2.821
        WIEN_X = 2.821
        T_star = self.H * nu_star / (self.K_B * WIEN_X)

        return SystemGeometry(
            L=self.L, R=self.R, mode=mode,
            L_pendulum=L_pend, T_pendulum=T_pend, f_pendulum=f_mode,
            r0=r0, r_in=r_in, G=G,
            d_slit=d_slit, theta_diffraction=theta,
            f_lens=f_lens,
            f_fan=f_fan, T_star=T_star, nu_star=nu_star,
        )


if False:  # flattened module demo (disabled in the monolith)
    geo = AcousticSphereGeometry(L=1.0, n=0, l=0, mode_index=1)
    sys_ = geo.solve()
    sys_.summary()
    # sanity: j_{0,1} = pi exactly
    j01 = spherical_bessel_zero(0, 1)
    print(f"\n   j_{{0,1}} = {j01:.10f}    pi = {math.pi:.10f}    "
          f"|delta| = {abs(j01 - math.pi):.2e}")


# ---- uma/sphere/field.py ---------------------------------------------
"""
field.py -- The sphere projection field as a UMA observation operator.

The standing wave pressure field P_nlm(r, theta, phi) IS the projection medium.
Each point in the field maps to a spherical harmonic amplitude.
The pendulum sweeping through it samples these amplitudes sequentially.

In UMA terms:
    The sphere field IS the observation operator H.
    H(z) = sum_lm [ <Y_lm | z> * P_nlm(r_pend(t)) ]

    The pendulum position r_pend(t) = R * (sin(omega t), 0, cos(omega t))
    sweeps a great circle through the standing wave.

    Each sample is an exact measurement of a spherical harmonic component.
"""

import math
import numpy as np
from typing import Tuple
pass  # spherical_jn provided by fallback shim above

pass  # uma import flattened (symbols are top-level)


# scipy renamed `sph_harm` -> `sph_harm_y` after 1.13. Cope with both — and with
# scipy being absent entirely (graceful degradation: exact pure-Python fallback,
# so Chiron runs on bare Python with no installs).
try:
    from scipy.special import sph_harm_y as _sph_harm_y  # type: ignore
    def sph_harm(m, l, phi, theta):  # noqa: D401
        return _sph_harm_y(l, m, theta, phi)            # sph_harm_y(n, m, theta, phi)
except Exception:  # pragma: no cover
    try:
        from scipy.special import sph_harm as _sph_harm  # type: ignore
        def sph_harm(m, l, phi, theta):  # noqa: D401
            return _sph_harm(m, l, phi, theta)
    except Exception:
        import math as _mh, cmath as _ch
        def _sph_harm_scalar(m, l, phi, theta):
            ma = abs(int(m)); l = int(l); x = _mh.cos(theta); pmm = 1.0
            if ma > 0:
                s = _mh.sqrt(max(0.0, (1.0 - x) * (1.0 + x))); f = 1.0
                for _i in range(1, ma + 1):
                    pmm *= -f * s; f += 2.0
            if l == ma:
                plm = pmm
            else:
                pmmp1 = x * (2 * ma + 1) * pmm
                if l == ma + 1:
                    plm = pmmp1
                else:
                    plm = 0.0
                    for ll in range(ma + 2, l + 1):
                        plm = ((2 * ll - 1) * x * pmmp1 - (ll + ma - 1) * pmm) / (ll - ma)
                        pmm = pmmp1; pmmp1 = plm
            norm = _mh.sqrt((2 * l + 1) / (4 * _mh.pi)
                            * _mh.factorial(l - ma) / _mh.factorial(l + ma))
            y = norm * plm * _ch.exp(1j * ma * phi)
            return ((-1) ** ma) * y.conjugate() if m < 0 else y
        try:
            import numpy as _npsh
            _vsh = _npsh.vectorize(_sph_harm_scalar)
            def sph_harm(m, l, phi, theta):  # noqa: D401
                return _vsh(m, l, phi, theta)
        except Exception:
            sph_harm = _sph_harm_scalar


class SphereProjectionField:
    """
    The acoustic sphere as a UMA observation/projection operator.

    Maps the UMA field state z to a spherical harmonic decomposition,
    sampled by the pendulum as it sweeps through the standing wave.
    """

    def __init__(self, geometry: SystemGeometry, n_harmonics: int = 4):
        self.geo = geometry
        self.n_harmonics = n_harmonics
        self._build_mode_table()

    def _build_mode_table(self) -> None:
        """Build table of (n, l, m) modes up to n_harmonics."""
        self.modes: list[tuple[int, int, int]] = []
        for n in range(self.n_harmonics):
            for l in range(n + 1):
                for m in range(-l, l + 1):
                    self.modes.append((n, l, m))

    def pressure(self, r: float, theta: float, phi: float, t: float) -> complex:
        """
        P(r, theta, phi, t) = sum_nlm [ j_n(k_nl r) * Y_lm(theta, phi) * e^(i omega t) ]

        The exact standing wave pressure at point (r, theta, phi) at time t.
        """
        P = 0.0 + 0j
        omega = 2 * math.pi * self.geo.mode.f
        k = self.geo.mode.k
        phase = np.exp(1j * omega * t)
        for n, l, m in self.modes:
            jn = spherical_jn(n, k * r)
            Ylm = sph_harm(m, l, phi, theta)
            P += jn * Ylm * phase
        return complex(P)

    def pendulum_sample(self, t: float) -> Tuple[float, complex]:
        """
        Sample the pressure field at the pendulum position at time t.

        Pendulum sweeps a great circle:
            r     = pendulum length (constant)
            theta = pi/2 (equatorial plane)
            phi   = omega_pend * t
        """
        omega_pend = 2 * math.pi * self.geo.f_pendulum
        phi = (omega_pend * t) % (2 * math.pi)
        theta = math.pi / 2
        r = self.geo.L_pendulum
        P = self.pressure(r, theta, phi, t)
        return phi, P

    def observation_vector(self, t: float, n_samples: int = 64) -> np.ndarray:
        """
        Build observation vector by sampling pendulum arc over one period.

        This is the H operator that maps field state to measurements.
        Returns real pressure amplitudes at each pendulum position.
        """
        T = self.geo.T_pendulum
        times = np.linspace(t, t + T, n_samples, endpoint=False)
        samples = []
        for ti in times:
            _phi, P = self.pendulum_sample(ti)
            samples.append(P.real)
        return np.array(samples)

    # --- input physics --------------------------------------------------

    def planck_input(self, nu: float, T_star: float) -> float:
        """
        B(nu, T) = 2 h nu^3 / c^2 / (exp(h nu / kT) - 1)

        Spectral radiance of input starlight.
        """
        H = 6.626e-34
        C = 3e8
        KB = 1.381e-23
        x = H * nu / (KB * T_star)
        return 2 * H * nu ** 3 / C ** 2 / (math.exp(x) - 1)

    def interference_amplitude(self, t: float, nu: float) -> float:
        """
        Amplitude of starlight + fan-synthetic interference at time t.

            phi_star      = h nu / kT   (Planck phase)
            phi_synthetic = omega_fan * t

            A = B(nu, T) * cos(phi_star - phi_synthetic)
        """
        H = 6.626e-34
        KB = 1.381e-23
        phi_star = H * nu / (KB * self.geo.T_star)
        phi_synthetic = 2 * math.pi * self.geo.f_fan * t
        B = self.planck_input(nu, self.geo.T_star)
        return B * math.cos(phi_star - phi_synthetic)


class SpherePendulum:
    """
    The pendulum as a geometric sampler of the sphere field.
    Period and length are exact -- derived from Bessel zeros.
    """

    def __init__(self, geometry: SystemGeometry):
        self.geo = geometry
        self.t = 0.0
        self.history: list[dict] = []

    def position(self, t: float) -> Tuple[float, float, float]:
        """
        (x, y, z) position of pendulum bob at time t.
        Sweeps a great circle in the equatorial plane.
        """
        omega = 2 * math.pi * self.geo.f_pendulum
        L = self.geo.L_pendulum
        x = L * math.cos(omega * t)
        y = L * math.sin(omega * t)
        z = 0.0
        return x, y, z

    def sample_field(self, field: SphereProjectionField, t: float) -> dict:
        """Sample the sphere field at current pendulum position."""
        x, y, z = self.position(t)
        r = math.sqrt(x * x + y * y + z * z)
        theta = math.acos(z / (r + 1e-15))
        phi = math.atan2(y, x)
        P = field.pressure(r, theta, phi, t)
        return {
            "t": t, "x": x, "y": y, "z": z,
            "r": r, "theta": theta, "phi": phi,
            "P_real": float(P.real), "P_imag": float(P.imag), "P_abs": abs(P),
        }


class SphereVenturi:
    """
    The Venturi with throat derived from Bessel zeros.
    r0 = R * j_nl / pi  -- exact resonance with sphere modes.
    """

    def __init__(self, geometry: SystemGeometry, N: int = 32):
        self.geo = geometry
        self.r0 = geometry.r0
        self.r_in = geometry.r_in
        self.G = geometry.G
        self._R = self._build_radial(N)

    def _build_radial(self, N: int) -> np.ndarray:
        x = np.linspace(0, 1, N, endpoint=False)
        X, Y = np.meshgrid(x, x)
        dx = np.abs(X - 0.5); dx = np.minimum(dx, 1 - dx)
        dy = np.abs(Y - 0.5); dy = np.minimum(dy, 1 - dy)
        return np.sqrt(dx ** 2 + dy ** 2)

    def coupling_field(self) -> np.ndarray:
        """V(r, r0) -- exact, derived from sphere geometry."""
        r0 = self.r0 / self.geo.R     # normalize to roughly [0, 0.5]
        r_in = self.r_in / self.geo.R
        r_out = 0.42
        r_eff = np.maximum(self._R, r_in)
        throat = r0 / r_eff
        envelope = np.clip((r_out - self._R) / (r_out - r0 + 1e-8), 0, 1)
        return throat * envelope

    def apply(self, psi: np.ndarray, psi_inject: np.ndarray, dt: float) -> np.ndarray:
        """Apply sphere-derived Venturi to field."""
        V = self.coupling_field()
        # broadcast V to psi grid
        if V.shape != psi.shape:
            from scipy.ndimage import zoom
            V = zoom(V, (psi.shape[0] / V.shape[0], psi.shape[1] / V.shape[1]), order=1)
        return psi + dt * self.G * V * psi_inject


# ---- uma/venturi/operator.py -----------------------------------------
"""
venturi.py -- 360-degree evolving Venturi for cross-domain injection.

Standalone. No dependencies except numpy and math.

The Venturi auto-regulates the throat radius r0 by the projected DC
energy E. When E < E* the throat expands (release more injected
amplitude); when E > E* the throat contracts (more suction). The Silver
Ratio constants are preserved as a deliberate text-encoding design
choice (see semantic/constants.py for the calibration retraction note).

Run:  python3 -m uma.venturi.operator
"""

import math
import numpy as np


# ---------------------------------------------------------------------
# Silver Ratio constants
# ---------------------------------------------------------------------

SQRT2          = math.sqrt(2)
SQRT_E         = math.sqrt(math.e)
DELTA_S        = 1.0 + SQRT2          # Silver Ratio
INV_DELTA_S_SQ = 1.0 / DELTA_S ** 2   # 3 - 2*sqrt(2) ~ 0.17157
C1_SILVER      = 1.0 - SQRT2          # ~ -0.41421


def silver_E_target(kT: float) -> float:
    return kT * INV_DELTA_S_SQ


def silver_dz_dt_floor(kT: float, lam: float, N: int, dt: float) -> float:
    return math.sqrt(2.0 * kT * INV_DELTA_S_SQ * lam * dt) / N


def silver_field_scale(kT: float) -> float:
    return math.sqrt(2.0 * silver_E_target(kT))


def engine3_complex_state(x: float) -> complex:
    """Engine3 seed: z_c = x * ((1 - sqrt 2) + i sqrt e). Encoding choice."""
    return complex(x * C1_SILVER, x * SQRT_E)


# ---------------------------------------------------------------------
# Venturi
# ---------------------------------------------------------------------

class Venturi:
    """
    360-degree evolving Venturi for cross-domain injection.

        V(r, r0) = (r0 / max(r, r_in))^beta * envelope(r)
        dr0/dt   = -lam_v * (E - E*)/E* * r0
        G        = 1 - (r_in/r0)^2

        d psi/dt|venturi = G * V(r, r0(t)) * phi_inject
    """

    def __init__(
        self,
        N: int = 32, kT: float = 0.005, lam: float = 0.4,
        r0: float = 0.15, r_in: float = 0.04, r_out: float = 0.42,
        beta: float = 1.0, lam_v: float = 0.1, coupling: float = 1.0, dt: float = 0.04,
    ):
        self.N = N
        self.kT = kT
        self.lam = lam
        self.r0 = r0
        self.r0_init = r0
        self.r_in = r_in
        self.r_out = r_out
        self.beta = beta
        self.lam_v = lam_v
        self.coupling = coupling
        self.dt = dt
        self.t = 0.0

        self.E_star      = silver_E_target(kT)
        self.dz_dt_floor = silver_dz_dt_floor(kT, lam, N, dt)
        self.field_scale = silver_field_scale(kT)

        self.history: list[dict] = []
        self._R = self._radial_grid(N)

    # -----------------------------------------------------------------

    def _radial_grid(self, N: int) -> np.ndarray:
        x = np.linspace(0, 1, N, endpoint=False)
        X, Y = np.meshgrid(x, x)
        dx = np.abs(X - 0.5); dx = np.minimum(dx, 1 - dx)
        dy = np.abs(Y - 0.5); dy = np.minimum(dy, 1 - dy)
        return np.sqrt(dx ** 2 + dy ** 2)

    def _V(self, r0: float) -> np.ndarray:
        r_eff = np.maximum(self._R, self.r_in)
        throat = (r0 / r_eff) ** self.beta
        envelope = np.clip((self.r_out - self._R) / (self.r_out - r0 + 1e-8), 0, 1)
        return throat * envelope

    def _G(self, r0: float) -> float:
        return max(0.0, 1.0 - (self.r_in / max(r0, self.r_in + 1e-8)) ** 2)

    def _evolve_r0(self, E: float) -> float:
        dr0 = -self.lam_v * (E - self.E_star) / (self.E_star + 1e-15) * self.r0
        self.r0 = float(np.clip(self.r0 + dr0 * self.dt, 0.03, 0.45))
        return float(dr0)

    # -----------------------------------------------------------------

    def step(self, psi: np.ndarray, phi_inject: np.ndarray, z_dc: np.ndarray) -> np.ndarray:
        """
        One Venturi step.

        psi        : current field (N x N complex)
        phi_inject : injection field (N x N complex)
        z_dc       : DC projected state (drives throat evolution)

        Returns psi_out (N x N complex)
        """
        z_dc = np.asarray(z_dc).ravel()
        E = float(np.real(z_dc @ z_dc) / 2.0)
        dr0 = self._evolve_r0(E)
        G = self._G(self.r0)
        V = self._V(self.r0)
        # broadcast V to psi grid if needed
        if V.shape != psi.shape:
            from scipy.ndimage import zoom
            V = zoom(V, (psi.shape[0] / V.shape[0], psi.shape[1] / V.shape[1]), order=1)
        self.t += self.dt
        psi_out = psi + self.dt * G * self.coupling * V * phi_inject
        self.history.append({
            "t": self.t, "r0": self.r0, "G": G,
            "E": E, "dr0_dt": dr0,
        })
        return psi_out

    def inject_text(
        self, text: str, psi: np.ndarray, z_dc: np.ndarray, anchor: str = "dIse",
    ) -> np.ndarray:
        """
        Inject a text string into the field via Venturi.

        text -> binary weight -> Engine3 complex state -> 360-degree field -> step.
        """
        binary = ''.join(format(ord(c), '08b') for c in text)
        anc_binary = ''.join(format(ord(c), '08b') for c in anchor)
        x = len(binary) / max(len(anc_binary), 1)
        z_c = engine3_complex_state(x)
        phi_s = self._azimuthal_field(z_c, psi)
        return self.step(psi, phi_s, z_dc)

    def _azimuthal_field(self, z_c: complex, psi: np.ndarray) -> np.ndarray:
        """360-degree injection: amplitude |z_c|, phase rotates around field center."""
        intensity = np.abs(psi) ** 2
        total = intensity.sum() + 1e-15
        coords = np.linspace(0, 1, psi.shape[0], endpoint=False)
        X, Y = np.meshgrid(coords, coords)
        cx = float((intensity * X).sum() / total)
        cy = float((intensity * Y).sum() / total)
        dx = X - cx; dx -= np.round(dx)
        dy = Y - cy; dy -= np.round(dy)
        theta = np.arctan2(dy, dx)
        return abs(z_c) * np.exp(1j * (np.angle(z_c) + theta))

    def reset(self) -> None:
        self.r0 = self.r0_init
        self.t = 0.0
        self.history.clear()

    def summary(self) -> str:
        if not self.history:
            return "No steps yet."
        h = self.history[-1]
        return (
            f"t={h['t']:.3f}  r0={h['r0']:.4f}  G={h['G']:.4f}  "
            f"E={h['E']:.4e}  E*={self.E_star:.4e}  dr0/dt={h['dr0_dt']:.4e}"
        )


# Alias the user uses interchangeably across the corpus
VenturiOperator = Venturi


# ---------------------------------------------------------------------
# Demo
# ---------------------------------------------------------------------

if False:  # flattened module demo (disabled in the monolith)
    print("=== 360-degree Venturi -- standalone demo ===\n")

    N, kT, lam, dt = 32, 0.005, 0.4, 0.04
