# ---- uma/venturi/injector.py -----------------------------------------
"""
uma.venturi.injector -- CrossDomainInjector.

Applies 360-degree azimuthal injection of synthetic amplitudes across
both the MSR (response) and semantic (field) domains. Sits on top of the
Venturi operator and routes injection through it for each domain.
"""

import numpy as np

pass  # uma import flattened (symbols are top-level)


class CrossDomainInjector:
    """
    Couples Venturi injection into two channels simultaneously:

      psi       <- venturi.step(psi, phi_inject, z_dc)
      psi_hat   <- venturi.step(psi_hat, phi_inject, z_dc)   (MSR response)

    Both domains see the same 360-degree azimuthal phi_inject derived
    from the Engine3 complex state seed for the given text.
    """

    def __init__(self, venturi: Venturi):
        self.venturi = venturi

    def inject(
        self,
        text: str,
        psi: np.ndarray,
        psi_hat: np.ndarray,
        z_dc: np.ndarray,
        anchor: str = "dIse",
    ) -> tuple[np.ndarray, np.ndarray]:
        binary = ''.join(format(ord(c), '08b') for c in text)
        anc_binary = ''.join(format(ord(c), '08b') for c in anchor)
        x = len(binary) / max(len(anc_binary), 1)
        z_c = engine3_complex_state(x)
        phi_s = self.venturi._azimuthal_field(z_c, psi)
        psi_out = self.venturi.step(psi, phi_s, z_dc)
        psi_hat_out = self.venturi.step(psi_hat, phi_s, z_dc)
        return psi_out, psi_hat_out


# ---- uma/semantic/constants.py ---------------------------------------
"""
UMA Semantic Constants.

NOTE ON THE SILVER RATIO:
    Earlier versions claimed E_DC/kT = 3 - 2 sqrt(2) = 1/delta_S^2 as a
    fundamental constant of the GENERIC Lagrangian. This was wrong.

    Across 50 independent trajectories, E_DC/kT ranges from 0.08 to 1.93
    with mean 0.77 and std 0.65. The value 0.1713 matched Silver to 0.16%
    only for seed=42. It was a coincidence, not a derived constant.

    The correct closure thresholds are in calibrate.py and friction.py.

WHAT REMAINS VALID:
    - The Engine3 complex state z = x * ((1 - sqrt 2) + i sqrt e) is a
      well-defined encoding. It maps text to a complex number via a
      specific algebraic structure.
    - The Silver angle arctan(sqrt(e) / (1 - sqrt 2)) ~= 104.1 degrees is
      arg(z_seed) -- a real property of the encoding.
    - These are useful as a DESIGN CHOICE for the encoding, not physics.
"""

import math


SQRT2  = math.sqrt(2)
SQRT_E = math.sqrt(math.e)

# Silver Ratio -- valid as a mathematical object, NOT as a physics constant
DELTA_S         = 1.0 + SQRT2
DELTA_S_SQ      = DELTA_S ** 2
INV_DELTA_S_SQ  = 1.0 / DELTA_S_SQ                # 3 - 2*sqrt(2) ~ 0.17157

C1_SILVER       = 1.0 - SQRT2                     # ~ -0.41421
C2_SILVER       = 2.0 - SQRT2                     # ~  0.58579
SILVER_ANGLE    = math.degrees(math.atan2(SQRT_E, C1_SILVER))  # ~ 104.1 deg

# Engine3 complex state seed
Z_SEED_REAL = C1_SILVER
Z_SEED_IMAG = SQRT_E


def engine3_complex_state(x: float) -> complex:
    """Map binary weight x to Engine3 complex state."""
    return complex(x * Z_SEED_REAL, x * Z_SEED_IMAG)


def engine3_E(x: float) -> float:
    """E = |z_c|^2 / 2 for the Engine3 complex state."""
    z = engine3_complex_state(x)
    return (z.real ** 2 + z.imag ** 2) / 2.0


# ---------------------------------------------------------------------------
# Calibrated values (50-trajectory baseline)
# These are physics-grounded; they replace Silver-Ratio derivations.
# ---------------------------------------------------------------------------

CALIBRATED_E_TARGET    = 3.837e-3
CALIBRATED_DZ_DT_FLOOR = 2.253e-3
CALIBRATED_FIELD_SCALE = 1.752e-1


def silver_E_target(kT: float) -> float:
    """Returns calibrated E_target. Name kept for backward compat."""
    return CALIBRATED_E_TARGET


def silver_dz_dt_floor(kT: float, lam: float, N: int, dt: float) -> float:
    """Returns calibrated dz_dt floor. Name kept for backward compat."""
    return CALIBRATED_DZ_DT_FLOOR


def silver_field_scale(kT: float, N: int = 32, rho_star: float = 1.0) -> float:
    """Returns calibrated field scale. Name kept for backward compat."""
    return CALIBRATED_FIELD_SCALE


# ---------------------------------------------------------------------------
# H[psi]-based calibrated thresholds (50 GENERIC trajectories)
# These track the actual Hamiltonian, not |z|^2/2 proxy.
# ---------------------------------------------------------------------------

CALIBRATED_H_TARGET    = 1.092794e+00   # mean(H[psi])
CALIBRATED_H_STD       = 2.550512e-01   # std(H[psi])
CALIBRATED_DH_DT_FLOOR = 1.292312e+00   # mean(|dH/dt|) -- thermal noise rate
CALIBRATED_DH_DT_P25   = 5.191530e-01   # lower quartile (tighter threshold)


if False:  # flattened module demo (disabled in the monolith)
    print("UMA Semantic Constants")
    print(f"   Silver Ratio delta_S  = {DELTA_S:.6f}      (mathematical, not physics)")
    print(f"   1/delta_S^2           = {INV_DELTA_S_SQ:.6f}")
    print(f"   Silver angle          = {SILVER_ANGLE:.2f} degrees")
    print(f"   sqrt(e)               = {SQRT_E:.6f}")
    print()
    print("   NOTE: These are encoding design constants, not GENERIC equilibrium values.")
    print(f"   CALIBRATED_H_TARGET    = {CALIBRATED_H_TARGET:.6e}")
    print(f"   CALIBRATED_DH_DT_FLOOR = {CALIBRATED_DH_DT_FLOOR:.6e}")
    print(f"   CALIBRATED_FIELD_SCALE = {CALIBRATED_FIELD_SCALE:.6e}")


# ---- uma/semantic/ir.py ----------------------------------------------
"""
UMA_IR -- Intermediate Representation.

Sits between SemanticEngine (compiler/planner) and UMA kernel (physics).
SemanticEngine emits a UMA_IR graph. UMAExecutor consumes it.

Node types:
    'evolve'      -- run dynamics forward by dt
    'observe'     -- apply (Observation, y) to the filter
    'constrain'   -- project state onto constraint set
    'checkpoint'  -- record friction, check closure
"""


from dataclasses import dataclass, field
from typing import Any, Callable, Dict, List, Optional

import numpy as np


@dataclass
class IRNode:
    node_id: str
    kind: str    # 'evolve' | 'observe' | 'constrain' | 'checkpoint'
    payload: Dict[str, Any] = field(default_factory=dict)


@dataclass
class UMA_IR:
    """Compiled execution graph. Compiler emits this; Executor consumes it."""
    nodes: List[IRNode] = field(default_factory=list)
    schedule: List[str] = field(default_factory=list)
    objective: Optional[Callable[[np.ndarray], float]] = None
    metadata: Dict[str, Any] = field(default_factory=dict)

    def append(self, node: IRNode) -> None:
        self.nodes.append(node)
        self.schedule.append(node.node_id)

    def __len__(self) -> int:
        return len(self.schedule)

    def summary(self) -> str:
        counts: Dict[str, int] = {}
        for n in self.nodes:
            counts[n.kind] = counts.get(n.kind, 0) + 1
        parts = [f"{k}*{v}" for k, v in counts.items()]
        return f"UMA_IR({', '.join(parts)}, total={len(self)} nodes)"


# ---- uma/semantic/constraints.py -------------------------------------
"""
UMA Equalities -- static fixed-point constraints on the projected field state.

These are the Constraint Alpha / Beta / Gamma operators from the
Semantic Engine formulation: equality markers that keep the system
anchored to its core architecture regardless of differential noise.

A constraint c(z) = 0 is enforced by a projection step after each
filter update. Three types are supported:

    LinearConstraint:    a^T z = b      (hyperplane anchor)
    BallConstraint:      ||P z|| <= r   (norm boundary)
    QuadraticConstraint: z^T Q z <= kappa  (ellipsoidal density anchor)

Each implements:
    .check(z) -> float       residual |c(z)|; 0 = fully satisfied
    .project(z) -> z_proj    nearest z satisfying the constraint
    .as_dict() -> metadata for logging

The ConstraintSet bundles multiple equalities and applies them in
sequence (alternating projection / Dykstra-style cascade).

Constraint semantics in the Semantic Engine:
    Alpha -- dIse:    Defines the static boundary of the product's semantic
                      space. -> LinearConstraint on a chosen projection of z.
    Beta  -- V:[H:    Establishes structural compilation boundary.
                      -> BallConstraint on ||z||: keeps state inside the
                      "compiled" region of the Fourier manifold.
    Gamma -- Jd$m4:   Fixes data density for metric re-articulation.
                      -> QuadraticConstraint: ellipsoidal metric anchor
                      derived from empirical Fisher information.
"""

from abc import ABC, abstractmethod
from dataclasses import dataclass
from typing import Any, Dict, List, Optional, Tuple

import numpy as np


# ---------------------------------------------------------------------------
# Abstract base
# ---------------------------------------------------------------------------

class EqualityConstraint(ABC):
    """Abstract fixed-point constraint on z in R^d."""

    def __init__(self, name: str):
        self.name = name
        self._violation_history: List[float] = []

    @abstractmethod
    def check(self, z: np.ndarray) -> float:
        """Return residual >= 0; 0 means z exactly satisfies the constraint."""

    @abstractmethod
    def project(self, z: np.ndarray) -> np.ndarray:
        """Nearest z' satisfying the constraint."""

    def apply(self, z: np.ndarray) -> Tuple[np.ndarray, float]:
        """Project and record violation before projection."""
        viol = self.check(z)
        self._violation_history.append(viol)
        z_proj = self.project(z)
        return z_proj, viol

    @property
    def violation_history(self) -> np.ndarray:
        return np.array(self._violation_history)

    @property
    def is_satisfied(self) -> bool:
        if not self._violation_history:
            return False
        return self._violation_history[-1] < 1e-6

    def as_dict(self) -> Dict[str, Any]:
        return {
            "name": self.name,
            "type": type(self).__name__,
            "n_applications": len(self._violation_history),
            "last_violation": (
                self._violation_history[-1] if self._violation_history else None
            ),
            "satisfied": self.is_satisfied,
        }

    def reset(self) -> None:
        self._violation_history.clear()


# ---------------------------------------------------------------------------
# Constraint Alpha -- LinearConstraint  (Constraint dIse)
# ---------------------------------------------------------------------------

class LinearConstraint(EqualityConstraint):
    """
    Hyperplane equality: a^T z = b.

    Semantic role (Constraint Alpha / dIse):
        Defines the static boundary of the product's semantic space.

    Projection:
        z_proj = z - ((a^T z - b) / ||a||^2) a   (orthogonal projection)
    """

    def __init__(self, a: np.ndarray, b: float, name: str = "alpha_dIse"):
        super().__init__(name)
        a = np.asarray(a, dtype=float)
        norm_sq = float(a @ a)
        if norm_sq < 1e-12:
            raise ValueError("Constraint normal vector `a` must be nonzero.")
        self._a = a
        self._b = b
        self._norm_sq = norm_sq

    @classmethod
    def from_direction(
        cls, d: int, direction: int = 0, b: float = 0.0,
        name: str = "alpha_dIse",
    ) -> "LinearConstraint":
        """Convenience: constrain z[direction] = b."""
        a = np.zeros(d)
        a[direction] = 1.0
        return cls(a, b, name)

    def check(self, z: np.ndarray) -> float:
        return abs(float(self._a @ z) - self._b)

    def project(self, z: np.ndarray) -> np.ndarray:
        residual = float(self._a @ z) - self._b
        return z - (residual / self._norm_sq) * self._a


# ---------------------------------------------------------------------------
# Constraint Beta -- BallConstraint  (Constraint V:[H)
# ---------------------------------------------------------------------------

class BallConstraint(EqualityConstraint):
    """
    L2-ball inequality (saturated at the boundary): ||P z|| <= r.

    Projection:
        If ||P z|| <= r: z unchanged.
        If ||P z|| > r: z_proj = z_fixed + r * (P z) / ||P z||
            where z_fixed is the (I - P) z component.
    """

    def __init__(
        self,
        r: float,
        P: Optional[np.ndarray] = None,
        center: Optional[np.ndarray] = None,
        name: str = "beta_VH",
    ):
        super().__init__(name)
        if r <= 0:
            raise ValueError("Ball radius r must be positive.")
        self._r = r
        self._P = P
        self._center = center

    def _pz(self, z: np.ndarray) -> np.ndarray:
        v = z if self._center is None else z - self._center
        return v if self._P is None else self._P @ v

    def check(self, z: np.ndarray) -> float:
        norm = float(np.linalg.norm(self._pz(z)))
        return max(0.0, norm - self._r)

    def project(self, z: np.ndarray) -> np.ndarray:
        center = np.zeros_like(z) if self._center is None else self._center
        v = z - center
        if self._P is None:
            norm = float(np.linalg.norm(v))
            if norm <= self._r:
                return z
            return center + self._r * v / norm
        Pv = self._P @ v
        norm_Pv = float(np.linalg.norm(Pv))
        if norm_Pv <= self._r:
            return z
        Pv_proj = self._r * Pv / norm_Pv
        complement = v - Pv
        return center + Pv_proj + complement


# ---------------------------------------------------------------------------
# Constraint Gamma -- QuadraticConstraint  (Constraint Jd$m4)
# ---------------------------------------------------------------------------

class QuadraticConstraint(EqualityConstraint):
    """
    Ellipsoidal constraint: z^T Q z <= kappa.

    Q encodes the Fisher information geometry. The ellipsoid
    {z : z^T Q z <= kappa} is the admissible region at confidence level
    kappa. Q must be SPD or PSD; if None, defaults to identity (ball).

    Projection via eigendecomposition of Q = V Lambda V^T.
    """

    def __init__(
        self,
        kappa: float,
        Q: Optional[np.ndarray] = None,
        center: Optional[np.ndarray] = None,
        name: str = "gamma_Jd4m",
    ):
        super().__init__(name)
        if kappa <= 0:
            raise ValueError("kappa must be positive.")
        self._kappa = kappa
        self._center = center
        self._Q = Q
        if Q is not None:
            eigs, vecs = np.linalg.eigh(0.5 * (Q + Q.T))
            self._eigs = np.clip(eigs, 1e-12, None)
            self._vecs = vecs
        else:
            self._eigs = None
            self._vecs = None

    def _mahal(self, z: np.ndarray) -> float:
        v = z if self._center is None else z - self._center
        if self._Q is None:
            return float(v @ v)
        return float(v @ self._Q @ v)

    def check(self, z: np.ndarray) -> float:
        return max(0.0, self._mahal(z) - self._kappa)

    def project(self, z: np.ndarray) -> np.ndarray:
        center = np.zeros_like(z) if self._center is None else self._center
        v = z - center
        if self._mahal(z) <= self._kappa:
            return z

        if self._Q is None:
            norm = float(np.linalg.norm(v))
            return center + np.sqrt(self._kappa) * v / (norm + 1e-15)

        # Ellipsoidal projection via KKT, eigenbasis Lagrange-multiplier search.
        w = self._vecs.T @ v
        lam_vals = self._eigs
        kappa = self._kappa

        def constraint_val(mu):
            w_proj = w / (1 + mu * lam_vals)
            return float(np.sum(lam_vals * w_proj ** 2)) - kappa

        mu_lo, mu_hi = 0.0, 1e8
        for _ in range(60):
            mu_mid = 0.5 * (mu_lo + mu_hi)
            val = constraint_val(mu_mid)
            if val > 0:
                mu_lo = mu_mid
            else:
                mu_hi = mu_mid
            if mu_hi - mu_lo < 1e-12:
                break
        mu_opt = 0.5 * (mu_lo + mu_hi)
        w_proj = w / (1 + mu_opt * lam_vals)
        v_proj = self._vecs @ w_proj
        return center + v_proj


# ---------------------------------------------------------------------------
# ConstraintSet -- bundles Alpha, Beta, Gamma; applies them in cascade
# ---------------------------------------------------------------------------

class ConstraintSet:
    """
    Bundle of UMA Equalities applied in cascade (alternating projection).

    For k constraints C_1, ..., C_k, applies them in round-robin until
    the total violation drops below `tol` or `max_iters` is reached.

    Usage:
        cs = ConstraintSet([alpha, beta, gamma], max_iters=20, tol=1e-6)
        z_anchored, report = cs.apply(z_raw)
    """

    def __init__(
        self,
        constraints: List[EqualityConstraint],
        max_iters: int = 20,
        tol: float = 1e-6,
    ):
        self.constraints = constraints
        self.max_iters = max_iters
        self.tol = tol

    def apply(self, z: np.ndarray) -> Tuple[np.ndarray, Dict[str, Any]]:
        z_curr = z.copy()
        violations_per_iter: List[float] = []
        for _it in range(self.max_iters):
            total_viol = 0.0
            for c in self.constraints:
                z_curr, viol = c.apply(z_curr)
                total_viol += viol
            violations_per_iter.append(total_viol)
            if total_viol < self.tol:
                break

        report = {
            "n_iters": len(violations_per_iter),
            "final_total_violation": (
                violations_per_iter[-1] if violations_per_iter else 0.0
            ),
            "converged": (
                violations_per_iter[-1] < self.tol if violations_per_iter else True
            ),
            "constraint_reports": [c.as_dict() for c in self.constraints],
        }
        return z_curr, report

    def reset(self) -> None:
        for c in self.constraints:
            c.reset()

    @classmethod
    def default_semantic_constraints(
        cls,
        dim: int,
        z_target: np.ndarray,
        ball_radius_factor: float = 3.0,
        kappa_factor: float = 9.0,
        alpha_direction: int = 0,
    ) -> "ConstraintSet":
        """
        Build the canonical three-constraint set (Alpha, Beta, Gamma)
        anchored to a given z_target.

        Alpha (dIse):  z[alpha_direction] = z_target[alpha_direction]
        Beta  (V:[H):  ||z - z_target|| <= r,
                       r = ball_radius_factor * ||z_target|| + 1
        Gamma (Jd$m4): (z - z_target)^T I (z - z_target) <= kappa,
                       kappa = kappa_factor * dim
        """
        a = np.zeros(dim)
        a[alpha_direction] = 1.0
        b = float(z_target[alpha_direction])
        alpha = LinearConstraint(a, b, name="alpha_dIse")

        r = ball_radius_factor * (float(np.linalg.norm(z_target)) + 1.0)
        beta = BallConstraint(r=r, center=z_target, name="beta_VH")

        kappa = kappa_factor * dim
        gamma = QuadraticConstraint(
            kappa=kappa, Q=None, center=z_target, name="gamma_Jd4m"
        )

        return cls([alpha, beta, gamma])


# ---- uma/semantic/friction.py ----------------------------------------
"""
SemanticFriction -- dH/dt accumulator tracking the actual GENERIC Hamiltonian.

WHAT CHANGED:
    Previous versions tracked dE/dt where E = |z|^2/2 (DC mode proxy).
    This version tracks dH/dt where H = H[psi] (actual GENERIC Hamiltonian).

    The friction and the relativistic outputs (MSR stress tensor, Einstein
    tensor) are now tracking the SAME physical quantity. The bridge between
    semantic closure and GR is now operative, not just structural.

    H[psi] = integral [ alpha |grad psi|^2 - mu |psi|^2 + (g/2) |psi|^4 ]
    dH/dt = (H_curr - H_prev) / dt   (energy flow rate)

    Closure when |dH/dt| < dH_dt_floor:
        The system's energy rate has dropped below the mean thermal
        fluctuation rate of H[psi] -- indistinguishable from equilibrium.
        This is the same condition the MSR stress tensor measures.

THRESHOLDS (from 50 GENERIC trajectories, 2000 production steps each):
    H_target       = 1.0928   mean(H[psi])
    dH_dt_floor    = 1.2923   mean(|dH/dt|) -- thermal noise rate of H
    dH_dt_p25      = 0.5192   lower quartile (tighter threshold)

PATTERN (Engine3 structure preserved):
    H        = client.dynamics.hamiltonian(lift(z))   # actual energy
    dH_dt    = (H - H_prev) / dt                      # rate of change
    friction -= step_weight / (1 + |dH_dt| / floor)   # decimal walk
    closed when friction < 0.15 AND |dH_dt| < floor AND |z - z*| < tol
"""

from dataclasses import dataclass
from typing import Callable, List, Optional

import numpy as np

pass  # uma import flattened (symbols are top-level)
pass  # uma import flattened (symbols are top-level)


# ---------------------------------------------------------------------------
# Config
# ---------------------------------------------------------------------------

@dataclass
class UmaSemanticFrictionConfig:
    step_weight: float = 0.02
    closure_friction_threshold: float = 0.15
    convergence_dz_dt: float = CALIBRATED_DH_DT_FLOOR
    closure_state_tol: float = CALIBRATED_FIELD_SCALE * 2.0
    min_steps_before_closure: int = 8
    kT: float = 0.005
    lam: float = 0.4
    N: int = 32
    dt: float = 0.04

    @classmethod
    def from_uma_config(cls, cfg, dt: float = 0.04, **kwargs) -> "UmaSemanticFrictionConfig":
        return cls(
            kT=cfg.generic.kT, lam=cfg.generic.reaction,
            N=cfg.grid.N, dt=dt, **kwargs,
        )


# ---------------------------------------------------------------------------
# FrictionRecord
# ---------------------------------------------------------------------------

@dataclass
class FrictionRecord:
    t: float
    H: float          # actual H[psi]
    E: float          # |z|^2 / 2 -- proxy
    dH_dt: float      # (H - H_prev) / dt
    dE_dt: float      # (E - E_prev) / dt -- proxy
    friction: float   # accumulated in [0, 1]
    z_distance: float
    closed: bool


# ---------------------------------------------------------------------------
# SemanticFriction
# ---------------------------------------------------------------------------

class SemanticFriction:
    """
    Tracks semantic friction via dH/dt -- the actual GENERIC Hamiltonian rate.

    Requires a hamiltonian_fn: z -> H[psi]. Provided by the pipeline as
    client.dynamics.hamiltonian(lift(z)). When None, falls back to the
    |z|^2 / 2 proxy.
    """

    def __init__(
        self,
        z_target: np.ndarray,
        config: Optional[UmaSemanticFrictionConfig] = None,
        hamiltonian_fn: Optional[Callable[[np.ndarray], float]] = None,
    ):
        self.z_target = np.asarray(z_target, dtype=float)
        self.config = config or UmaSemanticFrictionConfig()
        self.hamiltonian_fn = hamiltonian_fn

        self._friction: float = 1.0
        self._H_prev: Optional[float] = None
        self._E_prev: Optional[float] = None
        self._records: List[FrictionRecord] = []
        self._times: List[float] = []
        self._frictions: List[float] = []

    def reset(self, initial_posterior: FieldPosterior) -> None:
        self._friction = 1.0
        self._H_prev = None
        self._E_prev = None
        self._records.clear()
        self._times.clear()
        self._frictions.clear()

    def update(self, posterior: FieldPosterior, t: float) -> FrictionRecord:
        """One friction step."""
        cfg = self.config
        z = posterior.mean

        # Proxy energy (always computed)
        E = float(np.real(z @ z) / 2.0)
        dE_dt = (E - self._E_prev) / cfg.dt if self._E_prev is not None else 0.0
        self._E_prev = E

        # Actual Hamiltonian (if available)
        if self.hamiltonian_fn is not None:
            H = float(self.hamiltonian_fn(z))
            dH_dt = (H - self._H_prev) / cfg.dt if self._H_prev is not None else 0.0
            self._H_prev = H
        else:
            # Proxy fallback: scale E to H units
            scale = (CALIBRATED_H_TARGET / max(abs(E), 1e-15))
            H = E * scale
            dH_dt = dE_dt * scale

        # Friction decrement: dH/dt against H-calibrated floor
        floor = cfg.convergence_dz_dt + 1e-15
        step = cfg.step_weight / (1.0 + abs(dH_dt) / floor)
        self._friction = max(0.0, self._friction - step)

        field_scale = CALIBRATED_FIELD_SCALE + 1e-15
        z_dist = float(np.linalg.norm(z - self.z_target)) / field_scale

        closed = False
        if len(self._records) >= cfg.min_steps_before_closure:
            closed = (
                self._friction < cfg.closure_friction_threshold
                and abs(dH_dt)  < cfg.convergence_dz_dt
                and z_dist      < cfg.closure_state_tol / field_scale
            )

        rec = FrictionRecord(
            t=t, H=H, E=E,
            dH_dt=dH_dt, dE_dt=dE_dt,
            friction=self._friction,
            z_distance=z_dist,
            closed=closed,
        )
        self._records.append(rec)
        self._times.append(t)
        self._frictions.append(self._friction)
        return rec

    @property
    def value(self) -> float:
        return self._friction

    @property
    def is_closed(self) -> bool:
        return bool(self._records and self._records[-1].closed)

    @property
    def closure_step(self) -> Optional[int]:
        for i, r in enumerate(self._records):
            if r.closed:
                return i
        return None

    @property
    def records(self) -> List[FrictionRecord]:
        return list(self._records)

    def summary(self) -> dict:
        if not self._records:
            return {"status": "no_data"}
        final = self._records[-1]
        return {
            "sf_total":              round(self._friction, 6),
            "friction_final":        round(final.friction, 6),
            "H_final":               round(final.H, 6),
            "H_target":              round(CALIBRATED_H_TARGET, 6),
            "dH_dt_final":           round(final.dH_dt, 6),
            "dH_dt_floor":           round(self.config.convergence_dz_dt, 6),
            # canonical alias names (single-rep version tracks H, not E proxy)
            "dz_dt_final":           round(final.dH_dt, 6),
            "dz_dt_floor":           round(self.config.convergence_dz_dt, 6),
            "E_final":               round(final.E, 8),
            "dE_dt_final":           round(final.dE_dt, 8),
            "z_distance_final":      round(final.z_distance, 4),
            "n_steps":               len(self._records),
            "is_closed":             self.is_closed,
            "closure_step":          self.closure_step,
            "semantic_loss_pct":     round(self._friction * 100, 2),
            "using_hamiltonian":     self.hamiltonian_fn is not None,
        }


# ---- uma/semantic/inarticulation.py ----------------------------------
"""
Inarticulation Function -- G Translation.

The Inarticulation Function G is the final stage of the Semantic Engine:
it takes the **solved** State-Space Closure (Omega) and translates it
back into tangible production metrics.

In the UMA framework:
    G: (z_Omega, posterior_Omega, friction_summary, constraint_report)
       -> ProductionMetrics

This is the inverse of the initial ingestion step: the engine
"inarticulates" (makes concrete) the abstract solved trajectory.

Built-in translators:
    NullInarticulator        -- identity pass.
    ProjectionInarticulator  -- linear readout W : R^d -> R^m + phi.
    LLMInarticulator         -- (placeholder for LLM observation readout).

Stages (mirrors the SE spec table):
    Ingestion       -> Initial differential, friction at t = 0
    Stability       -> Equalities Filter, friction descending
    Inarticulation  -> G Translation, friction below threshold
    Solve           -> State-Space Closure, closed = True
"""

from abc import ABC, abstractmethod
from dataclasses import dataclass
from typing import Any, Callable, Dict, List, Optional

import numpy as np


# ---------------------------------------------------------------------------
# ProductionMetrics
# ---------------------------------------------------------------------------

@dataclass
class ProductionMetrics:
    """
    Tangible production output from the Inarticulation stage.
    All quantities are scalar or low-dimensional.
    """
    semantic_density: float       # 1 - SF_total in [0, 1]
    trajectory_delta: float       # ||z_Omega - z_target||
    scaling_coefficient: float    # det(Sigma)^{-1/d}
    stability_index: float        # 1 - final_constraint_violation
    constraint_converged: bool
    stage: str                    # 'ingestion' | 'stability' | 'inarticulation' | 'solve'
    closed: bool
    readout: Optional[np.ndarray] = None
    readout_labels: Optional[List[str]] = None
    friction_summary: Optional[Dict[str, Any]] = None
    constraint_report: Optional[Dict[str, Any]] = None

    def as_dict(self) -> Dict[str, Any]:
        d = {
            "semantic_density": round(self.semantic_density, 6),
            "trajectory_delta": round(self.trajectory_delta, 6),
            "scaling_coefficient": round(self.scaling_coefficient, 6),
            "stability_index": round(self.stability_index, 6),
            "constraint_converged": self.constraint_converged,
            "stage": self.stage,
            "closed": self.closed,
        }
        if self.readout is not None:
            d["readout"] = self.readout.tolist()
        if self.readout_labels is not None:
            d["readout_labels"] = self.readout_labels
        if self.friction_summary is not None:
            d["friction_summary"] = self.friction_summary
        if self.constraint_report is not None:
            d["constraint_report"] = self.constraint_report
        return d

    def __repr__(self) -> str:
        return (
            f"ProductionMetrics(stage={self.stage!r}, closed={self.closed}, "
            f"density={self.semantic_density:.4f}, "
            f"delta={self.trajectory_delta:.4f}, "
            f"stability={self.stability_index:.4f})"
        )


# ---------------------------------------------------------------------------
# Stage classifier
# ---------------------------------------------------------------------------

def classify_stage(
    sf_value: float,
    is_closed: bool,
    sf_stability_threshold: float = 0.50,
    sf_inarticulation_threshold: float = 0.20,
) -> str:
    """
    sf_value = 1.0          -> ingestion
    sf_value in (0.5, 1.0)  -> stability
    sf_value in (0.2, 0.5)  -> stability or inarticulation depending on sub-thresholds
    closed = True           -> solve
    """
    if is_closed:
        return "solve"
    if sf_value > sf_stability_threshold:
        return "ingestion"
    if sf_value > sf_inarticulation_threshold:
        return "stability"
    return "inarticulation"


# ---------------------------------------------------------------------------
# Scaling coefficient (single-representation FieldPosterior)
# ---------------------------------------------------------------------------

def _scaling_coefficient(posterior) -> float:
    """det(Sigma)^{-1/d}. High = concentrated. Low = diffuse."""
    d = posterior.dim
    Sigma = posterior.cov
    sign, logdet = np.linalg.slogdet(Sigma)
    if sign <= 0:
        return 0.0
    return float(np.exp(-logdet / d))


# ---------------------------------------------------------------------------
# Abstract Inarticulator
# ---------------------------------------------------------------------------

class Inarticulator(ABC):
    """Abstract base for G Translation functions."""

    @abstractmethod
    def translate(
        self,
        z_omega: np.ndarray,
        posterior,
        z_target: np.ndarray,
        friction_summary: Dict[str, Any],
        constraint_report: Dict[str, Any],
    ) -> ProductionMetrics:
        ...


# ---------------------------------------------------------------------------
# NullInarticulator
# ---------------------------------------------------------------------------

class NullInarticulator(Inarticulator):
    """Identity pass."""

    def translate(self, z_omega, posterior, z_target, friction_summary, constraint_report):
        sf_total = friction_summary.get("sf_total", 1.0)
        is_closed = friction_summary.get("is_closed", False)
        stage = classify_stage(sf_total, is_closed)
        delta = float(np.linalg.norm(z_omega - z_target))
        scl = _scaling_coefficient(posterior)
        final_viol = constraint_report.get("final_total_violation", 0.0)
        converged = constraint_report.get("converged", True)
        stability = float(np.clip(1.0 - final_viol, 0.0, 1.0))

        return ProductionMetrics(
            semantic_density=1.0 - sf_total,
            trajectory_delta=delta,
            scaling_coefficient=scl,
            stability_index=stability,
            constraint_converged=converged,
            stage=stage,
            closed=is_closed,
            readout=z_omega.copy(),
            readout_labels=[f"z_{i}" for i in range(len(z_omega))],
            friction_summary=friction_summary,
            constraint_report=constraint_report,
        )


# ---------------------------------------------------------------------------
# ProjectionInarticulator
# ---------------------------------------------------------------------------

class ProjectionInarticulator(Inarticulator):
    """Linear readout W : R^d -> R^m applied to z_Omega, then phi nonlinearity."""

    def __init__(
        self,
        W: np.ndarray,
        phi: Optional[Callable[[np.ndarray], np.ndarray]] = None,
        labels: Optional[List[str]] = None,
    ):
        self._W = np.asarray(W, dtype=float)
        self._phi = phi if phi is not None else (lambda x: x)
        self._labels = labels

    def translate(self, z_omega, posterior, z_target, friction_summary, constraint_report):
        sf_total = friction_summary.get("sf_total", 1.0)
        is_closed = friction_summary.get("is_closed", False)
        stage = classify_stage(sf_total, is_closed)

        readout_raw = self._phi(self._W @ z_omega)
        delta = float(np.linalg.norm(z_omega - z_target))
        scl = _scaling_coefficient(posterior)
        final_viol = constraint_report.get("final_total_violation", 0.0)
        converged = constraint_report.get("converged", True)
        stability = float(np.clip(1.0 - final_viol, 0.0, 1.0))

        return ProductionMetrics(
            semantic_density=1.0 - sf_total,
            trajectory_delta=delta,
            scaling_coefficient=scl,
            stability_index=stability,
            constraint_converged=converged,
            stage=stage,
            closed=is_closed,
            readout=readout_raw,
            readout_labels=self._labels,
            friction_summary=friction_summary,
            constraint_report=constraint_report,
        )

    @classmethod
    def principal_components(
        cls, dim: int, m: int = 4, labels: Optional[List[str]] = None,
    ) -> "ProjectionInarticulator":
        """Random orthonormal readout basis of rank m. Replace with calibrated W in production."""
        rng = np.random.default_rng(0)
        A = rng.standard_normal((dim, m))
        Q, _ = np.linalg.qr(A)
        return cls(W=Q.T[:m, :].copy(), labels=labels)


# ---- uma/semantic/engine.py ------------------------------------------
"""
SemanticEngine -- compiler + runner.

STACK (correct separation):
    SemanticEngine          compiles intent -> UMA_IR
        |
    UMA_IR                  execution graph
        |
    UMAExecutor             drives kernel
        |
    UMAClient               physics (untouched)

ENGINE3 BRIDGE -- Silver grounded:
    binary weight: x = len(binary(s)) / len(binary(anchor))
    complex state: z_c = x * ((1 - sqrt 2) + i sqrt e)
    E_integral:    E = |z_c|^2 / 2 = x^2 * (3 - 2 sqrt 2 + e) / 2
    dH_dt:         (H - H_prev) / dt
    friction:      walks down by step_weight / (1 + |dH_dt| / floor)

The imaginary component sqrt(e) is the architectural bridge between:
    pi    (continuous spacetime geometry)
    delta_S (discrete Silver Ratio / Pell recursion)

Closure (Omega) when:
    friction < 0.15
    |dH_dt|  < CALIBRATED_DH_DT_FLOOR
    |z - z*| < 2 * field_scale
"""

import math
from dataclasses import dataclass, field
