@dataclass
class SemanticEngineConfig:
    friction: UmaSemanticFrictionConfig = field(default_factory=UmaSemanticFrictionConfig)
    stop_on_closure: bool = True
    verbose: bool = False
    obs_every: int = 1
    constrain_every: int = 1

    @classmethod
    def from_uma_config(cls, cfg, dt: float = 0.04, **kwargs) -> "SemanticEngineConfig":
        return cls(
            friction=UmaSemanticFrictionConfig.from_uma_config(cfg, dt=dt),
            **kwargs,
        )


# ---------------------------------------------------------------------------
# Result
# ---------------------------------------------------------------------------

@dataclass
class SemanticEngineResult:
    is_closed: bool
    closure_node: Optional[str]
    friction_records: List[FrictionRecord]
    friction_summary: Dict[str, Any]
    final_posterior: Any
    z_final: np.ndarray
    production_metrics: ProductionMetrics
    nodes_executed: int
    ir: UMA_IR

    def summary(self) -> str:
        pm = self.production_metrics
        fs = self.friction_summary
        f_final = fs.get('friction_final', 0.0) if isinstance(fs, dict) else 0.0
        dH_dt   = fs.get('dH_dt_final',   0.0) if isinstance(fs, dict) else 0.0
        H_final = fs.get('H_final',        0.0) if isinstance(fs, dict) else 0.0
        H_target = fs.get('H_target',     0.0) if isinstance(fs, dict) else 0.0
        floor = fs.get('dH_dt_floor',     0.0) if isinstance(fs, dict) else 0.0
        return (
            "\nSemanticEngine Result\n"
            f"   IR:                 {self.ir.summary()}\n"
            f"   Nodes executed:     {self.nodes_executed}\n"
            f"   Stage:              {pm.stage}\n"
            f"   Closed (Omega):     {self.is_closed}\n"
            f"   Closure node:       {self.closure_node}\n"
            f"   Friction:           {f_final:.4f}\n"
            f"   dH/dt final:        {dH_dt:.4e}\n"
            f"   dH/dt floor:        {floor:.4e}\n"
            f"   H_final:            {H_final:.6e}\n"
            f"   H_target:           {H_target:.6e}\n"
            f"   Semantic density:   {pm.semantic_density:.4f}\n"
            f"   Stability index:    {pm.stability_index:.4f}\n"
            f"   1/delta_S^2 =       {INV_DELTA_S_SQ:.6f}\n"
        )


# ---------------------------------------------------------------------------
# SemanticEngine -- compiler
# ---------------------------------------------------------------------------

class SemanticEngine:
    """Compiles intent -> UMA_IR, then runs via UMAExecutor."""

    def __init__(
        self,
        z_target: np.ndarray,
        config: Optional[SemanticEngineConfig] = None,
        constraints: Optional[List[EqualityConstraint]] = None,
        inarticulator: Optional[Inarticulator] = None,
    ):
        self.z_target = np.asarray(z_target, dtype=float)
        self.config = config or SemanticEngineConfig()
        self._user_constraints = constraints
        self.inarticulator = inarticulator or NullInarticulator()

    @classmethod
    def from_uma_config(
        cls, cfg, z_target: np.ndarray, dt: float = 0.04, **kwargs
    ) -> "SemanticEngine":
        engine_cfg = SemanticEngineConfig.from_uma_config(cfg, dt=dt)
        return cls(z_target=z_target, config=engine_cfg, **kwargs)

    def compile(
        self,
        n_steps: int,
        dt: float,
        observations: Optional[List[Tuple[Observation, np.ndarray]]],
        constraint_set: ConstraintSet,
    ) -> UMA_IR:
        ir = UMA_IR()
        ir.metadata = {"z_target": self.z_target, "n_steps": n_steps, "dt": dt}

        obs_cycle = len(observations) if observations else 0
        obs_idx = 0

        for step in range(n_steps):
            sid = f"s{step:04d}"
            ir.append(IRNode(f"{sid}_evolve", "evolve", {"dt": dt}))

            if observations and step % self.config.obs_every == 0:
                obs, y = observations[obs_idx % obs_cycle]
                obs_idx += 1
                ir.append(IRNode(
                    f"{sid}_observe", "observe",
                    {"observation": obs, "y": y},
                ))

            if step % self.config.constrain_every == 0:
                ir.append(IRNode(
                    f"{sid}_constrain", "constrain",
                    {"constraint_set": constraint_set},
                ))

            ir.append(IRNode(f"{sid}_ckpt", "checkpoint", {}))

        return ir

    def run(
        self,
        client,
        n_steps: int = 100,
        dt: float = 0.04,
        observations: Optional[List[Tuple[Observation, np.ndarray]]] = None,
    ) -> SemanticEngineResult:
        dim = len(self.z_target)
        cs = (
            ConstraintSet(self._user_constraints, max_iters=20, tol=1e-6)
            if self._user_constraints
            else ConstraintSet.default_semantic_constraints(dim, self.z_target)
        )

        ir = self.compile(n_steps, dt, observations, cs)
        if self.config.verbose:
            print(f"[SemanticEngine] {ir.summary()}")

        # Hamiltonian function for friction tracker
        def H_of_z(z: np.ndarray) -> float:
            psi = client.projection.lift(z)
            return float(client.dynamics.cfg.dt and 0.0 + 0.0)  # placeholder
        # actually use the client's hamiltonian directly:
        def H_of_z_real(z: np.ndarray) -> float:
            psi = client.projection.lift(z)
            pass  # uma import flattened (symbols are top-level)
            return hamiltonian(psi, lam=client.config.generic.reaction)

        friction = SemanticFriction(
            self.z_target, self.config.friction, hamiltonian_fn=H_of_z_real,
        )
        executor = UMAExecutor(
            friction=friction,
            inarticulator=self.inarticulator,
            stop_on_closure=self.config.stop_on_closure,
            verbose=self.config.verbose,
        )
        ex: ExecutorResult = executor.run(ir, client)

        return SemanticEngineResult(
            is_closed=ex.is_closed,
            closure_node=ex.closure_node,
            friction_records=ex.friction_records,
            friction_summary=ex.friction_summary,
            final_posterior=ex.final_posterior,
            z_final=ex.z_final,
            production_metrics=ex.production_metrics,
            nodes_executed=ex.nodes_executed,
            ir=ir,
        )


# ---------------------------------------------------------------------------
# Engine3 bridge
# ---------------------------------------------------------------------------

def tokenize_to_binary_weight(s: str, anchor: str = "dIse") -> float:
    """Engine3's binary mapping: len(binary(s)) / len(binary(anchor))."""
    binary = ''.join(format(ord(c), '08b') for c in s)
    a_bin = ''.join(format(ord(c), '08b') for c in anchor)
    return len(binary) / max(len(a_bin), 1)


def string_to_observation(
    s: str,
    dim: int,
    anchor: str = "dIse",
    cfg=None,
) -> Tuple[GaussianObservation, np.ndarray]:
    """
    Engine3 -> UMA bridge, Silver-grounded.

    Pipeline:
        s -> x (binary weight)
        x -> z_complex = x * ((1 - sqrt 2) + i sqrt e)
        E = |z_complex|^2 / 2
        E -> normalized to field scale
        y = direction * E_normalized
    """
    x = tokenize_to_binary_weight(s, anchor)

    z_c = engine3_complex_state(x)
    E_raw = engine3_E(x)

    if cfg is not None:
        kT = cfg.generic.kT
        N = cfg.grid.N
        fs = silver_field_scale(kT, N, 1.0)
        x_norm = x / (x + 1.0)
        y_scale = fs * x_norm
    else:
        x_norm = x / (x + 1.0)
        y_scale = x_norm * math.sqrt(2.0 * E_raw)

    y = np.full(dim, y_scale / max(dim, 1) * math.sqrt(dim))
    noise_var = max(y_scale ** 2 * INV_DELTA_S_SQ, 1e-10)
    R = noise_var * np.eye(dim)
    obs = GaussianObservation(H=np.eye(dim), R=R)
    return obs, y


# ---- uma/semantic/executor.py ----------------------------------------
"""
UMAExecutor -- schedules and runs a UMA_IR graph against a UMAClient kernel.

This is the bridge layer:
    SemanticEngine (compiler/planner)
        |  emits
    UMA_IR
        |  consumed by
    UMAExecutor          <-- THIS FILE
        |  drives
    UMAClient (kernel)

The executor knows nothing about semantic intent. It only:
    1. Iterates the IR schedule
    2. Dispatches each node to the correct kernel call
    3. Records friction at every checkpoint node
    4. Returns a structured result

No semantic logic leaks into the kernel.

NOTE: This rebuild adapts the canonical executor to the single-
representation FieldPosterior. Behaviour is identical to the canonical
multi-rep executor on the 'full' representation.
"""

from dataclasses import dataclass
from typing import Any, Dict, List, Optional

import numpy as np

pass  # uma import flattened (symbols are top-level)
pass  # uma import flattened (symbols are top-level)
pass  # uma import flattened (symbols are top-level)
pass  # uma import flattened (symbols are top-level)
pass  # uma import flattened (symbols are top-level)


@dataclass
class ExecutorResult:
    """Raw output from UMAExecutor.run()."""
    is_closed: bool
    closure_node: Optional[str]
    friction_records: List[FrictionRecord]
    friction_summary: Dict[str, Any]
    final_posterior: FieldPosterior
    z_final: np.ndarray
    production_metrics: ProductionMetrics
    nodes_executed: int


class UMAExecutor:
    """
    Executes a UMA_IR schedule against a live UMAClient.
    Stateless across runs -- all state lives in the client.
    """

    def __init__(
        self,
        friction: SemanticFriction,
        inarticulator: Optional[Inarticulator] = None,
        stop_on_closure: bool = True,
        verbose: bool = False,
    ):
        self.friction = friction
        self.inarticulator = inarticulator or NullInarticulator()
        self.stop_on_closure = stop_on_closure
        self.verbose = verbose

    def _log(self, msg: str) -> None:
        if self.verbose:
            print(f"[UMAExecutor] {msg}")

    def run(self, ir: UMA_IR, client) -> ExecutorResult:
        """Execute ir.schedule against client. Client must be initialized."""
        posterior = client.filter.posterior
        self.friction.reset(posterior)

        z_target = ir.metadata.get("z_target", np.zeros(posterior.dim))
        node_map = {n.node_id: n for n in ir.nodes}

        last_constraint_report: Dict[str, Any] = {
            "converged": True, "final_total_violation": 0.0,
        }
        closure_node: Optional[str] = None

        nodes_executed = 0
        t = client.t

        for node_id in ir.schedule:
            node: IRNode = node_map[node_id]
            nodes_executed += 1

            if node.kind == "evolve":
                dt = node.payload.get("dt", None)
                client.evolve(dt=dt)
                t = client.t

            elif node.kind == "observe":
                obs = node.payload["observation"]
                y = node.payload["y"]
                client.observe(obs, y)

            elif node.kind == "constrain":
                cs: ConstraintSet = node.payload["constraint_set"]
                z = client.filter.posterior.mean.copy()
                z_anchored, report = cs.apply(z)
                last_constraint_report = report
                client.filter.posterior = FieldPosterior(
                    mean=z_anchored, cov=client.filter.posterior.cov,
                )
                client.psi = client.projection.lift(z_anchored)

            elif node.kind == "checkpoint":
                rec = self.friction.update(client.filter.posterior, t)
                self._log(
                    f"{node_id}  t={t:.3f}  "
                    f"H={rec.H:.4f}  dH/dt={rec.dH_dt:.4e}  "
                    f"friction={rec.friction:.4f}  closed={rec.closed}"
                )
                if self.stop_on_closure and rec.closed:
                    closure_node = node_id
                    self._log(f"Closure (Omega) at {node_id}")
                    break
            else:
                self._log(f"Unknown IR node kind: {node.kind!r}")

        posterior = client.filter.posterior
        z_final = posterior.mean.copy()
        friction_summary = self.friction.summary()

        production_metrics = self.inarticulator.translate(
            z_omega=z_final,
            posterior=posterior,
            z_target=z_target,
            friction_summary=friction_summary,
            constraint_report=last_constraint_report,
        )

        return ExecutorResult(
            is_closed=self.friction.is_closed,
            closure_node=closure_node,
            friction_records=self.friction.records,
            friction_summary=friction_summary,
            final_posterior=posterior,
            z_final=z_final,
            production_metrics=production_metrics,
            nodes_executed=nodes_executed,
        )


# ---- uma/client.py ---------------------------------------------------
"""
uma.client -- UMAClient: kernel orchestrating projection + dynamics + filter.

Architecture:
    UMAClient owns:
      - the spatial field psi(N, N)
      - a UmaFieldProjection that maps psi <-> z
      - a Kalman filter over z
      - a GENERICDynamics evolver that steps psi

The semantic layer (engine, executor, IR) talks to the client through:
      client.evolve(dt)
      client.observe(obs, y)
      client.psi             -- current spatial state
      client.filter.posterior -- current Gaussian posterior over z
"""

import numpy as np
from typing import Optional
pass  # uma import flattened (symbols are top-level)
pass  # uma import flattened (symbols are top-level)
pass  # uma import flattened (symbols are top-level)
pass  # uma import flattened (symbols are top-level)
pass  # uma import flattened (symbols are top-level)
pass  # uma import flattened (symbols are top-level)


class UMAClient:
    """The deterministic kernel. Knows nothing of semantic intent."""

    def __init__(self, config: Optional[Config] = None):
        self.config = config if config is not None else Config()
        self.projection = UmaFieldProjection(N=self.config.grid.N, n_modes=self.config.grid.n_modes)
        d = self.projection.real_dim
        post = FieldPosterior.initial(d=d, init_cov=self.config.filter.init_cov)
        self.filter = KalmanFilter(post, process_noise=self.config.filter.process_noise)
        self.dynamics = GENERICDynamics(self.config.generic)
        self.dynamics.seed(self.config.seed)
        self.psi: np.ndarray = np.zeros((self.config.grid.N, self.config.grid.N), dtype=complex)
        self.t = 0.0
        self._step_count = 0

    # ------------------------------------------------------------------
    # initialisation
    # ------------------------------------------------------------------
    def initialize(
        self,
        psi0: np.ndarray,
        sigma0: Optional[float] = None,
        dt: Optional[float] = None,
    ) -> None:
        psi0 = np.asarray(psi0, dtype=complex)
        if psi0.shape != self.psi.shape:
            raise ValueError(f"psi0 shape {psi0.shape} != grid shape {self.psi.shape}")
        self.psi = psi0
        z0 = self.projection.project(psi0)
        self.filter.posterior.mean = z0
        if sigma0 is not None:
            d = self.projection.real_dim
            self.filter.posterior.cov = float(sigma0) * np.eye(d)
        if dt is not None:
            self.dynamics.cfg.dt = float(dt)
        self.t = 0.0
        self._step_count = 0

    # Compat alias used by canonical executor / engine
    @property
    def posterior_state(self) -> FieldPosterior:
        return self.filter.posterior

    @posterior_state.setter
    def posterior_state(self, p: FieldPosterior) -> None:
        self.filter.posterior = p

    # ------------------------------------------------------------------
    # evolution
    # ------------------------------------------------------------------
    def evolve(self, dt: Optional[float] = None) -> None:
        """Forward GENERIC step. Updates psi, syncs posterior mean."""
        if dt is not None:
            old_dt = self.dynamics.cfg.dt
            self.dynamics.cfg.dt = dt
            self.psi = self.dynamics.step(self.psi)
            self.dynamics.cfg.dt = old_dt
            self.t += dt
        else:
            self.psi = self.dynamics.step(self.psi)
            self.t += self.dynamics.cfg.dt
        # gentle covariance inflation (process noise on z)
        d = self.projection.real_dim
        F = np.eye(d)
        Q = self.config.filter.process_noise * np.eye(d)
        # update mean from psi via projection (deterministic-only sync)
        z_new = self.projection.project(self.psi)
        self.filter.posterior.mean = z_new
        self.filter.posterior.cov = F @ self.filter.posterior.cov @ F.T + Q
        self.filter.posterior.cov = 0.5 * (self.filter.posterior.cov + self.filter.posterior.cov.T)
        self._step_count += 1

    def observe(self, obs: Observation, y: np.ndarray) -> None:
        """Apply a Gaussian observation update."""
        self.filter.update(np.asarray(y, dtype=float), obs.H, obs.R)
        # lift the updated z back into psi (band-limited)
        z = self.filter.posterior.mean
        self.psi = self.projection.lift(z)

    # ------------------------------------------------------------------
    # diagnostics
    # ------------------------------------------------------------------
    def hamiltonian(self) -> float:
        return hamiltonian(self.psi, lam=self.config.generic.reaction)

    def entropy(self) -> float:
        return entropy_S(self.psi)

    def msr_response(self) -> np.ndarray:
        return msr_response(self.psi, lam=self.config.generic.reaction)

    @property
    def z(self) -> np.ndarray:
        """Current projected state."""
        return self.filter.posterior.mean

    @property
    def cov(self) -> np.ndarray:
        return self.filter.posterior.cov


# ---- uma/pipeline.py -------------------------------------------------
"""
uma/pipeline.py -- The complete UMA pipeline. All 15 modules integrated.

FLOW (sphere outward, then field inward):

    AcousticSphereGeometry              sphere/geometry.py
        -> SystemGeometry               (all params derived, nothing chosen)
        -> SphereVenturi                sphere/field.py
        -> SpherePendulum               sphere/field.py
        -> SphereProjectionField        sphere/field.py
        -> Planck input B(nu, T)        (e is structural)

    UMAClient + GENERICDynamics         client.py + dynamics/generic.py
        -> H[psi], dH/dpsi*, S[psi]     (actual Hamiltonian, not |z|^2/2)
        -> dissipative_drift            (entropy production)
        -> psi_hat = -dH/dpsi*          (MSR response field, exact)

    CrossDomainInjector + VenturiOperator   venturi/{injector,operator}.py
        -> 360-degree azimuthal injection (both domains: MSR + semantic)

    SemanticEngine                      semantic/engine.py
        -> UMA_IR compiler              semantic/ir.py
        -> UMAExecutor                  semantic/executor.py
        -> SemanticFriction             semantic/friction.py
        -> ConstraintSet                semantic/constraints.py
        -> Inarticulator                semantic/inarticulation.py

    MSR verification                    msr/stress_energy.py
        -> <T_munu> ~ G_munu^(1)        (GR confirmed per step)

    TensorBridge                        msr/tensor_bridge.py
        -> live <T_munu> <-> G_munu^(1) residual

    Wetterich RG                        msr/wetterich_flow.py
        -> universality class           (Levy basin, z = 1.5)

OUTPUT: UMAPipelineResult
    All geometry (exact, derived)
    H[psi] trajectory (real Hamiltonian, not proxy)
    Friction walk (Bellman convergence)
    Pendulum samples (sphere field measurements)
    MSR/GR cosine similarity
    RG basin classification
    Closure status
"""

