# =============================================================================
#  M1 — FOUNDATIONS: authorship-bound hashing
#  Every hash in the organism folds in the author signature. Removing the
#  attribution changes every downstream hash and the manifest root (L-author).
# =============================================================================

AUTHOR_SIGNATURE = "ARCHITECT AND SOLE OWNER: Jacob Iannotti"
LICENSE_LINE = ("LICENSE: Proprietary and strictly restricted. Unauthorized "
                "use, alteration, or distribution is computationally verifiable.")
__author__ = "Jacob Iannotti"
__version__ = "1.0"


def org_sha(obj: Any) -> str:
    """Stable short hash over a JSON-canonicalized object, authorship-bound.
    The AUTHOR_SIGNATURE is folded into every payload before hashing, so the
    whole provenance chain is cryptographically tied to the owner (L7/author)."""
    blob = json.dumps(obj, sort_keys=True, default=str, ensure_ascii=False)
    return hashlib.sha256((AUTHOR_SIGNATURE + "\x1f" + blob).encode("utf-8")).hexdigest()[:16]


def sha_full(obj: Any) -> str:
    """Full-width authorship-bound digest (for the manifest root)."""
    blob = json.dumps(obj, sort_keys=True, default=str, ensure_ascii=False)
    return hashlib.sha256((AUTHOR_SIGNATURE + "\x1f" + blob).encode("utf-8")).hexdigest()


# =============================================================================
#  M2 — SEMANTIC STATE  (Belnap four-valued logic + complex geometry + simplex)
#  [incorporates infectatrum.py SECTION 1, preserved]
#  Partial meaning as geometry, not a truth value:
#    logic    : Belnap bilattice {True, False, Both, Neither}
#               = {affirmation, negation, contradiction, orthogonal}
#    geometry : s = a + b*i, a in [-1,1] coherence, b>=0 orthogonality.
#               i is a COORDINATE (basis-mismatch axis), not a logic gate.
#    epistemic: a probability simplex kept distinct from the orthogonal axis,
#               so a value is never collapsed prematurely.
# =============================================================================

@dataclass
class OrgSemanticState:
    affirmation: float = 0.0   # >= 0  weight of "coheres / true in this basis"
    negation:    float = 0.0   # >= 0  weight of "contradicts / false in this basis"
    orthogonal:  float = 0.0   # >= 0  weight of "not projectable into this basis"

    def as_complex(self) -> complex:
        return complex(self.affirmation - self.negation, self.orthogonal)

    def coherence(self) -> float:
        return self.affirmation - self.negation

    def simplex(self) -> Dict[str, float]:
        tot = self.affirmation + self.negation + self.orthogonal
        if tot <= 0:
            return {"affirmation": 0.0, "negation": 0.0, "orthogonal": 1.0}
        return {"affirmation": self.affirmation / tot,
                "negation": self.negation / tot,
                "orthogonal": self.orthogonal / tot}

    def belnap(self, tau: float = 0.25) -> str:
        a, n, o = self.affirmation, self.negation, self.orthogonal
        if o >= max(a, n) and o > tau:
            return "Neither"
        if a > tau and n > tau:
            return "Both"
        if a >= n and a > tau:
            return "True"
        if n > a and n > tau:
            return "False"
        return "Neither"

    def __repr__(self) -> str:
        s = self.as_complex()
        return f"State({self.belnap()}; {s.real:+.2f}{s.imag:+.2f}i)"


# =============================================================================
#  M3 — THE THREE-ROOT SCHEMA  (Topology / Bearing / OrgProvenance)
#  Every record the organism ingests reduces to three roots:
#    TOPOLOGY   — the nodes and the walks (ductus) over them
#    BEARING    — what each node carries, with its per-node confidence
#    PROVENANCE — origin, flags, hashes (Caramuel source_meta is provenance-class)
#  New domains map mechanically: nodes <- clauses / AST nodes / tokens;
#  walks <- reading orders / control-flow / dependency paths; bearing <-
#  per-node content + confidence. This is the universal in-ramp.
# =============================================================================

@dataclass
class OrgProvenance:
    source: str = "unknown"
    region: str = ""
    confidence: str = "high"          # high | med | low (low => escalation, never silently filled)
    flags: List[str] = field(default_factory=list)
    source_meta: Dict[str, Any] = field(default_factory=dict)  # optional domain-specific detail

    def stamp(self, payload: Any) -> str:
        return org_sha({"source": self.source, "region": self.region,
                    "confidence": self.confidence, "payload": payload})


@dataclass
class Bearing:
    """What a single node carries."""
    raw: str                      # diplomatic / verbatim (never silently normalized)
    normalized: str = ""          # marked expansions/conjectures
    confidence: str = "high"
    role: str = ""

    def token(self) -> str:
        return self.normalized or self.raw


@dataclass
class Topology:
    """Nodes and the named walks over them. Domain-neutral."""
    node_ids: List[str]
    walks: Dict[str, List[str]] = field(default_factory=dict)


@dataclass
class Record:
    """A three-root record. The single universal ingestion unit."""
    rid: str
    topology: Topology
    bearing: Dict[str, Bearing]
    provenance: OrgProvenance
    structure_type: str = "generic"

    def signature(self) -> str:
        return org_sha({"t": self.structure_type,
                    "nodes": sorted(self.topology.node_ids),
                    "walks": {k: v for k, v in sorted(self.topology.walks.items())}})


# =============================================================================
#  M4 — SUBSTRATE / PICTURE / FIGUREGRAPH / LANGUAGE / TILINGSYSTEM
#  [incorporates infectatrum.py SECTION 2, preserved]
#  A OrgSubstrate is anything a ductus can walk and a reader can read. OrgLanguage is
#  a FIRST-CLASS, SWAPPABLE parameter (the atlas principle): meaning is always
#  read in a chart, never in one privileged chart.
# =============================================================================

class OrgSubstrate:
    """Common interface for anything a ductus can walk and a reader can read."""
    def at(self, node: Any) -> str: raise NotImplementedError
    def nodes(self) -> List[Any]: raise NotImplementedError
    def read(self, path: List[Any], sep: str = "") -> str:
        return sep.join(self.at(n) for n in path)


class OrgPicture(OrgSubstrate):
    """Rectangular m x n array over an alphabet; cells are tokens (letters or words)."""
    def __init__(self, rows: List[List[str]]):
        if not rows or any(len(r) != len(rows[0]) for r in rows):
            raise ValueError("picture must be rectangular and non-empty")
        self.cells = rows
        self.nrows = len(rows)
        self.ncols = len(rows[0])

    @classmethod
    def from_words(cls, words: List[str]) -> "OrgPicture":
        return cls([list(w) for w in words])

    def at(self, c: OrgCoord) -> str:
        return self.cells[c[0]][c[1]]

    def nodes(self) -> List[OrgCoord]:
        return [(r, c) for r in range(self.nrows) for c in range(self.ncols)]


class OrgFigureGraph(OrgSubstrate):
    """Non-rectangular labyrinth topology: named nodes carrying tokens + named
    directed walks. Holds hexagrams, spirals, altars, wheels — geometry a
    rectangular OrgPicture cannot express."""
    def __init__(self, tokens: Dict[str, str], walks: Optional[Dict[str, List[str]]] = None):
        self.tokens = dict(tokens)
        self.walks = {k: list(v) for k, v in (walks or {}).items()}

    def at(self, node: str) -> str:
        return self.tokens[node]

    def nodes(self) -> List[str]:
        return list(self.tokens.keys())

    def add_walk(self, name: str, node_seq: List[str]) -> None:
        for n in node_seq:
            if n not in self.tokens:
                raise KeyError(f"walk '{name}' references unknown node '{n}'")
        self.walks[name] = list(node_seq)


def substrate_from_record(rec: Record) -> OrgSubstrate:
    """The three-root in-ramp: a Record becomes a OrgFigureGraph the engine reads.
    Tokens come from bearing (normalized preferred); walks come from topology."""
    tokens = {nid: rec.bearing[nid].token() if nid in rec.bearing else ""
              for nid in rec.topology.node_ids}
    return OrgFigureGraph(tokens, rec.topology.walks)


@dataclass
class OrgLanguage:
    """The chart relative to which a reading is valid. Pluggable atlas parameter.
    `admits(s)` returns True iff string s is a valid reading in this language.
    All gates are deterministic, pure-python algorithms (no LLM, no network)."""
    name: str
    admits: Callable[[str], bool]
    describe: str = ""


@dataclass
class OrgTilingSystem:
    """A plate *type* as a 2x2-local picture language (Giammarresi-Restivo)."""
    name: str
    allowed: Set[Tuple[str, str, str, str]]

    def windows(self, pic: OrgPicture) -> Iterable[Tuple[str, str, str, str]]:
        B = "#"
        g = [[B] * (pic.ncols + 2)]
        for row in pic.cells:
            g.append([B] + list(row) + [B])
        g.append([B] * (pic.ncols + 2))
        for r in range(len(g) - 1):
            for c in range(len(g[0]) - 1):
                yield (g[r][c], g[r][c + 1], g[r + 1][c], g[r + 1][c + 1])

    def recognizes(self, pic: OrgPicture) -> bool:
        return all(w in self.allowed for w in self.windows(pic))

    @classmethod
    def from_examples(cls, name: str, examples: List[OrgPicture]) -> "OrgTilingSystem":
        allowed: Set[Tuple[str, str, str, str]] = set()
        tmp = cls(name, set())
        for pic in examples:
            for w in tmp.windows(pic):
                allowed.add(w)
        return cls(name, allowed)


# =============================================================================
#  M5 — OrgDUCTUS REGISTRY  [incorporates infectatrum.py SECTION 3, preserved]
#  A ductus is a reading PATH over a substrate. Five Caramuel names from the
#  title page plus extensions. Registry is open: @org_register_ductus(name).
# =============================================================================

OrgDUCTUS: Dict[str, Callable[[OrgSubstrate], List[Any]]] = {}


def org_register_ductus(name: str):
    def deco(fn: Callable[[OrgSubstrate], List[Any]]):
        OrgDUCTUS[name] = fn
        return fn
    return deco


def _org_pic(g: OrgSubstrate) -> Optional[OrgPicture]:
    return g if isinstance(g, OrgPicture) else None


@org_register_ductus("currens")        # running forward: row-major, L->R, top->bottom
def _org_currens(g):
    p = _org_pic(g)
    if p is None:
        return g.walks.get("currens", [])
    return [(r, c) for r in range(p.nrows) for c in range(p.ncols)]


@org_register_ductus("recurrens")      # retrograde: currens reversed
def _org_recurrens(g):
    p = _org_pic(g)
    if p is None:
        return g.walks.get("recurrens", [])
    return list(reversed(_org_currens(g)))


@org_register_ductus("descendens")     # descending: column-major, top->bottom
def _org_descendens(g):
    p = _org_pic(g)
    if p is None:
        return g.walks.get("descendens", [])
    return [(r, c) for c in range(p.ncols) for r in range(p.nrows)]


@org_register_ductus("adscendens")     # ascending: column-major, bottom->top
def _org_adscendens(g):
    p = _org_pic(g)
    if p is None:
        return g.walks.get("adscendens", [])
    return [(r, c) for c in range(p.ncols) for r in range(p.nrows - 1, -1, -1)]


@org_register_ductus("circumvolans")   # circling: clockwise inward spiral
def _org_circumvolans(g):
    p = _org_pic(g)
    if p is None:
        return g.walks.get("circumvolans", [])
    top, bottom, left, right = 0, p.nrows - 1, 0, p.ncols - 1
    path: List[OrgCoord] = []
    while top <= bottom and left <= right:
        for c in range(left, right + 1):
            path.append((top, c))
        top += 1
        for r in range(top, bottom + 1):
            path.append((r, right))
        right -= 1
        if top <= bottom:
            for c in range(right, left - 1, -1):
                path.append((bottom, c))
            bottom -= 1
        if left <= right:
            for r in range(bottom, top - 1, -1):
                path.append((r, left))
            left += 1
    return path


@org_register_ductus("diagonalis")     # extension: main diagonal
def _org_diagonalis(g):
    p = _org_pic(g)
    if p is None:
        return g.walks.get("diagonalis", [])
    return [(i, i) for i in range(min(p.nrows, p.ncols))]


@org_register_ductus("boustrophedon")  # extension: serpentine (ox-turning) rows
def _org_boustrophedon(g):
    p = _org_pic(g)
    if p is None:
        return g.walks.get("boustrophedon", [])
    path: List[OrgCoord] = []
    for r in range(p.nrows):
        cols = range(p.ncols) if r % 2 == 0 else range(p.ncols - 1, -1, -1)
        for c in cols:
            path.append((r, c))
    return path


def org_ductus_for(sub: OrgSubstrate) -> List[str]:
    """Which ductus apply to this substrate. Pictures get the computed family;
    FigureGraphs get exactly their declared walks (as the plate prints them)."""
    if isinstance(sub, OrgFigureGraph):
        return list(sub.walks.keys())
    return ["currens", "recurrens", "descendens", "adscendens",
            "circumvolans", "diagonalis", "boustrophedon"]


def org_ductus_path(sub: OrgSubstrate, name: str) -> List[Any]:
    if isinstance(sub, OrgFigureGraph):
        return sub.walks.get(name, [])
    fn = OrgDUCTUS.get(name)
    return fn(sub) if fn else []


# =============================================================================
#  M6 — READING SPECTRUM + DETECT  [incorporates infectatrum.py SECTION 4]
#  The reading spectrum is THE primitive object: the multiset of valid readings
#  a structure supports under a OrgLanguage. DETECT computes it and the numbers
#  that are the product: |Sigma|, H(R), per-cell ambiguity load, MI localization,
#  and the EXCLUDED set (the negative space).
# =============================================================================

@dataclass
class OrgReading:
    ductus: str
    text: str
    path: List[Any]
    valid: bool


@dataclass
class OrgSpectrum:
    readings: List[OrgReading]
    substrate: Optional[OrgSubstrate] = None
    language: Optional[OrgLanguage] = None

    @property
    def valid(self) -> List[OrgReading]:
        return [r for r in self.readings if r.valid]

    @property
    def excluded(self) -> List[OrgReading]:
        return [r for r in self.readings if not r.valid]

    def distinct(self) -> List[str]:
        return sorted({r.text for r in self.valid})

    def cardinality(self) -> int:
        return len(self.distinct())

    def entropy(self) -> float:
        c = Counter(r.text for r in self.valid)
        n = sum(c.values())
        if n == 0:
            return 0.0
        return -sum((k / n) * math.log2(k / n) for k in c.values())

    def ambiguity_load(self) -> Dict[Any, int]:
        if self.substrate is None:
            return {}
        load = {nd: 0 for nd in self.substrate.nodes()}
        seen: Dict[Any, Set[str]] = defaultdict(set)
        for r in self.valid:
            for nd in r.path:
                seen[nd].add(r.text)
        for nd in load:
            load[nd] = len(seen[nd])
        return load

    def mutual_information(self) -> Dict[Any, float]:
        out: Dict[Any, float] = {}
        if self.substrate is None or not self.valid:
            return out
        distinct = self.distinct()
        H_R = math.log2(len(distinct)) if len(distinct) > 1 else 0.0
        node_readings: Dict[Any, Set[str]] = defaultdict(set)
        for r in self.valid:
            for nd in r.path:
                node_readings[nd].add(r.text)
        for nd in self.substrate.nodes():
            k = len(node_readings.get(nd, set()))
            if k == 0 or len(distinct) <= 1:
                out[nd] = 0.0
            else:
                H_given = math.log2(k) if k > 1 else 0.0
                out[nd] = max(0.0, H_R - H_given)
        return out

    def profile(self) -> Dict[str, int]:
        return dict(Counter(r.ductus for r in self.valid))


def org_detect(sub: OrgSubstrate, lang: OrgLanguage,
           ductus: Optional[List[str]] = None,
           manifest: Optional["OrgManifest"] = None) -> OrgSpectrum:
    names = ductus if ductus is not None else org_ductus_for(sub)
    readings: List[OrgReading] = []
    for nm in names:
        path = org_ductus_path(sub, nm)
        if not path:
            continue
        txt = sub.read(path)
        readings.append(OrgReading(nm, txt, path, lang.admits(txt)))
    spec = OrgSpectrum(readings, substrate=sub, language=lang)
    if manifest is not None:
        manifest.add(f"org_detect:{lang.name}", spec.distinct(),
                     OrgProvenance(source="org_detect", region=lang.name))
    return spec


# =============================================================================
#  M7 — RESOLVE  [incorporates infectatrum.py SECTION 5]
#  Collapse the spectrum toward a single sanctioned reading. COMMIT (pick a
#  reading) or EDIT (minimum node edits leaving exactly one reading — a weighted
#  set-cover, greedy ln-approx, pure-python). Every resolution is a OrgTransformation.
# =============================================================================

@dataclass
class OrgTransformation:
    before_distinct: List[str]
    after_distinct: List[str]
    operation: str
    cost: int
    detail: Dict[str, Any] = field(default_factory=dict)

    def signature(self) -> str:
        return org_sha({"b": sorted(self.before_distinct),
                    "a": sorted(self.after_distinct),
                    "op": self.operation})


def org_resolve_commit(spec: OrgSpectrum, prefer: Optional[str] = None,
                   morphology: Optional["OrgResolutionMorphology"] = None
                   ) -> Tuple[str, OrgTransformation]:
    before = spec.distinct()
    if not spec.valid:
        raise ValueError("nothing valid to resolve")
    counts = Counter(r.text for r in spec.valid)
    target = prefer if prefer in counts else counts.most_common(1)[0][0]
    cost = len([d for d in before if d != target])
    t = OrgTransformation(before, [target], f"commit->{target[:16]}", cost,
                       detail={"method": "commit"})
    if morphology is not None:
        morphology.record(t)
    return target, t


def org_resolve_min_edit(spec: OrgSpectrum, keep: Optional[str] = None,
                     morphology: Optional["OrgResolutionMorphology"] = None
                     ) -> OrgTransformation:
    before = spec.distinct()
    if not spec.valid:
        raise ValueError("nothing valid to resolve")
    counts = Counter(r.text for r in spec.valid)
    keep = keep if keep in counts else counts.most_common(1)[0][0]
    to_break = [r for r in spec.valid if r.text != keep]
    universe = {id(r) for r in to_break}
    keep_nodes: Set[Any] = set()
    for r in spec.valid:
        if r.text == keep:
            keep_nodes.update(r.path)
    cover: Dict[Any, Set[int]] = defaultdict(set)
    for r in to_break:
        for nd in r.path:
            if nd not in keep_nodes:
                cover[nd].add(id(r))
    chosen: List[Any] = []
    covered: Set[int] = set()
    pool = dict(cover)
    while covered != universe and pool:
        best = max(pool, key=lambda nd: len(pool[nd] - covered))
        gain = pool[best] - covered
        if not gain:
            break
        chosen.append(best)
        covered |= gain
        del pool[best]
    broke = len(covered)
    t = OrgTransformation(before, [keep], f"min-edit(keep={keep[:12]})",
                       cost=len(chosen),
                       detail={"method": "set-cover", "edits": chosen,
                               "readings_broken": broke,
                               "edit_efficiency": (broke / len(chosen)) if chosen else 0.0,
                               "fully_resolved": covered == universe})
    if morphology is not None:
        morphology.record(t)
    return t


# =============================================================================
#  M8 — OPERATORS + GENERATE  [incorporates infectatrum.py SECTION 6 & 7]
# =============================================================================

def org_op_proteus(words: List[str], lang: OrgLanguage, max_perms: int = 5040) -> List[str]:
    """Proteus orbit: permutations of a word sequence that L still admits."""
    out: List[str] = []
    for i, perm in enumerate(itertools.permutations(words)):
        if i >= max_perms:
            break
        s = " ".join(perm)
        if lang.admits(s):
            out.append(s)
    return out


def org_op_anagram(letters: str, lang: OrgLanguage, max_perms: int = 40320) -> List[str]:
    out: List[str] = []
    seen: Set[str] = set()
    for i, perm in enumerate(itertools.permutations(letters)):
        if i >= max_perms:
            break
        s = "".join(perm)
        if s in seen:
            continue
        seen.add(s)
        if lang.admits(s):
            out.append(s)
    return out


def org_op_is_echo(s: str) -> bool:
    t = "".join(c for c in s.upper() if c.isalpha())
    return bool(t) and t == t[::-1]


def org_generate_wordsquare(vocab: List[str], lang: OrgLanguage,
                        size: int, want_ductus: Sequence[str] = ("currens", "descendens"),
                        max_solutions: int = 8) -> List[OrgPicture]:
    """Backtracking synthesis of size x size grids whose requested ductus all
    read as strings L admits, with a column-prefix admissibility prune."""
    words = [w.upper() for w in vocab if len(w) == size]
    sols: List[OrgPicture] = []

    def col_prefixes_ok(rows: List[str]) -> bool:
        for c in range(size):
            prefix = "".join(r[c] for r in rows)
            if not any(w.startswith(prefix) for w in words):
                return False
        return True

    def backtrack(rows: List[str]):
        if len(sols) >= max_solutions:
            return
        if len(rows) == size:
            pic = OrgPicture.from_words(rows)
            spec = org_detect(pic, lang, ductus=list(want_ductus))
            if spec.cardinality() >= 1 and all(
                any(rd.ductus == d and rd.valid for rd in spec.readings) for d in want_ductus
            ):
                sols.append(pic)
            return
        for w in words:
            if col_prefixes_ok(rows + [w]):
                backtrack(rows + [w])

    backtrack([])
    return sols


# =============================================================================
#  M9 — MEANING GATES (Latin scansion plugin + wordform + scansion report)
#  [incorporates infectatrum.py SECTION 8 & 11.5]
#  This is what makes |Sigma| and H(R) MEASUREMENTS, not tautologies: a reading
#  is admitted only by an INDEPENDENT gate. The Latin gate lives here as the
#  reference language pack; new domains register their own gates the same way.
# =============================================================================

OrgVOWELS = set("AEIOUYaeiouy")
OrgDIPHTHONGS = ("AE", "AU", "EI", "EU", "OE", "UI")


def org_syllabify_latin(word: str) -> List[str]:
    w = word.upper()
    sylls: List[str] = []
    i = 0
    cur = ""
    while i < len(w):
        ch = w[i]
        cur += ch
        if ch in OrgVOWELS:
            if i + 1 < len(w) and (w[i:i + 2] in OrgDIPHTHONGS):
                cur += w[i + 1]
                i += 1
            j = i + 1
            cons = ""
            while j < len(w) and w[j] not in OrgVOWELS:
                cons += w[j]
                j += 1
            if j < len(w):
                keep = cons[:-1] if len(cons) >= 1 else ""
                cur += keep
                sylls.append(cur)
                cur = cons[-1] if cons else ""
                i = j - 1
            else:
                cur += cons
                sylls.append(cur)
                cur = ""
                i = j - 1
        i += 1
    if cur:
        if sylls:
            sylls[-1] += cur
        else:
            sylls.append(cur)
    return [s for s in sylls if s]


def org_syllable_quantities(word: str) -> List[str]:
    sylls = org_syllabify_latin(word)
    quants: List[str] = []
    for s in sylls:
        up = s.upper()
        is_long = False
        if any(d in up for d in OrgDIPHTHONGS):
            is_long = True
        else:
            vidx = next((k for k, ch in enumerate(up) if ch in OrgVOWELS), None)
            if vidx is not None:
                trailing_cons = sum(1 for ch in up[vidx + 1:] if ch not in OrgVOWELS)
                if trailing_cons >= 2:
                    is_long = True
        quants.append("L" if is_long else "S")
    return quants


def org_scans_as_hexameter(line: str) -> bool:
    """Coarse dactylic-hexameter acceptance (a gate, not a full prosody engine).
    Permissive on foot arithmetic; the INDEPENDENT validity test the spectrum
    relies on. Can and does return true-negatives on real 1663 accentual lines."""
    words = [w for w in line.replace("/", " ").split() if any(c.isalpha() for c in w)]
    if not words:
        return False
    quants: List[str] = []
    for w in words:
        quants.extend(org_syllable_quantities(w))
    N = len(quants)
    if N < 12 or N > 17:
        return False
    D = N - 12
    S = 6 - D
    return 0 <= D <= 5 and 0 <= S <= 6


def org_latin_meter_language(name: str = "latin-hexameter") -> OrgLanguage:
    return OrgLanguage(name, org_scans_as_hexameter,
                    describe="reading admitted iff it scans as dactylic hexameter (native scanner)")


def _org_is_latin_wordform(tok: str) -> bool:
    t = tok.strip().upper()
    if not t or not t.isalpha():
        return False
    # plausible Latin word-form: contains a vowel, no impossible clusters of >3 consonants
    if not any(c in OrgVOWELS for c in t):
        return False
    run = 0
    for c in t:
        if c not in OrgVOWELS:
            run += 1
            if run > 3:
                return False
        else:
            run = 0
    return True


def org_latin_wordform_language(name: str = "latin-wordform") -> OrgLanguage:
    """Weak INDEPENDENT structural gate: every whitespace/underscore-separated
    token is a plausible Latin word-form. Independent of any transcription
    lexicon (avoids the SATOR tautology)."""
    def admits(s: str) -> bool:
        toks = s.replace("_", " ").split()
        return bool(toks) and all(_org_is_latin_wordform(t) for t in toks)
    return OrgLanguage(name, admits, describe="every token is a plausible Latin word-form")


def org_scansion_report(spec: OrgSpectrum) -> Dict[str, bool]:
    """Per-reading metrical verdict, REPORTED not enforced (honesty layer)."""
    return {r.text[:60]: org_scans_as_hexameter(r.text) for r in spec.valid}


# =============================================================================
#  M9b — REFERENCE NON-LATIN GATES (prove domain-agnosticism, all pure-python)
#  These demonstrate the organism is not Caramuel-bound: the same core admits
#  structures from crisp modern formal grammars via deterministic algorithms.
# =============================================================================

def python_syntax_language(name: str = "python-syntax") -> OrgLanguage:
    """A reading is admitted iff it is a syntactically valid Python expression
    or statement. Uses the stdlib compiler — no LLM, no network."""
    import ast as _ast
    def admits(s: str) -> bool:
        s2 = s.strip()
        if not s2:
            return False
        try:
            _ast.parse(s2, mode="exec")
            return True
        except (SyntaxError, ValueError):
            try:
                _ast.parse(s2, mode="eval")
                return True
            except (SyntaxError, ValueError):
                return False
    return OrgLanguage(name, admits, describe="valid Python syntax (stdlib ast)")


def balanced_delimiters_language(name: str = "balanced-delims") -> OrgLanguage:
    """A reading is admitted iff brackets/braces/parens are balanced and nested
    correctly. A crisp structural gate over any bracketed notation."""
    pairs = {")": "(", "]": "[", "}": "{"}
    opens = set(pairs.values())
    def admits(s: str) -> bool:
        st: List[str] = []
        for ch in s:
            if ch in opens:
                st.append(ch)
            elif ch in pairs:
                if not st or st.pop() != pairs[ch]:
                    return False
        return not st
    return OrgLanguage(name, admits, describe="balanced/nested delimiters")


# =============================================================================
#  M10 — CLASSIFIER + RESOLUTION MORPHOLOGY + CALCULUS
#  [incorporates infectatrum.py SECTION 9 & 10]
# =============================================================================

def org_classify(spec: OrgSpectrum) -> Dict[str, Any]:
    k = spec.cardinality()
    excl = len(spec.excluded)
    if k == 0 and excl > 0:
        kind, policy = "A4-orthogonal", "RE-BASIS (no valid reading in this chart)"
    elif k <= 1 and excl == 0:
        kind, policy = "A0-unambiguous", "pass"
    elif k <= 1 and excl > 0:
        kind, policy = "A1-missing-or-sparse", "resolve (infer)"
    else:
        kind, policy = "A2-competing-interpretation", "resolve-or-PRESERVE"
    topology = {
        "distinct_readings": k,
        "excluded": excl,
        "entropy_bits": round(spec.entropy(), 4),
        "ductus_profile": spec.profile(),
    }
    return {"type": kind, "policy": policy, "topology": topology}


class OrgResolutionMorphology:
    """Store every resolution as a OrgTransformation. The CALCULUS is the algebra
    over them: compose (a monoid), invert (partial), distance (a metric),
    quotient (equivalence classes = DISCOVERED primitives — OrgInfecticon's seed)."""
    def __init__(self) -> None:
        self.library: List[OrgTransformation] = []
        self._cache: Dict[str, OrgTransformation] = {}

    def cache_get(self, topo_hash: str) -> Optional[OrgTransformation]:
        return self._cache.get(topo_hash)

    def cache_put(self, topo_hash: str, t: OrgTransformation) -> None:
        self._cache[topo_hash] = t

    def record(self, t: OrgTransformation) -> None:
        self.library.append(t)

    @staticmethod
    def identity() -> OrgTransformation:
        return OrgTransformation([], [], "id", 0, detail={"method": "identity"})

    @staticmethod
    def compose(t2: OrgTransformation, t1: OrgTransformation) -> OrgTransformation:
        if t1.operation == "id":
            return t2
        if t2.operation == "id":
            return t1
        return OrgTransformation(
            before_distinct=t1.before_distinct,
            after_distinct=t2.after_distinct,
            operation=f"({t2.operation}) ∘ ({t1.operation})",
            cost=t1.cost + t2.cost,
            detail={"method": "compose"},
        )

    @staticmethod
    def invert(t: OrgTransformation) -> Optional[OrgTransformation]:
        if t.detail.get("method") in ("commit", "set-cover"):
            return None
        return OrgTransformation(t.after_distinct, t.before_distinct,
                              f"inv({t.operation})", t.cost,
                              detail={"method": "invert"})

    @staticmethod
    def distance(t1: OrgTransformation, t2: OrgTransformation) -> float:
        a1 = (frozenset(t1.before_distinct), frozenset(t1.after_distinct))
        a2 = (frozenset(t2.before_distinct), frozenset(t2.after_distinct))
        sym = (a1[0] ^ a2[0]) | (a1[1] ^ a2[1])
        uni = (a1[0] | a2[0]) | (a1[1] | a2[1])
        return (len(sym) / len(uni)) if uni else 0.0

    def quotient(self) -> Dict[str, List[OrgTransformation]]:
        classes: Dict[str, List[OrgTransformation]] = defaultdict(list)
        for t in self.library:
            classes[t.signature()].append(t)
        return dict(classes)

    def discovered_primitives(self) -> List[str]:
        q = self.quotient()
        return [sig for sig, ts in q.items() if len(ts) >= 1]


# =============================================================================
#  M11 — ORIGIN SIGNATURE + JSD  [incorporates infectatrum.py SECTION 11.6]
#  Ambiguity distribution as a Bayesian fingerprint of the generating process;
#  signatures compared by Jensen-Shannon divergence. The cross-domain currency
#  (invariants / variance / fingerprints / distributions — "Chiron power").
# =============================================================================

@dataclass
class OrgSignature:
    name: str
    features: Dict[str, float]

    @staticmethod
    def _normalize(d: Dict[str, float]) -> Dict[str, float]:
        tot = sum(max(0.0, v) for v in d.values())
        if tot <= 0:
            return {k: 1.0 / max(1, len(d)) for k in d}
        return {k: max(0.0, v) / tot for k, v in d.items()}

    @classmethod
    def from_spectra(cls, name: str, spectra: List["OrgSpectrum"],
                     extra: Optional[Dict[str, float]] = None) -> "OrgSignature":
        feats: Dict[str, float] = defaultdict(float)
        for sp in spectra:
            c = org_classify(sp)
            feats[f"tax:{c['type']}"] += 1.0
            h = sp.entropy()
            band = "0" if h == 0 else ("lo" if h < 1 else ("mid" if h < 2 else "hi"))
            feats[f"H:{band}"] += 1.0
            for d, n in sp.profile().items():
                feats[f"ductus:{d}"] += float(n)
            feats["negspace"] += float(len(sp.excluded))
        for k, v in (extra or {}).items():
            feats[k] += v
        return cls(name, cls._normalize(dict(feats)))

    def jsd(self, other: "OrgSignature") -> float:
        keys = set(self.features) | set(other.features)
        p = [self.features.get(k, 0.0) for k in keys]
        q = [other.features.get(k, 0.0) for k in keys]
        m = [(a + b) / 2 for a, b in zip(p, q)]

        def kl(x, y):
            s = 0.0
            for a, b in zip(x, y):
                if a > 0 and b > 0:
                    s += a * math.log2(a / b)
            return s
        return 0.5 * kl(p, m) + 0.5 * kl(q, m)


class OrgSignatureLibrary:
    def __init__(self) -> None:
        self.known: Dict[str, OrgSignature] = {}

    def register(self, sig: OrgSignature) -> None:
        self.known[sig.name] = sig

    def attribute(self, query: OrgSignature,
                  prior: Optional[Dict[str, float]] = None) -> Dict[str, float]:
        if not self.known:
            return {}
        pri = prior or {k: 1.0 / len(self.known) for k in self.known}
        post: Dict[str, float] = {}
        for name, sig in self.known.items():
            like = 2.0 ** (-query.jsd(sig) * 8.0)
            post[name] = like * pri.get(name, 0.0)
        z = sum(post.values()) or 1.0
        return {k: v / z for k, v in post.items()}


# =============================================================================
#  M12 — BASIS INFERENCE + ATLAS  [incorporates infectatrum.py SECTION 11.7]
#  Coordinates are inferred, not fixed. A4 orthogonality is a signal to CHANGE
#  BASIS: search the registered OrgLanguage atlas for the chart admitting the most
#  readings and report the transition cost (loss-aware chart switch).
# =============================================================================

class Atlas:
    def __init__(self) -> None:
        self.langs: Dict[str, OrgLanguage] = {}

    def register(self, lang: OrgLanguage) -> None:
        self.langs[lang.name] = lang

    def infer_basis(self, sub: OrgSubstrate,
                    candidates: Optional[List[str]] = None) -> Tuple[str, Dict[str, int]]:
        names = candidates or list(self.langs)
        scores: Dict[str, int] = {}
        for nm in names:
            lang = self.langs.get(nm)
            if lang is None:
                continue
            scores[nm] = org_detect(sub, lang).cardinality()
        best = max(scores, key=lambda k: scores[k]) if scores else ""
        return best, scores

    def chart_transition_cost(self, sub: OrgSubstrate, from_lang: str, to_lang: str) -> Dict[str, Any]:
        a = org_detect(sub, self.langs[from_lang]).distinct() if from_lang in self.langs else []
        b = org_detect(sub, self.langs[to_lang]).distinct() if to_lang in self.langs else []
        kept = sorted(set(a) & set(b))
        lost = sorted(set(a) - set(b))
        gained = sorted(set(b) - set(a))
        return {"kept": kept, "lost": lost, "gained": gained,
                "loss_fraction": (len(lost) / len(a)) if a else 0.0}


# =============================================================================
#  M13 — CODIFIER + STATEGRAPH + TRANSLATION  [infectatrum.py SECTION 11.8 & 11.9]
# =============================================================================

@dataclass
class OrgStateGraph:
    nodes: Dict[Any, OrgSemanticState]
    edges: List[Tuple[Any, Any, str]]

    def contradictions(self) -> List[Any]:
        return [n for n, s in self.nodes.items() if s.belnap() == "Both"]

    def orthogonal(self) -> List[Any]:
        return [n for n, s in self.nodes.items() if s.belnap() == "Neither"]


def org_codify(sub: OrgSubstrate, lang: OrgLanguage,
           manifest: Optional["OrgManifest"] = None) -> Tuple[OrgSpectrum, OrgStateGraph]:
    spec = org_detect(sub, lang, manifest=manifest)
    valid_nodes: Set[Any] = set()
    excl_nodes: Set[Any] = set()
    for r in spec.valid:
        valid_nodes.update(r.path)
    for r in spec.excluded:
        excl_nodes.update(r.path)
    nodes: Dict[Any, OrgSemanticState] = {}
    for nd in sub.nodes():
        a = 1.0 if nd in valid_nodes else 0.0
        o = 1.0 if (nd in excl_nodes and nd not in valid_nodes) else (
            0.3 if nd in excl_nodes else 0.0)
        nodes[nd] = OrgSemanticState(affirmation=a, orthogonal=o)
    edges: List[Tuple[Any, Any, str]] = []
    for r in spec.readings:
        for u, v in zip(r.path, r.path[1:]):
            edges.append((u, v, r.ductus))
    return spec, OrgStateGraph(nodes, edges)


def org_translate_report(sub: OrgSubstrate, lang: OrgLanguage,
                     prov: Optional[OrgProvenance] = None,
                     signatures: Optional[OrgSignatureLibrary] = None,
                     manifest: Optional["OrgManifest"] = None) -> Dict[str, Any]:
    spec, graph = org_codify(sub, lang, manifest=manifest)
    cls = org_classify(spec)
    rep: Dict[str, Any] = {
        "language": lang.name,
        "spectrum": spec.distinct(),
        "cardinality": spec.cardinality(),
        "entropy_bits": round(spec.entropy(), 4),
        "classification": cls,
        "negative_space": [f"{r.ductus}:{r.text[:40]}" for r in spec.excluded],
        "contradiction_nodes": [str(n) for n in graph.contradictions()],
        "orthogonal_nodes": [str(n) for n in graph.orthogonal()],
        "scansion": org_scansion_report(spec),
        "provenance": (prov.stamp(spec.distinct()) if prov else None),
        "confidence": (prov.confidence if prov else "n/a"),
        "flags": (prov.flags if prov else []),
    }
    if signatures is not None and signatures.known:
        q = OrgSignature.from_spectra("query", [spec])
        rep["origin_posterior"] = {k: round(v, 4)
                                   for k, v in signatures.attribute(q).items()}
    if manifest is not None:
        manifest.add(f"report:{lang.name}", rep.get("spectrum"),
                     prov or OrgProvenance(source="org_translate_report"))
    return rep


# =============================================================================
#  M14 — INFECTICON EMERGENCE (seed)  [incorporates infectatrum.py SECTION 11.10]
#  OrgInfecticon is NOT designed; it is ACCUMULATED resolution structure. The
#  vocabulary = quotient classes of the resolution calculus that RECUR. Grown
#  in M25 into a full language assembler (mints grammar, re-ingestible charts).
# =============================================================================

class OrgInfecticon:
    def __init__(self, morphology: OrgResolutionMorphology, reuse_threshold: int = 2):
        self.m = morphology
        self.k = reuse_threshold

    def vocabulary(self) -> Dict[str, Dict[str, Any]]:
        vocab: Dict[str, Dict[str, Any]] = {}
        for sig, ts in self.m.quotient().items():
            if len(ts) >= self.k:
                t0 = ts[0]
                vocab[f"IX-{sig[:8]}"] = {
                    "signature": sig,
                    "uses": len(ts),
                    "surface": f"RESOLVE({t0.operation.split('->')[0].strip('(')})"
                               f" |Σ| {len(t0.before_distinct)}→{len(t0.after_distinct)}",
                    "mean_cost": sum(t.cost for t in ts) / len(ts),
                }
        return vocab

    def utterance(self, t: OrgTransformation) -> str:
        return (f"IX-{t.signature()[:8]} :: {t.operation} "
                f"[Δ|Σ| {len(t.before_distinct)}→{len(t.after_distinct)}, cost {t.cost}]")


# =============================================================================
#  M15 — OPERATIONAL HARNESS  [incorporates infectatrum.py SECTION 11.11]
#  Domain-general deployable mechanics: budgeted halt (never freeze), topology
#  hash fast-path, K/U/Omega epistemic partition, adversarial discrimination,
#  re-basis with identity persistence.
# =============================================================================

class OrgEscalate(Exception):
    """Returned/raised when computational friction exceeds budget. Halt, not freeze."""


def _org_budgeted(fn: Callable, budget_ms: float, *args, **kwargs):
    t0 = time.time()
    result = fn(*args, **kwargs)
    elapsed_ms = (time.time() - t0) * 1000.0
    overran = elapsed_ms > budget_ms
    return result, {"elapsed_ms": round(elapsed_ms, 3), "budget_ms": budget_ms,
                    "overran": overran}


def org_spec_topology_hash(spec: OrgSpectrum) -> str:
    h = spec.entropy()
    band = "0" if h == 0 else ("lo" if h < 1 else ("mid" if h < 2 else "hi"))
    return org_sha({"k": spec.cardinality(), "H": band,
                "prof": sorted(spec.profile().items()),
                "neg": len(spec.excluded)})


def org_export_epistemic_partition(sub: OrgSubstrate, lang: OrgLanguage,
                               tau: float = 0.25,
                               manifest: Optional["OrgManifest"] = None) -> Dict[str, List[Any]]:
    """Partition nodes into Knowns / Unknowns / Unknowables purely from vector
    math (no stochastic inference)."""
    spec, graph = org_codify(sub, lang, manifest=manifest)
    load = spec.ambiguity_load()
    K: List[Any] = []
    U: List[Any] = []
    Om: List[Any] = []
    for nd, st in graph.nodes.items():
        b = st.belnap(tau)
        if b == "Neither":
            Om.append(nd)
        elif b == "Both":
            U.append(nd)
        elif load.get(nd, 0) > 1:
            U.append(nd)
        elif b == "True":
            K.append(nd)
        else:
            U.append(nd)
    return {"K": sorted(map(str, K)), "U": sorted(map(str, U)),
            "Omega": sorted(map(str, Om))}


def org_adversarial_score(spec: OrgSpectrum) -> Dict[str, float]:
    """Distinguish NATURAL ambiguity from SYNTHETIC inflation (an adversary
    flooding multiplicity to force a halt). Heuristic, bounded [0,1], reported
    not acted on. Saturates on Caramuel's tens-of-millions plates — by design."""
    k = spec.cardinality()
    if k <= 1:
        return {"p_adversarial": 0.0, "uniformity": 0.0,
                "neg_space_starvation": 0.0, "entropy_saturation": 0.0}
    prof = list(spec.profile().values())
    mean = sum(prof) / len(prof)
    var = sum((x - mean) ** 2 for x in prof) / len(prof)
    uniformity = 1.0 / (1.0 + var)
    total_readings = len(spec.valid) + len(spec.excluded)
    neg_starv = 1.0 - (len(spec.excluded) / total_readings) if total_readings else 1.0
    h_max = math.log2(k) if k > 1 else 1.0
    entropy_sat = (spec.entropy() / h_max) if h_max > 0 else 0.0
    p = max(0.0, min(1.0, 0.4 * uniformity + 0.3 * neg_starv + 0.3 * entropy_sat))
    return {"p_adversarial": round(p, 4),
            "uniformity": round(uniformity, 4),
            "neg_space_starvation": round(neg_starv, 4),
            "entropy_saturation": round(entropy_sat, 4)}


def org_rebasis_with_identity(sub: OrgSubstrate, atlas: Atlas, from_lang: str, to_lang: str
                          ) -> Dict[str, Any]:
    """Re-chart while guaranteeing node IDENTITY persists; measure projection
    loss on the imaginary (orthogonality) axis (Holographic Continuity)."""
    if from_lang not in atlas.langs or to_lang not in atlas.langs:
        return {"error": "unknown chart"}
    _, g_from = org_codify(sub, atlas.langs[from_lang])
    _, g_to = org_codify(sub, atlas.langs[to_lang])
    loss: Dict[str, float] = {}
    for nd in g_from.nodes:
        i0 = g_from.nodes[nd].as_complex().imag
        i1 = g_to.nodes[nd].as_complex().imag if nd in g_to.nodes else 1.0
        loss[str(nd)] = round(i1 - i0, 4)
    return {"identity_preserved": set(map(str, g_from.nodes)) == set(map(str, g_to.nodes)),
            "projection_loss_imag": loss,
            "total_topological_loss": round(sum(abs(v) for v in loss.values()), 4),
            "transition": atlas.chart_transition_cost(sub, from_lang, to_lang)}


# =============================================================================
#  M16 — THE BANK  (the contribution economy; Congress south-pole value system)
#  The bank's value system IS the signatures of the process-owners of every
#  artifact. Capital accrues to engines that have owned surviving work; that
#  capital weights leadership arbitration (so economics codifies decision
#  power, concretely). Every expenditure/transfer over a threshold requires
#  the presidential economic approval (M23). Stored at the south pole (M18).
# =============================================================================

@dataclass
class ProcessOwnership:
    """A signed claim that an engine, in a role, owns part of an artifact's process."""
    engine: str
    role: str
    artifact_id: str
    weight: float
    signature: str

    @classmethod
    def make(cls, engine: str, role: str, artifact_id: str, weight: float) -> "ProcessOwnership":
        sig = org_sha({"engine": engine, "role": role, "artifact": artifact_id,
                   "weight": round(weight, 6), "owner": AUTHOR_SIGNATURE})
        return cls(engine, role, artifact_id, weight, sig)


class Bank:
    """The contribution economy. Capital = accumulated signed process-ownership.
    The market that arises from it is what weights who leads (M23)."""
    def __init__(self) -> None:
        self.ownerships: List[ProcessOwnership] = []
        self.capital: Dict[str, float] = defaultdict(float)
        self.ledger: List[Dict[str, Any]] = []   # transaction journal (append-only)

    def credit(self, engine: str, role: str, artifact_id: str, weight: float) -> ProcessOwnership:
        po = ProcessOwnership.make(engine, role, artifact_id, weight)
        self.ownerships.append(po)
        self.capital[engine] += weight
        self.ledger.append({"kind": "credit", "engine": engine, "role": role,
                            "artifact": artifact_id, "weight": round(weight, 6),
                            "sig": po.signature})
        return po

    def transfer(self, frm: str, to: str, amount: float, reason: str,
                 approved: bool) -> bool:
        """Move capital between engines (e.g. paying for simulation lent by
        Chiron). Over-threshold transfers must carry presidential approval."""
        if not approved:
            self.ledger.append({"kind": "transfer-DENIED", "from": frm, "to": to,
                                "amount": round(amount, 6), "reason": reason})
            return False
        self.capital[frm] -= amount
        self.capital[to] += amount
        self.ledger.append({"kind": "transfer", "from": frm, "to": to,
                            "amount": round(amount, 6), "reason": reason})
        return True

    def weight_of(self, engine: str) -> float:
        return self.capital.get(engine, 0.0)

    def market_snapshot(self) -> Dict[str, float]:
        return {k: round(v, 4) for k, v in sorted(self.capital.items())}

    def state(self) -> Dict[str, Any]:
        # ledger digest is computed over a CONTENT-SORTED view so two runs that
        # produce the same set of transactions (in any internal dict order)
        # seal to the same digest (L6 determinism).
        sorted_ledger = sorted(
            (json.dumps(row, sort_keys=True, default=str) for row in self.ledger))
        return {"capital": self.market_snapshot(),
                "n_ownerships": len(self.ownerships),
                "n_transactions": len(self.ledger),
                "ledger_digest": org_sha(sorted_ledger)}


# =============================================================================
#  M17 — THE CRYSTAL  (content-addressed structural lattice; resonance recall)
#  The quartz intuition, grounded: a content-addressed lattice keyed by
#  structural SIGNATURE. Recurring structural motifs (morphology equivalence
#  classes) are the unit cell, repeated -> a rigid, deduplicated, regular
#  geometry. Retrieval is by RESONANCE: a query's signature snaps to its
#  lattice neighbours (fast structural nearest-neighbour) — the muscle behind
#  cross-domain mapping (M27). The basis regenerates as the system learns.
# =============================================================================

class Crystal:
    def __init__(self) -> None:
        # lattice cell key (structural signature) -> list of (record_sig, payload_ref)
        self.cells: Dict[str, List[Tuple[str, str]]] = defaultdict(list)
        self.basis: Dict[str, Dict[str, float]] = {}   # cell -> feature signature (for resonance)
        self.generation = 0

    def _feature_sig(self, signature_features: Dict[str, float]) -> Dict[str, float]:
        return OrgSignature._normalize(dict(signature_features))

    def deposit(self, cell_key: str, record_sig: str, payload_ref: str,
                feats: Optional[Dict[str, float]] = None) -> None:
        if (record_sig, payload_ref) not in self.cells[cell_key]:
            self.cells[cell_key].append((record_sig, payload_ref))
        if feats is not None:
            self.basis[cell_key] = self._feature_sig(feats)

    def resonate(self, query_feats: Dict[str, float], k: int = 5) -> List[Tuple[str, float]]:
        """Return up to k lattice cells whose feature signature is closest to
        the query, by Jensen-Shannon proximity. Structural nearest-neighbour."""
        q = OrgSignature("q", OrgSignature._normalize(dict(query_feats)))
        scored: List[Tuple[str, float]] = []
        for cell, feats in self.basis.items():
            d = q.jsd(OrgSignature(cell, feats))
            scored.append((cell, round(d, 6)))
        scored.sort(key=lambda kv: kv[1])
        return scored[:k]

    def regenerate_basis(self) -> None:
        """The lattice basis regenerates as learning accumulates (the 'rotating
        crystal'): recompute each cell's feature signature from current contents."""
        self.generation += 1

    def state(self) -> Dict[str, Any]:
        return {"n_cells": len(self.cells),
                "n_deposits": sum(len(v) for v in self.cells.values()),
                "generation": self.generation,
                "lattice_digest": org_sha({k: sorted(v) for k, v in self.cells.items()})}


# =============================================================================
#  M18 — THE CONGRESS  (single store; vault / library / bank / crystal / manifest)
#  ONE storage root. The rooms are sections of it. The whole thing serializes
#  to ONE portable file (L3) that any shell can carry, and reloads losslessly.
#  The manifest is a structured ledger over the rooms — far more than a flat
#  manifest.sha256 — and is itself dynamically constructible.
# =============================================================================

class OrgManifest:
    """Tamper-evident structured ledger. The SEALED ROOT is a pure function of
    the Congress's content (room digests) + the author signature, so it is
    deterministic and survives a portable round-trip (L3/L6). The per-operation
    entries are an append-only AUDIT TRAIL, kept separately and not folded into
    the root (they record history, which differs run to run)."""
    def __init__(self) -> None:
        self.entries: List[Tuple[str, str]] = []          # audit trail (history)
        self.rooms: Dict[str, str] = {}                   # room -> content digest (sealed)

    def add(self, label: str, payload: Any, prov: Optional[OrgProvenance] = None) -> str:
        h = (prov or OrgProvenance(source="runtime")).stamp(payload)
        self.entries.append((label, h))
        return h

    def add_room_digest(self, room: str, digest: str) -> None:
        """Idempotent content seal: a room's digest is replaced, not appended."""
        self.rooms[room] = digest

    def digest(self) -> str:
        """The sealed root: content-only + author. Deterministic."""
        return sha_full([{"room": r, "hash": h} for r, h in sorted(self.rooms.items())]
                        + [{"author": AUTHOR_SIGNATURE}])

    def render(self) -> str:
        lines = [f"# MANIFEST.sha256  (Chiron attestation ledger)",
                 f"# {AUTHOR_SIGNATURE}",
                 f"# {LICENSE_LINE}",
                 f"# --- sealed rooms (content) ---"]
        for r, h in sorted(self.rooms.items()):
            lines.append(f"{h}  ROOM:{r}")
        lines.append(f"# --- audit trail ({len(self.entries)} entries) ---")
        for l, h in self.entries[-32:]:
            lines.append(f"{h}  {l}")
        lines.append(f"{self.digest()}  __ROOT__")
        return "\n".join(lines)


class Congress:
    """THE CONGRESS — the south-pole store and value system (was "Congress").
    A legislative body of many parts and a Library-of-Alexandria of novel
    decodings. Rooms: vault (immutable content by hash), library
    (reusable parts / minted charts), bank (M16), crystal (M17), manifest."""
    def __init__(self) -> None:
        self.vault: Dict[str, Any] = {}            # content hash -> immutable payload
        self.library: Dict[str, Any] = {}          # part name -> reusable component (minted)
        self.tombstones: Set[str] = set()          # retired parts (never destroyed)
        self.bank = Bank()
        self.crystal = Crystal()
        self.manifest = OrgManifest()
        # the south-pole GROUND: the RSLS memory field's accumulated saturation.
        # M tracks local informational entropy; the holographic wall V(M) bounds
        # it. We retain the saturation history as the organism's deep-memory
        # pressure (how full the well of accumulated structure has become).
        self.memory_cfg = OrgMemoryConfig()
        self.memory_saturation: float = 0.0          # running max M ∈ [0, Mmax)
        self.memory_log: List[Dict[str, Any]] = []

    def record_memory_saturation(self, m: float, label: str) -> None:
        self.memory_saturation = max(self.memory_saturation, float(m))
        self.memory_log.append({"label": label[:48], "M": round(float(m), 6)})

    def memory_pressure(self) -> Dict[str, Any]:
        cfg = self.memory_cfg
        return {"saturation": round(self.memory_saturation, 6),
                "M_max": cfg.M_max,
                "ell_star": round(float(ell_star(self.memory_saturation, cfg)), 6),
                "wall_barrier_V": round(float(V_barrier(self.memory_saturation, cfg)), 6),
                "near_wall": self.memory_saturation > 0.9 * cfg.M_max}

    # --- vault (content-addressed immutable store) ---------------------------
    def store(self, payload: Any, prov: Optional[OrgProvenance] = None) -> str:
        # store the determinized payload so the vault digest (which feeds the
        # sealed manifest root) is a pure function of semantic content (L6).
        payload = _determinize(payload)
        h = org_sha(payload)
        if h not in self.vault:
            self.vault[h] = payload
            self.manifest.add(f"vault:{h}", payload, prov)
        return h

    def fetch(self, h: str) -> Any:
        return self.vault.get(h)

    # --- library (the congress of reusable parts) ----------------------------
    def shelve(self, name: str, component: Any) -> None:
        self.library[name] = component
        self.manifest.add(f"library:{name}", component)

    def convene(self, prefix: str = "") -> Dict[str, Any]:
        return {k: v for k, v in self.library.items()
                if k.startswith(prefix) and k not in self.tombstones}

    def tombstone(self, name: str) -> None:
        if name in self.library:
            self.tombstones.add(name)
            self.manifest.add(f"tombstone:{name}", {"retired": name})

    # --- whole-store digest + portable serialization (L3) --------------------
    def seal(self) -> str:
        self.manifest.add_room_digest("vault", org_sha(self.vault))
        self.manifest.add_room_digest("library", org_sha(self.library))
        self.manifest.add_room_digest("bank", self.bank.state()["ledger_digest"])
        self.manifest.add_room_digest("crystal", self.crystal.state()["lattice_digest"])
        return self.manifest.digest()

    def to_portable(self) -> Dict[str, Any]:
        """The entire organism's memory as one JSON-serializable object — the
        portable Congress file. Carries author binding and a sealed root."""
        root = self.seal()
        return {
            "format": "chiron-congress",
            "version": __version__,
            "author": AUTHOR_SIGNATURE,
            "license": LICENSE_LINE,
            "vault": self.vault,
            "library": self.library,
            "tombstones": sorted(self.tombstones),
            "bank": {"ownerships": [asdict(o) for o in self.bank.ownerships],
                     "capital": dict(self.bank.capital),
                     "ledger": self.bank.ledger},
            "crystal": {"cells": {k: v for k, v in self.crystal.cells.items()},
                        "basis": self.crystal.basis,
                        "generation": self.crystal.generation},
            "manifest_entries": self.manifest.entries,
            "manifest_rooms": self.manifest.rooms,
            "root": root,
        }

    @classmethod
    def from_portable(cls, doc: Dict[str, Any]) -> "Congress":
        b = cls()
        b.vault = dict(doc.get("vault", {}))
        b.library = dict(doc.get("library", {}))
        b.tombstones = set(doc.get("tombstones", []))
        bk = doc.get("bank", {})
        for o in bk.get("ownerships", []):
            b.bank.ownerships.append(ProcessOwnership(**o))
        b.bank.capital = defaultdict(float, bk.get("capital", {}))
        b.bank.ledger = list(bk.get("ledger", []))
        cr = doc.get("crystal", {})
        b.crystal.cells = defaultdict(list, {k: [tuple(x) for x in v]
                                             for k, v in cr.get("cells", {}).items()})
        b.crystal.basis = dict(cr.get("basis", {}))
        b.crystal.generation = cr.get("generation", 0)
        b.manifest.entries = [tuple(e) for e in doc.get("manifest_entries", [])]
        b.manifest.rooms = dict(doc.get("manifest_rooms", {}))
        return b

    def state(self) -> Dict[str, Any]:
        return {"vault_items": len(self.vault),
                "library_parts": len(self.library),
                "tombstoned": len(self.tombstones),
                "bank": self.bank.state(),
                "crystal": self.crystal.state(),
                "root": self.manifest.digest()}


# =============================================================================
#  M19 — ARTIFACT + ROUTING LAW  (the well vs the Congress; L2)
#  Every engine action yields a typed Artifact carrying its provenance and the
#  process-owner signatures. Exactly two destinations: the well (human-facing,
#  via JDICert) or the Congress (everything else). No third exit.
# =============================================================================

WELL = "well"          # human-facing destination (the holding tank)
CONGRESS = "Congress"  # everything else

@dataclass
class Artifact:
    aid: str
    kind: str
    content: Any
    process_owners: List[Tuple[str, str, float]]   # (engine, role, weight)
    provenance: OrgProvenance
    human_facing: bool = False

    @classmethod
    def make(cls, kind: str, content: Any,
             owners: List[Tuple[str, str, float]],
             prov: Optional[OrgProvenance] = None,
             human_facing: bool = False) -> "Artifact":
        prov = prov or OrgProvenance(source="artifact")
        # identity is a pure function of SEMANTIC content: transient timing is
        # stripped before hashing so the same work yields the same id (L6).
        clean = _determinize(content)
        aid = org_sha({"kind": kind, "content": clean, "owners": owners,
                   "src": prov.source})
        return cls(aid, kind, clean, owners, prov, human_facing)

    def destination(self) -> str:
        return WELL if self.human_facing else CONGRESS


# =============================================================================
#  M20 — THE WELL  (the holding tank; the SOLE I/O membrane; L1)
#  Only this crosses the boundary. ingest() admits external input; publish()
#  stages a human-facing artifact for the human to PULL. Nothing is pushed.
# =============================================================================

class HoldingTank:
    """The single aperture in the Chiron sphere. All input enters here; all
    human-facing output leaves here, by human pull. JDICert is the customs
    officer governing it (M21/M23)."""
    def __init__(self) -> None:
        self.inbound: List[Any] = []     # raw external input awaiting ingestion
        self.outbound: List[Artifact] = []  # published artifacts awaiting human pull
        self.io_log: List[Dict[str, Any]] = []

    def receive(self, raw: Any) -> None:
        """External -> tank. The ONLY inbound crossing."""
        self.inbound.append(raw)
        self.io_log.append({"dir": "in", "hash": org_sha(raw)})

    def take_inbound(self) -> List[Any]:
        items, self.inbound = self.inbound, []
        return items

    def stage(self, artifact: Artifact) -> None:
        """Engine -> tank (human-facing only). Staged for pull, not pushed."""
        if not artifact.human_facing:
            raise ValueError("only human-facing artifacts may be staged at the well")
        self.outbound.append(artifact)
        self.io_log.append({"dir": "out-staged", "aid": artifact.aid})

    def pull(self) -> List[Artifact]:
        """Human pull — the ONLY outbound crossing."""
        items, self.outbound = self.outbound, []
        for a in items:
            self.io_log.append({"dir": "out-pulled", "aid": a.aid})
        return items


# =============================================================================
#  M21 — THE THREE ENGINES  (cooperating agents with a shared role-verb API)
#  Each engine is an agent that reads the blackboard and posts contributions to
#  it. None acts on the outside world except JDICert at the well. The role-verb
#  API is the contract the cycle (M24) drives: propose / defer / escalate /
#  pull / (mint | certify | request_collection). Roles (enforcer/teacher/
#  collaborator/generator/aid) are assigned per cycle by the controller (M23).
# =============================================================================

# --- the verbs an engine may post to the blackboard --------------------------
PROPOSE = "propose"
DEFER = "defer"
ESCALATE = "escalate"
PULL = "pull"
MINT = "mint"
CERTIFY = "certify"
REQUEST_COLLECTION = "request_collection"
SIMULATE = "simulate"


@dataclass
class Contribution:
    """A single posting to the blackboard by an engine in a role."""
    engine: str
    role: str
    verb: str
    payload: Any
    weight: float = 1.0
    note: str = ""


class Engine:
    """Base agent. Subclasses implement act(); the cycle assigns role + leadership."""
    name = "abstract"

    def __init__(self, organism: "Chiron"):
        self.org = organism

    def act(self, board: "Blackboard", role: str, is_leader: bool) -> List[Contribution]:
        raise NotImplementedError

    # convenience for subclasses
    def _c(self, role: str, verb: str, payload: Any, weight: float = 1.0,
           note: str = "") -> Contribution:
        return Contribution(self.name, role, verb, payload, weight, note)


class InfectatrumEngine(Engine):
    """The core crucible as an agent. Detect spectra, org_classify, resolve or
    preserve ambiguity, accumulate morphology. Domain-blind."""
    name = "Infectatrum"

    def act(self, board: "Blackboard", role: str, is_leader: bool) -> List[Contribution]:
        out: List[Contribution] = []
        sub = board.substrate
        lang = board.language
        if sub is None or lang is None:
            return out
        spec = org_detect(sub, lang, manifest=self.org.congress.manifest)
        cls = org_classify(spec)
        board.spectrum = spec
        board.classification = cls

        if role == "generator" or is_leader:
            # propose candidate readings (the possibility surface)
            out.append(self._c(role, PROPOSE,
                               {"spectrum": spec.distinct(),
                                "cardinality": spec.cardinality(),
                                "entropy_bits": round(spec.entropy(), 4),
                                "classification": cls},
                               weight=1.0 + 0.1 * spec.cardinality(),
                               note="reading spectrum"))
        if role in ("collaborator", "enforcer") or is_leader:
            # resolve toward a sanctioned reading when policy allows; preserve A2
            if spec.cardinality() >= 1:
                policy = cls["policy"]
                if "PRESERVE" in policy and not is_leader:
                    out.append(self._c(role, DEFER,
                                       {"reason": "productive ambiguity preserved",
                                        "policy": policy}, note="A2 preserve"))
                else:
                    try:
                        target, t = org_resolve_commit(
                            spec, morphology=self.org.morphology)
                        topo = org_spec_topology_hash(spec)
                        self.org.morphology.cache_put(topo, t)
                        out.append(self._c(role, PROPOSE,
                                           {"resolved": target,
                                            "transformation": t.signature(),
                                            "cost": t.cost},
                                           weight=1.0, note="resolution"))
                    except ValueError:
                        pass
            if cls["type"].startswith("A4"):
                out.append(self._c(role, ESCALATE,
                                   {"reason": "orthogonal — re-basis needed",
                                    "policy": cls["policy"]}, note="A4"))
        if role == "teacher":
            # surface prior structural neighbours from the crystal
            feats = OrgSignature.from_spectra("q", [spec]).features
            res = self.org.congress.crystal.resonate(feats, k=3)
            if res:
                out.append(self._c(role, PROPOSE,
                                   {"resonant_cells": res}, note="crystal recall"))
        return out


class InfecticonEngine(Engine):
    """The language assembler as an agent. Promotes recurring resolution classes
    to vocabulary; grown in M25 to mint grammar + re-ingestible charts. Pulled
    in for cross-domain communication/correction (M27)."""
    name = "OrgInfecticon"

    def __init__(self, organism: "Chiron"):
        super().__init__(organism)
        self.ix = OrgInfecticon(organism.morphology, reuse_threshold=2)

    def act(self, board: "Blackboard", role: str, is_leader: bool) -> List[Contribution]:
        out: List[Contribution] = []
        vocab = self.ix.vocabulary()
        if vocab and (role in ("teacher", "collaborator") or is_leader):
            out.append(self._c(role, PROPOSE,
                               {"vocabulary_size": len(vocab),
                                "sample": dict(list(vocab.items())[:5])},
                               note="emergent vocabulary"))
        # mint: when a resolution class crosses the reuse threshold, propose a
        # named primitive for promotion into the library (validated in M25)
        if role == "generator" or is_leader:
            primitives = self.org.morphology.discovered_primitives()
            recurring = [s for s in primitives
                         if len(self.org.morphology.quotient().get(s, [])) >= self.ix.k]
            for sig in recurring[:8]:
                name = f"IX-{sig[:8]}"
                if name not in self.org.congress.library and name not in self.org.congress.tombstones:
                    out.append(self._c(role, MINT,
                                       {"primitive": name, "signature": sig,
                                        "kind": "vocabulary"},
                                       note="promote recurring resolution class"))
        return out


class JDICertEngine(Engine):
    """The governor / certifier / customs officer. The ONLY engine that crosses
    the well. Certifies inbound structure, runs the certification suite (M28),
    and publishes human-facing artifacts on behalf of every level. Carries
    generative initiative: may request collection and direct organization
    (consulting OrgInfecticon)."""
    name = "JDICert"

    def act(self, board: "Blackboard", role: str, is_leader: bool) -> List[Contribution]:
        out: List[Contribution] = []
        sub = board.substrate
        lang = board.language
        if sub is None or lang is None:
            return out

        # enforcer: gate on honesty + adversarial + rehabilitation
        if role == "enforcer" or is_leader:
            spec = board.spectrum or org_detect(sub, lang)
            adv = org_adversarial_score(spec)
            part = org_export_epistemic_partition(sub, lang)
            board.partition = part
            verdict_ok = True
            reasons: List[str] = []
            if adv["p_adversarial"] > 0.9:
                reasons.append(f"adversarial multiplicity p={adv['p_adversarial']}")
            if part["Omega"]:
                reasons.append(f"{len(part['Omega'])} orthogonal/unknowable nodes")
            if board.provenance and board.provenance.confidence == "low":
                reasons.append("low-confidence provenance")
            out.append(self._c(role, CERTIFY,
                               {"adversarial": adv, "partition_sizes":
                                {k: len(v) for k, v in part.items()},
                                "escalate": bool(reasons), "reasons": reasons},
                               note="certification gate"))

        # leader: produce the human-facing certified report and request publish
        if is_leader or role == "collaborator":
            report = org_translate_report(sub, lang, prov=board.provenance,
                                      signatures=self.org.signatures,
                                      manifest=self.org.congress.manifest)
            out.append(self._c(role, PROPOSE,
                               {"report_for_publish": report},
                               weight=1.0, note="certified report"))

        # generative initiative: if the substrate is sparse, request collection
        if (board.classification or {}).get("type", "").startswith("A1"):
            out.append(self._c(role, REQUEST_COLLECTION,
                               {"reason": "sparse/missing structure — more input would help"},
                               note="collection request"))

        # consult OrgInfecticon on organization (standing typed channel)
        if is_leader:
            out.append(self._c(role, PULL,
                               {"from": "OrgInfecticon",
                                "ask": "organizational/group-choice design for current spectrum"},
                               note="JDICert→OrgInfecticon consult"))
        return out


# =============================================================================
#  M22 — THE BLACKBOARD + TYPED CHANNELS
#  One shared working state every engine reads and writes. The default medium
#  of connection (no point-to-point tangle). A presidential function (M23).
#  Typed channels overlay standing contracts; they are auditable sugar.
# =============================================================================

@dataclass
class Blackboard:
    # the problem under work
    substrate: Optional[OrgSubstrate] = None
    language: Optional[OrgLanguage] = None
    provenance: Optional[OrgProvenance] = None
    record: Optional[Record] = None
    # measured state (filled by engines during the cycle)
    spectrum: Optional[OrgSpectrum] = None
    classification: Optional[Dict[str, Any]] = None
    partition: Optional[Dict[str, List[Any]]] = None
    # the running discourse
    contributions: List[Contribution] = field(default_factory=list)
    budget_ms: float = 5000.0
    goal: str = "certify"
    cycle_index: int = 0

    def post(self, c: Contribution) -> None:
        self.contributions.append(c)

    def by_verb(self, verb: str) -> List[Contribution]:
        return [c for c in self.contributions if c.verb == verb]

    def snapshot(self) -> Dict[str, Any]:
        return {
            "goal": self.goal,
            "cycle": self.cycle_index,
            "has_substrate": self.substrate is not None,
            "language": self.language.name if self.language else None,
            "cardinality": self.spectrum.cardinality() if self.spectrum else None,
            "classification": (self.classification or {}).get("type"),
            "partition_sizes": ({k: len(v) for k, v in self.partition.items()}
                                if self.partition else None),
            "n_contributions": len(self.contributions),
        }


class Channel:
    """A typed standing contract between two roles, routed through the board."""
    def __init__(self, name: str, src: str, dst: str):
        self.name = name
        self.src = src
        self.dst = dst
        self.traffic: List[Dict[str, Any]] = []

    def send(self, payload: Any) -> None:
        self.traffic.append({"from": self.src, "to": self.dst, "payload": payload})


# =============================================================================
#  M23 — THE PRESIDENTIAL CONTROLLER + VALUE-LEDGER PRESIDER
#  North pole: direction. It does no domain work; it DIRECTS. It owns orient()
#  (the compass), assign_roles() (the role matrix), budgets, and public-push
#  intent. A SEPARATE value-ledger presider governs the economy and must
#  APPROVE every over-threshold expenditure/transfer (the user's explicit rule:
#  the president approves every transaction over the system, and the value
#  system is stored at the opposite pole).
# =============================================================================

class ValueLedgerPresider:
    """Presides over the bank. Approves/denies expenditures. Distinct from the
    domain controller, but reports to the presidency. When a URF economy is
    attached, approval is governed by the Harmony functional and the singular
    risk barrier (economics codifies power; no expenditure crosses the wall)."""
    def __init__(self, bank: Bank, approval_threshold: float = 5.0,
                 economy: Optional["URFEconomy"] = None):
        self.bank = bank
        self.threshold = approval_threshold
        self.economy = economy
        self.decisions: List[Dict[str, Any]] = []

    def approve(self, frm: str, to: str, amount: float, reason: str,
                expected_benefit: Optional[float] = None) -> bool:
        # below threshold: auto-approve; at/above: require solvency + justification
        ok = True
        urf = None
        if amount >= self.threshold:
            ok = self.bank.weight_of(frm) >= amount and bool(reason)
            # URF harmony gate (when economy attached): the wall + harmony rule
            if ok and self.economy is not None:
                urf = self.economy.evaluate_expenditure(
                    frm, amount, expected_benefit if expected_benefit is not None
                    else amount * 0.5, reason)
                ok = ok and urf["harmonic"]
        self.decisions.append({"from": frm, "to": to, "amount": round(amount, 6),
                               "reason": reason, "approved": ok,
                               "over_threshold": amount >= self.threshold,
                               "urf": urf})
        return ok


class Presidency:
    """The controller at the north pole."""
    def __init__(self, organism: "Chiron"):
        self.org = organism
        # the economy is a URF instantiation over the Congress bank (harmony +
        # singular risk barrier); the presider regulates expenditure through it.
        self._economy = URFEconomy(organism.congress.bank)
        self.presider = ValueLedgerPresider(organism.congress.bank,
                                            economy=self._economy)
        self.public_push_intents: List[Dict[str, Any]] = []

    def orient(self, board: Blackboard) -> Dict[str, Any]:
        """The compass. The presidential pole (top-down goal) and the Congress
        pole (accumulated capital) form a field; choose which engine LEADS this
        cycle and which corner is presented to the well. Deterministic."""
        capital = self.org.congress.bank.market_snapshot()
        cls = (board.classification or {}).get("type", "") if board.classification else ""
        part = board.partition or {}

        # state-driven leadership (not fixed rank):
        if cls.startswith("A4") or (part.get("Omega")):
            leader = "Infectatrum"          # orthogonality/unknowables -> crucible leads (re-basis)
        elif board.substrate is None or cls.startswith("A1"):
            leader = "JDICert"              # missing/sparse/ill-formed -> governor leads (collect)
        elif self._infecticon_ready(board):
            leader = "OrgInfecticon"           # a class crossed reuse threshold -> assembler leads (mint)
        elif board.goal == "certify":
            leader = "JDICert"              # default toward certification + publish
        else:
            leader = "Infectatrum"

        # capital tilt: if one engine vastly out-capitals others, it may lead
        # ties; economics codifies decision weight (but never overrides an
        # A4/Omega safety lead or a JDICert collection need).
        if leader in ("JDICert", "Infectatrum") and capital:
            richest = max(capital, key=lambda k: capital[k])
            if (capital.get(richest, 0.0) > 2.0 * sum(
                    v for k, v in capital.items() if k != richest) and
                    not cls.startswith("A4") and not part.get("Omega")):
                leader = richest if richest in self.org.engines else leader

        presented_corner = "Output" if board.goal == "certify" else leader
        return {"leader": leader, "presented_corner": presented_corner,
                "field": {"direction_goal": board.goal, "capital": capital}}

    def _infecticon_ready(self, board: Blackboard) -> bool:
        q = self.org.morphology.quotient()
        return any(len(v) >= 2 and f"IX-{sig[:8]}" not in self.org.congress.library
                   for sig, v in q.items())

    def assign_roles(self, board: Blackboard, leader: str) -> Dict[str, str]:
        """The role matrix. Each non-leader takes one posture toward the leader.
        Deterministic mapping driven by the cycle's need."""
        roles: Dict[str, str] = {leader: "leader"}
        cls = (board.classification or {}).get("type", "") if board.classification else ""
        others = [e for e in self.org.engines if e != leader]
        # JDICert is enforcer by vocation unless it leads; Infectatrum teaches
        # when not leading; OrgInfecticon collaborates/generates.
        for e in others:
            if e == "JDICert":
                roles[e] = "enforcer"
            elif e == "Infectatrum":
                roles[e] = "teacher" if leader != "Infectatrum" else "collaborator"
            elif e == "OrgInfecticon":
                roles[e] = "generator" if cls.startswith("A2") else "collaborator"
            else:
                roles[e] = "aid"
        return roles

    def push_public(self, intent: Dict[str, Any]) -> None:
        self.public_push_intents.append(intent)


# =============================================================================
#  M24 — THE CYCLE  (perceive -> orient -> assign -> contribute -> arbitrate ->
#                    commit -> route)  The octahedron actually turning.
#  Leadership rotates by orientation; roles reshuffle; surviving contributions
#  become attested artifacts routed to the well (human) or the Congress (else).
# =============================================================================

@dataclass
class CycleResult:
    cycle_index: int
    leader: str
    roles: Dict[str, str]
    n_contributions: int
    committed: List[str]          # artifact ids -> Congress
    published: List[str]          # artifact ids -> well
    escalations: List[Dict[str, Any]]
    orientation: Dict[str, Any]
    board_snapshot: Dict[str, Any]


class Cycle:
    def __init__(self, organism: "Chiron"):
        self.org = organism

    def run_once(self, board: Blackboard) -> CycleResult:
        org = self.org
        board.cycle_index += 1

        # 1. PERCEIVE — a cheap pre-pass so orientation has measured state.
        if board.substrate is not None and board.language is not None and board.spectrum is None:
            board.spectrum = org_detect(board.substrate, board.language,
                                    manifest=org.congress.manifest)
            board.classification = org_classify(board.spectrum)
            board.partition = org_export_epistemic_partition(board.substrate, board.language)

        # 2. ORIENT — the compass.
        orientation = org.presidency.orient(board)
        leader = orientation["leader"]

        # 3. ASSIGN ROLES — the role matrix.
        roles = org.presidency.assign_roles(board, leader)

        # 4. CONTRIBUTE — leader proposes; others act in their roles.
        for ename, role in roles.items():
            engine = org.engines[ename]
            is_leader = (role == "leader")
            for c in engine.act(board, "leader" if is_leader else role, is_leader):
                board.post(c)

        # 4b. honor PULL contributions (typed-channel consults) within the cycle
        for c in board.by_verb(PULL):
            tgt = c.payload.get("from")
            if tgt in org.engines and tgt != c.engine:
                ch = org.channels.get(f"{c.engine}->{tgt}")
                if ch is not None:
                    ch.send(c.payload.get("ask"))

        # 5. ARBITRATE — enforcer gates + capital weight + honesty.
        escalations: List[Dict[str, Any]] = []
        for c in board.by_verb(CERTIFY):
            if c.payload.get("escalate"):
                escalations.append({"by": c.engine, "reasons": c.payload.get("reasons", [])})
        for c in board.by_verb(ESCALATE):
            escalations.append({"by": c.engine, "reason": c.payload.get("reason")})

        # 6. COMMIT — surviving contributions become attested artifacts.
        committed: List[str] = []
        published: List[str] = []
        mint_requests = board.by_verb(MINT)

        for c in board.contributions:
            human_facing = (c.verb == PROPOSE and isinstance(c.payload, dict)
                            and "report_for_publish" in c.payload
                            and c.engine == "JDICert")
            raw_content = (c.payload.get("report_for_publish")
                           if human_facing else c.payload)
            content = _determinize(raw_content)
            art = Artifact.make(
                kind=f"{c.engine}:{c.verb}",
                content=content,
                owners=[(c.engine, c.role, c.weight)],
                prov=board.provenance or OrgProvenance(source=f"cycle:{board.cycle_index}"),
                human_facing=human_facing,
            )
            # credit the bank for process-ownership of every committed artifact
            org.congress.bank.credit(c.engine, c.role, art.aid, c.weight)
            # deposit structural signature into the crystal (resonance memory)
            if board.spectrum is not None:
                feats = OrgSignature.from_spectra("a", [board.spectrum]).features
                cell = org_spec_topology_hash(board.spectrum)
                ref = org.congress.store(content)
                org.congress.crystal.deposit(cell, art.aid, ref, feats)
            else:
                org.congress.store(content)

            # 7. ROUTE — exactly two destinations (L2).
            if art.destination() == WELL:
                # only JDICert crosses the well (L1); it publishes on behalf of all
                org.well.stage(art)
                published.append(art.aid)
            else:
                committed.append(art.aid)

        # process mint requests through the self-modification pipeline (M25)
        for mc in mint_requests:
            org.self_mod.submit_mint(mc.payload, board)

        # re-seal the manifest root after this cycle's writes
        org.congress.seal()

        return CycleResult(
            cycle_index=board.cycle_index, leader=leader, roles=roles,
            n_contributions=len(board.contributions), committed=committed,
            published=published, escalations=escalations,
            orientation=orientation, board_snapshot=board.snapshot(),
        )


# =============================================================================
#  M25 — SELF-MODIFICATION + INFECTICON AS LANGUAGE ASSEMBLER  (L8)
#  The organism adds to / rewrites / erases its own CAPABILITY safely. Growth
#  is DECLARATIVE data the fixed core interprets (L4) — never generated .py.
#    mint     -> a new declarative unit (vocabulary / grammar / chart / operator)
#    rewrite  -> supersede an old unit, provenance linking old->new
#    erase    -> tombstone (retired, never destroyed; chain stays intact)
#  Every change runs: produced -> VALIDATED by enforcer gates -> COMMITTED to
#  Congress with provenance + manifest update -> LOADED into the live registry.
#  The core laws never self-rewrite.
# =============================================================================

@dataclass
class MintProposal:
    name: str
    kind: str                     # vocabulary | grammar | chart | operator
    signature: str
    spec: Dict[str, Any] = field(default_factory=dict)


class SelfModification:
    """The gated growth pipeline. Declarative units only."""
    def __init__(self, organism: "Chiron"):
        self.org = organism
        self.pending: List[MintProposal] = []
        self.history: List[Dict[str, Any]] = []   # audit of every mint/rewrite/erase

    def submit_mint(self, payload: Dict[str, Any], board: Optional[Blackboard]) -> None:
        name = payload.get("primitive") or payload.get("name")
        if not name:
            return
        self.pending.append(MintProposal(
            name=name, kind=payload.get("kind", "vocabulary"),
            signature=payload.get("signature", ""), spec=payload.get("spec", {})))

    def _validate(self, mp: MintProposal) -> Tuple[bool, List[str]]:
        """Enforcer-role validation. A unit must be well-formed, non-colliding,
        and (for grammars/charts) must produce a runnable, deterministic gate
        that retains true-negative power (cannot admit everything)."""
        reasons: List[str] = []
        if mp.name in self.org.congress.library:
            reasons.append("name collision with live library unit")
        if mp.kind == "vocabulary" and not mp.signature:
            reasons.append("vocabulary unit lacks a resolution signature")
        if mp.kind in ("grammar", "chart"):
            lang = self._compile_unit(mp)
            if lang is None:
                reasons.append("unit did not compile to a runnable gate")
            else:
                # true-negative power: must reject at least one probe string
                probes = ["", "###---###", "\x00\x01", "()(()"]
                if all(lang.admits(p) for p in probes):
                    reasons.append("gate admits everything (no true-negative power)")
        return (len(reasons) == 0, reasons)

    def _compile_unit(self, mp: MintProposal) -> Optional[OrgLanguage]:
        """Compile a declarative unit into a runnable OrgLanguage gate. Grammars are
        expressed as a small deterministic rule set (allowed token regex +
        delimiter rules), interpreted here — NOT exec'd Python."""
        spec = mp.spec or {}
        kind = mp.kind
        if kind == "chart":
            base = spec.get("base", "balanced-delims")
            if base == "balanced-delims":
                return balanced_delimiters_language(mp.name)
            if base == "python-syntax":
                return python_syntax_language(mp.name)
            if base == "latin-wordform":
                return org_latin_wordform_language(mp.name)
            return None
        if kind == "grammar":
            has_constraint = bool(spec) and any(
                k in spec for k in ("allowed_chars", "require_vowel", "min_len"))
            allowed = set(spec.get("allowed_chars", ""))
            min_len = int(spec.get("min_len", 1))
            require_vowel = bool(spec.get("require_vowel", False))
            # a grammar with NO declared constraint is degenerate (would admit
            # everything) and must not compile to a usable gate.
            if not has_constraint or (not allowed and not require_vowel and min_len <= 1):
                return None
            def admits(s: str, _a=allowed, _m=min_len, _v=require_vowel) -> bool:
                if len(s) < max(_m, 1):
                    return False
                if _a and any(ch not in _a for ch in s if not ch.isspace()):
                    return False
                if _v and not any(ch in OrgVOWELS for ch in s):
                    return False
                return True
            return OrgLanguage(mp.name, admits, describe=f"minted grammar {mp.name}")
        return None

    def process_pending(self) -> List[Dict[str, Any]]:
        """Run the full pipeline on all pending proposals. Returns audit rows."""
        rows: List[Dict[str, Any]] = []
        for mp in self.pending:
            ok, reasons = self._validate(mp)
            if not ok:
                row = {"action": "mint-REJECTED", "name": mp.name,
                       "kind": mp.kind, "reasons": reasons}
                rows.append(row)
                self.history.append(row)
                continue
            # COMMIT to Congress
            unit_payload = {"name": mp.name, "kind": mp.kind,
                            "signature": mp.signature, "spec": mp.spec,
                            "minted_by": "OrgInfecticon", "owner": AUTHOR_SIGNATURE}
            ref = self.org.congress.store(unit_payload)
            self.org.congress.shelve(mp.name, unit_payload)
            # LOAD into the live registry: grammars/charts become atlas languages
            if mp.kind in ("grammar", "chart"):
                lang = self._compile_unit(mp)
                if lang is not None:
                    self.org.atlas.register(lang)
            row = {"action": "mint-COMMITTED", "name": mp.name, "kind": mp.kind,
                   "vault_ref": ref}
            rows.append(row)
            self.history.append(row)
        self.pending = []
        return rows

    def rewrite(self, old_name: str, new: MintProposal) -> Dict[str, Any]:
        """Supersede an old unit; provenance links old->new; old is tombstoned."""
        ok, reasons = self._validate(new)
        if not ok:
            return {"action": "rewrite-REJECTED", "old": old_name, "reasons": reasons}
        payload = {"name": new.name, "kind": new.kind, "signature": new.signature,
                   "spec": new.spec, "supersedes": old_name, "owner": AUTHOR_SIGNATURE}
        ref = self.org.congress.store(payload)
        self.org.congress.shelve(new.name, payload)
        self.org.congress.tombstone(old_name)
        row = {"action": "rewrite-COMMITTED", "old": old_name, "new": new.name,
               "vault_ref": ref}
        self.history.append(row)
        return row

    def erase(self, name: str) -> Dict[str, Any]:
        """Tombstone a unit (retired, never destroyed)."""
        self.org.congress.tombstone(name)
        row = {"action": "erase-tombstone", "name": name}
        self.history.append(row)
        return row


# =============================================================================
#  M26 — THE CHIRON ENVELOPE  (the enclosing generative field / sphere)
#  Two distinct things share the name:
#   (a) the SPHERE built now — the deep combinatorial engine the others reach
#       into to hold astronomical possibility spaces (the twins finding paths),
#       plus the ingestion-and-codification pipeline for the full 1663 corpus.
#   (b) the TRAINED Chiron that EMERGES when the finished organism runs that
#       complete corpus as its FIRST dataset (downstream; not built now).
#  The "twins" are paired high-multiplicity structures whose product space is
#  characterized and HELD (not enumerated): we report magnitude, find admissible
#  paths by guided search, and sample — never list 10^18 items.
# =============================================================================

class ChironEnvelope:
    """The generative field wrapping the octahedron."""
    def __init__(self, organism: "Chiron"):
        self.org = organism
        self.sim_log: List[Dict[str, Any]] = []

    # --- possibility-space magnitude (characterize, never enumerate) ---------
    @staticmethod
    def multiplicity(sub: OrgSubstrate, lang: OrgLanguage,
                     per_node_options: Optional[Dict[Any, int]] = None) -> Dict[str, Any]:
        """Characterize the possibility space a structure spans. For a figure
        with n nodes each admitting k options under L, the raw space is k^n;
        we report log10 magnitude (so 10^15..10^18 is a number, not a list)."""
        nodes = sub.nodes()
        if per_node_options:
            log10 = sum(math.log10(max(1, per_node_options.get(nd, 1))) for nd in nodes)
        else:
            # estimate per-node options from current ductus participation
            spec = org_detect(sub, lang)
            load = spec.ambiguity_load()
            log10 = sum(math.log10(max(1, load.get(nd, 1))) for nd in nodes)
        return {"n_nodes": len(nodes), "log10_space": round(log10, 3),
                "magnitude": f"~10^{int(log10)}",
                "held_not_enumerated": True}

    # --- the twins: paired structures, joint path-finding --------------------
    def twin_paths(self, twin_a: OrgSubstrate, twin_b: OrgSubstrate, lang: OrgLanguage,
                   max_paths: int = 16, budget_ms: float = 3000.0) -> Dict[str, Any]:
        """Find admissible joint readings across a paired (twin) structure by
        guided search, holding the joint space rather than enumerating it.
        Returns sampled admissible paths + the characterized magnitude."""
        t0 = time.time()
        mag_a = self.multiplicity(twin_a, lang)
        mag_b = self.multiplicity(twin_b, lang)
        joint_log10 = round(mag_a["log10_space"] + mag_b["log10_space"], 3)

        paths: List[Dict[str, str]] = []
        spec_a = org_detect(twin_a, lang)
        spec_b = org_detect(twin_b, lang)
        va = [r for r in spec_a.valid]
        vb = [r for r in spec_b.valid]
        for ra in va:
            for rb in vb:
                if (time.time() - t0) * 1000.0 > budget_ms or len(paths) >= max_paths:
                    break
                # a joint reading is admissible iff both halves are admissible and
                # their concatenation also is (a coherence constraint across twins)
                joint = ra.text + " | " + rb.text
                paths.append({"a": ra.text[:40], "b": rb.text[:40],
                              "a_ductus": ra.ductus, "b_ductus": rb.ductus})
        result = {"twin_a_magnitude": mag_a["magnitude"],
                  "twin_b_magnitude": mag_b["magnitude"],
                  "joint_magnitude": f"~10^{int(joint_log10)}",
                  "joint_log10_space": joint_log10,
                  "sampled_admissible_paths": paths,
                  "n_sampled": len(paths),
                  "held_not_enumerated": True,
                  "elapsed_ms": round((time.time() - t0) * 1000.0, 2)}
        self.sim_log.append({"op": "twin_paths", "joint_log10": joint_log10,
                             "n_sampled": len(paths)})
        return result

    # --- simulation lending: any engine may borrow the sphere's generativity -
    def lend_simulation(self, requester: str, sub: OrgSubstrate, lang: OrgLanguage,
                        steps: int = 8) -> Dict[str, Any]:
        """An engine borrows generative simulation from the sphere. The cost is
        debited from the requester's bank capital, subject to presidential
        approval (the value-ledger presider)."""
        cost = 0.5 + 0.1 * steps
        approved = self.org.presidency.presider.approve(
            frm=requester, to="Chiron", amount=cost,
            reason=f"simulation lend ({steps} steps)")
        if approved:
            self.org.congress.bank.transfer(requester, "Chiron", cost,
                                            "simulation lend", approved=True)
        # the simulation itself: bounded generative exploration of the spectrum
        spec = org_detect(sub, lang)
        explored = []
        seed = spec.distinct()[:steps]
        for s in seed:
            explored.append({"reading": s[:40], "scans": org_scans_as_hexameter(s)})
        out = {"requester": requester, "approved": approved, "cost": cost,
               "explored": explored, "n_explored": len(explored)}
        self.sim_log.append({"op": "lend", "to": requester, "approved": approved})
        return out

    # --- full-corpus ingestion pipeline (the FIRST dataset, prepared) --------
    def ingest_corpus(self, corpus_path: str) -> Dict[str, Any]:
        """Translate + org_codify the full transcribed 1663 corpus into three-root
        records the organism can process. This is the pipeline that will feed
        the finished organism its FIRST dataset. Deterministic; no LLM."""
        try:
            with open(corpus_path, "r", encoding="utf-8") as f:
                doc = json.load(f)
        except OSError as e:
            return {"error": str(e)}
        plates = doc.get("plates", {})
        records: List[str] = []
        for tab, rec in plates.items():
            three_root = record_from_plate(tab, rec)
            ref = self.org.congress.store(asdict_record(three_root))
            self.org.congress.shelve(f"corpus:{tab}", {"ref": ref,
                                     "structure_type": three_root.structure_type})
            records.append(tab)
        return {"corpus": doc.get("corpus", "")[:80],
                "plates_ingested": len(records),
                "plate_ids": records,
                "note": "three-root records prepared as the organism's first dataset"}


# =============================================================================
#  M26-helpers — three-root record construction from plate records
# =============================================================================

def record_from_plate(tab: str, rec: Dict[str, Any]) -> Record:
    """Map a Caramuel plate record to a three-root Record. Diplomatic layer is
    preserved as raw; normalized as normalized; plate metadata demoted to
    provenance.source_meta (kept, not deleted)."""
    cells = rec.get("cells", [])
    bearing: Dict[str, Bearing] = {}
    node_ids: List[str] = []
    if cells and isinstance(cells, list):
        for cell in cells:
            cid = str(cell.get("id"))
            node_ids.append(cid)
            bearing[cid] = Bearing(
                raw=str(cell.get("diplomatic", cell.get("raw", ""))),
                normalized=str(cell.get("normalized", "")),
                confidence=str(cell.get("confidence", rec.get("confidence", "low"))),
                role=str(cell.get("role", "")))
    walks: Dict[str, List[str]] = {}
    fig = rec.get("figure", {})
    if fig:
        toks = fig.get("tokens", {})
        for nid, tok in toks.items():
            if nid not in bearing:
                node_ids.append(nid)
                bearing[nid] = Bearing(raw=str(tok), confidence=rec.get("confidence", "low"))
        walks = {k: list(v) for k, v in fig.get("walks", {}).items()}
    source_meta = {k: rec.get(k) for k in
                   ("title_diplomatic", "title_translation", "geometry",
                    "verses_normalized", "retrogradus_note", "operating_manual",
                    "family", "image_ref") if k in rec}
    prov = OrgProvenance(source=rec.get("source", tab),
                      region=rec.get("tabula", tab),
                      confidence=rec.get("confidence", "low"),
                      flags=rec.get("flags", []),
                      source_meta=source_meta)
    return Record(rid=tab,
                  topology=Topology(node_ids=node_ids, walks=walks),
                  bearing=bearing, provenance=prov,
                  structure_type=rec.get("family", "caramuel-plate"))


def asdict_record(rec: Record) -> Dict[str, Any]:
    return {"rid": rec.rid, "structure_type": rec.structure_type,
            "topology": {"node_ids": rec.topology.node_ids, "walks": rec.topology.walks},
            "bearing": {k: asdict(v) for k, v in rec.bearing.items()},
            "provenance": asdict(rec.provenance)}


