@dataclass
class DomainFingerprint:
    """A compressed, retained representation of a domain: its signature over a
    set of exemplar structures, plus the languages that chart it."""
    name: str
    signature: OrgSignature
    chart_names: List[str]
    n_exemplars: int


class DomainRegistry:
    """Holds all internalized domains, compressed to fingerprints. Cross-maps
    them by signature divergence and mediates communication between them."""
    def __init__(self, organism: "Chiron"):
        self.org = organism
        self.domains: Dict[str, DomainFingerprint] = {}

    def internalize(self, name: str, exemplars: List[Tuple[OrgSubstrate, OrgLanguage]]) -> DomainFingerprint:
        """Compress a domain to a fingerprint: aggregate the spectra of its
        exemplars into one signature, retain the charts. The exemplars
        themselves are stored in the Congress vault (retained, not discarded)."""
        spectra = [org_detect(s, l) for s, l in exemplars]
        sig = OrgSignature.from_spectra(name, spectra)
        charts = sorted({l.name for _, l in exemplars})
        for s, l in exemplars:
            self.org.congress.store({"domain": name, "chart": l.name,
                                     "nodes": s.nodes()})
        fp = DomainFingerprint(name, sig, charts, len(exemplars))
        self.domains[name] = fp
        # deposit the domain's fingerprint into the crystal for resonance recall
        self.org.congress.crystal.deposit(f"domain:{name}", org_sha(name),
                                          self.org.congress.store(sig.features),
                                          sig.features)
        return fp

    def variance_map(self) -> Dict[str, Dict[str, float]]:
        """Pairwise JSD between every pair of retained domains: the mapped
        variance that lets them correct against each other."""
        names = list(self.domains)
        out: Dict[str, Dict[str, float]] = {}
        for a in names:
            out[a] = {}
            for b in names:
                out[a][b] = round(self.domains[a].signature.jsd(
                    self.domains[b].signature), 6)
        return out

    def cross_correct(self, source_domain: str, target_domain: str,
                      sub: OrgSubstrate) -> Dict[str, Any]:
        """Use the target domain's chart to re-read a source-domain structure,
        and report what the variance predicts vs what is observed. This is
        cross-domain communication mediated by the fingerprint geometry."""
        if source_domain not in self.domains or target_domain not in self.domains:
            return {"error": "unknown domain"}
        src = self.domains[source_domain]
        tgt = self.domains[target_domain]
        predicted_divergence = src.signature.jsd(tgt.signature)
        # observed: read sub under each domain's first chart and compare
        observed = {}
        for dom in (src, tgt):
            if dom.chart_names:
                lang = self.org.atlas.langs.get(dom.chart_names[0])
                if lang is not None:
                    sp = org_detect(sub, lang)
                    observed[dom.name] = {"cardinality": sp.cardinality(),
                                          "entropy": round(sp.entropy(), 4)}
        return {"predicted_divergence": round(predicted_divergence, 6),
                "observed": observed,
                "mediated_by": "OrgInfecticon (variance bridge)"}

    def resonant_domains(self, sub: OrgSubstrate, lang: OrgLanguage, k: int = 3) -> List[Tuple[str, float]]:
        """Which retained domains does this structure most resemble? Resonance
        recall over the crystal — the muscle behind 'it has all domains'."""
        feats = OrgSignature.from_spectra("q", [org_detect(sub, lang)]).features
        cells = self.org.congress.crystal.resonate(feats, k=k * 2)
        out: List[Tuple[str, float]] = []
        for cell, dist in cells:
            if cell.startswith("domain:"):
                out.append((cell.split(":", 1)[1], dist))
        return out[:k]


