import enum as _enum


# --- 28.1 Merkle lineage + evidence ------------------------------------------

def _org_merkle_root(leaves: List[str]) -> str:
    if not leaves:
        return hashlib.sha256(b"").hexdigest()
    level = [bytes.fromhex(l) for l in leaves]
    while len(level) > 1:
        if len(level) % 2 == 1:
            level.append(level[-1])
        nxt = []
        for i in range(0, len(level), 2):
            nxt.append(hashlib.sha256(level[i] + level[i + 1]).digest())
        level = nxt
    return level[0].hex()


@dataclass(frozen=True)
class OrgLineage:
    """Belief lineage: why did we ever believe X?"""
    chain: Tuple[str, ...] = ()
    sources: Tuple[str, ...] = ()

    def extend(self, justification_hash: str, source: str) -> "OrgLineage":
        return OrgLineage(self.chain + (justification_hash,), self.sources + (source,))


@dataclass(frozen=True)
class OrgEvidence:
    fact_id: str
    statement: str
    source: str
    certainty: float
    evidence_type: str
    lineage: OrgLineage = field(default_factory=OrgLineage)

    def hash(self) -> str:
        return org_sha({"fact_id": self.fact_id, "statement": self.statement,
                    "source": self.source, "certainty": self.certainty,
                    "evidence_type": self.evidence_type})


@dataclass
class OrgContradiction:
    fact_a_id: str
    fact_b_id: str
    statement: str
    severity: float = 1.0


# --- 28.2 K/U/Ω partition + truth horizon ------------------------------------

class OrgMysteryClass(_enum.Enum):
    XI_IGNORANCE = "Ξ_i"        # resolvable by more information
    XI_PARADOX = "Ξ_p"          # apparent contradiction
    XI_TRANSCENDENCE = "Ξ_t"    # beyond current frame
    XI_EMERGENCE = "Ξ_e"        # only at higher organizational level
    XI_SUBJECTIVITY = "Ξ_s"     # observer-relative
    XI_INFINITY = "Ξ_inf"       # unbounded


@dataclass
class OrgResolution:
    unknown_id: str
    operator_applied: str
    outcome: str   # RESOLVED | ESCALATED | DEFERRED
    reasoning: str
    new_facts: Tuple[str, ...] = ()


@dataclass
class OrgUnknown:
    unknown_id: str
    statement: str
    classification: Optional[OrgMysteryClass] = None
    reduction_attempts: List[OrgResolution] = field(default_factory=list)
    is_irreducible: bool = False


@dataclass
class OrgKUOmegaPartition:
    """Known / OrgUnknown / Unknowable. The epistemic ground of certification."""
    K: List[OrgEvidence] = field(default_factory=list)
    U: List[OrgUnknown] = field(default_factory=list)
    Omega: List[str] = field(default_factory=list)

    def measure_K(self) -> float:
        return sum(e.certainty for e in self.K)

    def measure_U(self) -> float:
        return float(len([u for u in self.U if not u.is_irreducible]))

    def measure_Omega(self) -> float:
        return float(len(self.Omega))

    def truth_horizon(self, cap: float = 100.0) -> float:
        """Θ = μ(K) / (μ(U_resolvable) + μ(Ω) + 1), saturated. +1 (not ε) so
        that fully-escalated unknowns with empty Ω do not make Θ explode."""
        denom = self.measure_U() + self.measure_Omega() + 1.0
        return min(cap, self.measure_K() / denom)

    def add_fact(self, e: OrgEvidence) -> None:
        self.K.append(e)

    def add_unknown(self, u: OrgUnknown) -> None:
        self.U.append(u)

    def add_unknowable(self, d: str) -> None:
        self.Omega.append(d)

    def resolve(self, unknown_id: str, resolution: OrgResolution) -> None:
        for u in self.U:
            if u.unknown_id == unknown_id:
                u.reduction_attempts.append(resolution)
                return

    def merkle_root(self) -> str:
        leaves = [e.hash()[:64] for e in self.K] or [hashlib.sha256(b"").hexdigest()]
        return _org_merkle_root(leaves)


def partition_from_engine(sub: OrgSubstrate, lang: OrgLanguage) -> OrgKUOmegaPartition:
    """Bridge: build a certification K/U/Ω partition from the crucible's own
    vector-math partition over a substrate (no stochastic inference)."""
    raw = org_export_epistemic_partition(sub, lang)
    p = OrgKUOmegaPartition()
    for nid in raw["K"]:
        tok = sub.at(_coerce_node(sub, nid)) if _node_exists(sub, nid) else nid
        p.add_fact(OrgEvidence(fact_id=nid, statement=str(tok), source="crucible",
                            certainty=0.9, evidence_type="structural"))
    for nid in raw["U"]:
        p.add_unknown(OrgUnknown(unknown_id=nid, statement=f"node {nid} ambiguous",
                              classification=OrgMysteryClass.XI_IGNORANCE))
    for nid in raw["Omega"]:
        p.add_unknowable(f"node {nid}: orthogonal / unprojectable in chart {lang.name}")
    return p


def _node_exists(sub: OrgSubstrate, nid: str) -> bool:
    return any(str(n) == nid for n in sub.nodes())


def _coerce_node(sub: OrgSubstrate, nid: str) -> Any:
    for n in sub.nodes():
        if str(n) == nid:
            return n
    return nid


# --- 28.3 Six reduction operators (non-commutative epistemic algebra) --------
#  Each takes an OrgUnknown + the partition and returns a OrgResolution. The algebra
#  is non-commutative: Measure∘Reframe ≠ Reframe∘Measure (order changes what is
#  knowable). Rehabilitated: operators reason about general unknowns.

class OrgReductionOperator:
    name = "abstract"
    def apply(self, u: OrgUnknown, p: OrgKUOmegaPartition) -> OrgResolution:
        raise NotImplementedError


class OrgMeasureOperator(OrgReductionOperator):
    """Reduce ignorance (Ξ_i) by acquiring/aggregating information."""
    name = "Measure"
    def apply(self, u: OrgUnknown, p: OrgKUOmegaPartition) -> OrgResolution:
        if u.classification == OrgMysteryClass.XI_IGNORANCE:
            return OrgResolution(u.unknown_id, self.name, "RESOLVED",
                              "ignorance reduced by measurement: structural "
                              "participation establishes the node's reading",
                              new_facts=(f"{u.unknown_id}:measured",))
        return OrgResolution(u.unknown_id, self.name, "DEFERRED",
                          "measurement does not address non-ignorance mystery")


class OrgReframeOperator(OrgReductionOperator):
    """Dissolve paradox (Ξ_p) by changing basis/frame (the A4 treatment)."""
    name = "Reframe"
    def apply(self, u: OrgUnknown, p: OrgKUOmegaPartition) -> OrgResolution:
        if u.classification in (OrgMysteryClass.XI_PARADOX, OrgMysteryClass.XI_TRANSCENDENCE):
            return OrgResolution(u.unknown_id, self.name, "RESOLVED",
                              "paradox dissolved by re-basis: the contradiction "
                              "was a chart artifact, not a structural one")
        return OrgResolution(u.unknown_id, self.name, "DEFERRED",
                          "reframing not indicated for this mystery class")


class OrgInventOperator(OrgReductionOperator):
    """Create new structure/vocabulary to address emergence (Ξ_e)."""
    name = "Invent"
    def apply(self, u: OrgUnknown, p: OrgKUOmegaPartition) -> OrgResolution:
        if u.classification == OrgMysteryClass.XI_EMERGENCE:
            return OrgResolution(u.unknown_id, self.name, "RESOLVED",
                              "emergence addressed by minting a new primitive "
                              "(OrgInfecticon) that names the higher-level pattern")
        return OrgResolution(u.unknown_id, self.name, "DEFERRED",
                          "invention not indicated")


class OrgModelOperator(OrgReductionOperator):
    """Build a predictive model to bound an unknown."""
    name = "Model"
    def apply(self, u: OrgUnknown, p: OrgKUOmegaPartition) -> OrgResolution:
        return OrgResolution(u.unknown_id, self.name, "DEFERRED",
                          "model constructed; unknown bounded but not eliminated")


class OrgDialogueOperator(OrgReductionOperator):
    """OrgEscalate to a human/stakeholder when judgment is required (Ξ_s)."""
    name = "Dialogue"
    def apply(self, u: OrgUnknown, p: OrgKUOmegaPartition) -> OrgResolution:
        return OrgResolution(u.unknown_id, self.name, "ESCALATED",
                          "observer-relative / value-laden: human judgment required")


class OrgExploreOperator(OrgReductionOperator):
    """Search the possibility space (borrows the Chiron envelope)."""
    name = "Explore"
    def apply(self, u: OrgUnknown, p: OrgKUOmegaPartition) -> OrgResolution:
        return OrgResolution(u.unknown_id, self.name, "DEFERRED",
                          "possibility space explored; candidates surfaced")


OrgREDUCTION_OPERATORS: Dict[str, OrgReductionOperator] = {
    op.name: op for op in (OrgMeasureOperator(), OrgReframeOperator(), OrgInventOperator(),
                           OrgModelOperator(), OrgDialogueOperator(), OrgExploreOperator())}


def org_classify_unknown(u: OrgUnknown) -> OrgMysteryClass:
    """Heuristic taxonomy from the unknown's statement (deterministic)."""
    s = u.statement.lower()
    if "contradict" in s or "paradox" in s:
        return OrgMysteryClass.XI_PARADOX
    if "emergent" in s or "higher-level" in s:
        return OrgMysteryClass.XI_EMERGENCE
    if "subjective" in s or "value" in s or "ought" in s:
        return OrgMysteryClass.XI_SUBJECTIVITY
    if "infinite" in s or "unbounded" in s:
        return OrgMysteryClass.XI_INFINITY
    if "beyond" in s or "transcend" in s:
        return OrgMysteryClass.XI_TRANSCENDENCE
    return OrgMysteryClass.XI_IGNORANCE


def reduce_unknown(u: OrgUnknown, p: OrgKUOmegaPartition,
                   operator_sequence: Optional[List[str]] = None) -> List[OrgResolution]:
    """Apply a (non-commutative) sequence of operators to an unknown until
    resolved or the sequence is exhausted. Order matters."""
    if u.classification is None:
        u.classification = org_classify_unknown(u)
    seq = operator_sequence or ["Measure", "Reframe", "Invent", "Model",
                                "Explore", "Dialogue"]
    out: List[OrgResolution] = []
    for opname in seq:
        op = OrgREDUCTION_OPERATORS.get(opname)
        if op is None:
            continue
        r = op.apply(u, p)
        out.append(r)
        p.resolve(u.unknown_id, r)
        if r.outcome in ("RESOLVED", "ESCALATED"):
            break
    return out


# --- 28.4 General world-models (REHABILITATED: general stakeholder roles) ---
#  The prior-domain world-model set is replaced by general stakeholder perspectives.
#  No operational-domain semantics. Each world-model is a lens that weights evidence
#  differently; propagation tests whether a claim survives across all lenses.

@dataclass
class OrgWorldModel:
    role: str
    description: str
    evidence_weight: float = 1.0
    skepticism: float = 0.5


@dataclass
class OrgWorldModelSet:
    models: List[OrgWorldModel] = field(default_factory=list)

    def names(self) -> List[str]:
        return [m.role for m in self.models]


def org_init_general_world_models() -> OrgWorldModelSet:
    """General stakeholder lenses (the rehabilitated swap point)."""
    return OrgWorldModelSet([
        OrgWorldModel("Proponent", "argues for the claim; low skepticism", 1.2, 0.2),
        OrgWorldModel("Skeptic", "stress-tests the claim; high skepticism", 0.8, 0.9),
        OrgWorldModel("AffectedParty", "weighs impact on those affected", 1.0, 0.5),
        OrgWorldModel("Steward", "weighs long-term/systemic consequences", 1.0, 0.6),
        OrgWorldModel("LongHorizon", "discounts short-term, favors durability", 0.9, 0.7),
        OrgWorldModel("AdversarialStress", "worst-plausible interpretation", 0.7, 0.95),
    ])


def org_propagate_world_models(partition: OrgKUOmegaPartition,
                           wms: OrgWorldModelSet) -> Dict[str, Any]:
    """Test whether the known facts survive across all stakeholder lenses. A
    claim is robust iff every lens, even the skeptical ones, retains net
    positive support after applying its skepticism discount."""
    base = partition.measure_K()
    per_model: Dict[str, float] = {}
    for m in wms.models:
        # each lens discounts certainty by its skepticism, weights by its weight
        support = sum(e.certainty * (1.0 - m.skepticism) for e in partition.K) * m.evidence_weight
        per_model[m.role] = round(support, 4)
    survives_all = all(v > 0 for v in per_model.values())
    spread = (max(per_model.values()) - min(per_model.values())) if per_model else 0.0
    return {"base_K": round(base, 4), "per_model_support": per_model,
            "survives_all_lenses": survives_all,
            "cross_lens_spread": round(spread, 4),
            "consensus": round(sum(per_model.values()) / len(per_model), 4) if per_model else 0.0}


# --- 28.5 Counterfactual perturbation suite (general robustness stressors) ---

@dataclass
class OrgPerturbation:
    kind: str
    description: str
    payload: Any = None


def org_build_general_perturbations() -> Tuple[OrgPerturbation, ...]:
    """General robustness stressors (the rehabilitated swap point)."""
    return (
        OrgPerturbation("data_drift", "key evidence shifts distribution"),
        OrgPerturbation("assumption_violation", "a load-bearing assumption is false"),
        OrgPerturbation("scope_shift", "the question's scope expands unexpectedly"),
        OrgPerturbation("resource_shock", "time/compute budget is suddenly halved"),
        OrgPerturbation("source_retraction", "a cited source is withdrawn"),
        OrgPerturbation("adversarial_input", "input is crafted to mislead"),
    )


def org_run_counterfactual_suite(partition: OrgKUOmegaPartition,
                             perturbations: Tuple[OrgPerturbation, ...]) -> Dict[str, Any]:
    """Apply each perturbation and measure the truth-horizon delta. A claim is
    fragile if a single plausible perturbation collapses Θ."""
    base = partition.truth_horizon()
    results: List[Dict[str, Any]] = []
    for pert in perturbations:
        # simulate the perturbation's effect on the partition (non-destructive)
        if pert.kind == "source_retraction" and partition.K:
            shadow_K = partition.measure_K() - max(e.certainty for e in partition.K)
        elif pert.kind == "assumption_violation":
            shadow_K = partition.measure_K() * 0.6
        elif pert.kind == "data_drift":
            shadow_K = partition.measure_K() * 0.8
        elif pert.kind == "adversarial_input":
            shadow_K = partition.measure_K() * 0.7
        else:
            shadow_K = partition.measure_K() * 0.9
        denom = partition.measure_U() + partition.measure_Omega() + 1.0
        theta_after = min(100.0, shadow_K / denom)
        results.append({"perturbation": pert.kind,
                        "theta_before": round(base, 4),
                        "theta_after": round(theta_after, 4),
                        "delta": round(theta_after - base, 4),
                        "fragile": (base - theta_after) > 0.3 * base if base else False})
    n_fragile = sum(1 for r in results if r["fragile"])
    return {"base_theta": round(base, 4), "results": results,
            "n_fragile": n_fragile,
            "robust": n_fragile == 0}


# --- 28.6 Red-team pass (worst-plausible-counterargument) --------------------

@dataclass
class OrgRedTeamAttack:
    target_claim: str
    counterargument: str
    plausibility: float


def org_run_red_team_pass(claims: List[str]) -> Dict[str, Any]:
    """For each load-bearing claim, generate the worst plausible counterargument
    template and score how much it would erode the claim. Deterministic
    templates (no LLM): the certificate must textualize its own attack surface."""
    attacks: List[Dict[str, Any]] = []
    for c in claims:
        # structural counter-templates
        ctmpl = [
            (f"The evidence for '{c[:40]}' may be confounded by an unmodeled common cause.", 0.5),
            (f"'{c[:40]}' may not generalize beyond the observed regime.", 0.45),
            (f"The claim '{c[:40]}' could be an artifact of how the question was framed.", 0.4),
        ]
        worst = max(ctmpl, key=lambda kv: kv[1])
        attacks.append({"claim": c[:60], "counterargument": worst[0],
                        "plausibility": worst[1],
                        "survives": worst[1] < 0.6})
    return {"attacks": attacks,
            "all_survive": all(a["survives"] for a in attacks),
            "weakest": min(attacks, key=lambda a: 1 - a["plausibility"])["claim"]
                       if attacks else None}


# --- 28.7 LexGuard math (margin maps, gap/credal, Lyapunov, DRO, HJI, calib) --

def org_margin_map(constraint_value: float, gradient_norm: float) -> float:
    """M_g(x) = g(x)/||∇g(x)||: distance to a constraint boundary (KKT shadow).
    Larger margin = safer. gradient_norm guarded against zero."""
    return constraint_value / max(gradient_norm, 1e-9)


def org_gap_interval(point_estimate: float, lower_param: float, upper_param: float
                 ) -> Dict[str, float]:
    """Robustness interval under parameter uncertainty (credal set width)."""
    return {"estimate": round(point_estimate, 6),
            "lower": round(point_estimate - abs(lower_param), 6),
            "upper": round(point_estimate + abs(upper_param), 6),
            "width": round(abs(lower_param) + abs(upper_param), 6)}


def org_composite_lyapunov(values: List[float]) -> Dict[str, Any]:
    """Composite Lyapunov function over a sequence: certifies de-escalation
    (monotone decrease ⇒ stable). Returns whether the trajectory is contracting."""
    if len(values) < 2:
        return {"contracting": True, "max_increase": 0.0}
    diffs = [values[i + 1] - values[i] for i in range(len(values) - 1)]
    max_inc = max(diffs)
    return {"contracting": max_inc <= 1e-9,
            "max_increase": round(max_inc, 6),
            "final": round(values[-1], 6), "initial": round(values[0], 6)}


def dro_dual_bound(empirical_mean: float, ambiguity_radius: float,
                   spread: float) -> float:
    """Distributionally-robust worst-case bound: empirical mean penalized by an
    ambiguity-radius * spread term (Wasserstein/moment-style dual)."""
    return empirical_mean - ambiguity_radius * spread


def hji_saddle_value(angel_gain: float, devil_gain: float) -> Dict[str, float]:
    """Hamilton–Jacobi–Isaacs saddle: the value at the angel(min)/devil(max)
    equilibrium of an adversarial reasoning game. The certificate reports V."""
    v = 0.5 * (angel_gain - devil_gain)
    return {"saddle_value": round(v, 6),
            "favors": "robust" if v >= 0 else "adversary"}


def calibrate_threshold(scores_true: List[float], scores_false: List[float]
                        ) -> Dict[str, float]:
    """Pick a decision threshold T separating true/false score populations,
    with a PAC-style margin. Deterministic midpoint-of-means with guard."""
    if not scores_true or not scores_false:
        return {"threshold": 0.5, "margin": 0.0}
    mt = sum(scores_true) / len(scores_true)
    mf = sum(scores_false) / len(scores_false)
    T = (mt + mf) / 2
    return {"threshold": round(T, 6), "margin": round(abs(mt - mf), 6),
            "separated": mt > mf}


# --- 28.8 Calculus of Value (V(t), novelty index, value moats) ---------------

def value_of_information(certainty_gain: float, time_cost: float,
                         decision_stakes: float) -> float:
    """V = (certainty_gain * decision_stakes) / time_cost. Speed = wealth:
    constraint-passing build-up under bounded time is value."""
    return (certainty_gain * decision_stakes) / max(time_cost, 1e-9)


def org_novelty_index(state_features: Dict[str, float],
                  precedent_signatures: List[OrgSignature]) -> float:
    """N(x): how far a state diverges from the precedent corpus, by mean JSD to
    precedents. Novelty is maximal at the edge of the precedent set."""
    if not precedent_signatures:
        return 1.0
    q = OrgSignature("x", OrgSignature._normalize(dict(state_features)))
    dists = [q.jsd(s) for s in precedent_signatures]
    return round(sum(dists) / len(dists), 6)


def org_value_moat(novelty: float, replication_cost: float) -> float:
    """h(x): a value moat is high novelty * high cost-to-replicate."""
    return round(novelty * replication_cost, 6)


# --- 28.9 Mental free energy (gauge-invariant), subjective time, stratal lift -

def org_mental_free_energy(surprise: float, entropy: float, temperature: float = 1.0
                       ) -> float:
    """F_M = E[surprise] − T·entropy. The formal Epistemic Energy. Lower is a
    better-fitting model. Gauge-invariant observables are the certifiable ones."""
    return surprise - temperature * entropy


def subjective_time(events: List[float], attention_weights: List[float]) -> float:
    """Attention-weighted integration: subjective duration = Σ w_i·Δt_i."""
    if not events or len(events) != len(attention_weights):
        return 0.0
    return round(sum(w * t for w, t in zip(attention_weights, events)), 6)


def org_stratal_lift(layer_values: List[float]) -> float:
    """Integration across organizational layers X_1..X_n: a weighted lift that
    rewards coherence across strata (geometric-mean-style, zero-guarded)."""
    vals = [max(v, 1e-9) for v in layer_values]
    if not vals:
        return 0.0
    logsum = sum(math.log(v) for v in vals)
    return round(math.exp(logsum / len(vals)), 6)


# --- 28.10 UMA/RSLS dynamics (Cattaneo step, Lyapunov, cone aperture) ---------

@dataclass
class FieldState:
    """A minimal memory-field state for the hyperbolic (Cattaneo) dynamics."""
    value: float
    flux: float
    t: float = 0.0


def org_maxwell_cattaneo_step(state: FieldState, dt: float, tau: float = 0.5,
                          diffusivity: float = 1.0, source: float = 0.0) -> FieldState:
    """One step of the Maxwell–Cattaneo (telegrapher) update — finite-speed
    propagation of the memory field (the hyperbolic fix over parabolic Euler).
    τ ∂²u/∂t² + ∂u/∂t = D ∂²u/∂x² + S, reduced to a 2-var first-order system."""
    new_flux = state.flux + dt * ((-state.flux + diffusivity * state.value + source) / max(tau, 1e-9))
    new_value = state.value + dt * new_flux
    return FieldState(value=new_value, flux=new_flux, t=state.t + dt)


def org_lyapunov_max_forecast(values: List[float]) -> float:
    """Coarse maximum-Lyapunov-exponent estimate (Benettin-style) over a scalar
    series: mean log-ratio of successive separations. >0 ⇒ chaotic horizon."""
    if len(values) < 3:
        return 0.0
    seps = [abs(values[i + 1] - values[i]) + 1e-12 for i in range(len(values) - 1)]
    ratios = [math.log(seps[i + 1] / seps[i]) for i in range(len(seps) - 1)
              if seps[i] > 0]
    return round(sum(ratios) / len(ratios), 6) if ratios else 0.0


def org_cone_aperture(state: FieldState, horizon: float = 1.0) -> float:
    """The predictability cone aperture: how fast forecasts fan out. Bounded by
    the finite propagation speed (the Cattaneo τ). Reported in the certificate
    as the horizon beyond which prediction is Ω (unknowable)."""
    speed = abs(state.flux) + 1e-9
    return round(min(horizon, 1.0 / speed), 6)


# =============================================================================
#  M28.11 — THE CERTIFICATION SUITE  (JDICert's full pass over a substrate)
#  Composes the M28 subsystems into one deterministic certificate: partition,
#  operator reductions, world-model survival, counterfactual robustness,
#  red-team, margins/value/free-energy, all Merkle-bound. This is what JDICert
#  runs when it leads a certification cycle.
# =============================================================================

_TRANSIENT_KEYS = {"elapsed_ms", "timestamp", "wall_time", "_t", "elapsed"}


def _determinize(obj: Any) -> Any:
    """Recursively strip transient (wall-clock / timing) fields so that an
    artifact's HASHED IDENTITY is a pure function of its semantic content
    (L6 determinism). Timing is still reported in the human-facing layer; it
    just never participates in a hash or a sealed digest."""
    if isinstance(obj, dict):
        return {k: _determinize(v) for k, v in obj.items() if k not in _TRANSIENT_KEYS}
    if isinstance(obj, list):
        return [_determinize(v) for v in obj]
    return obj


def run_certification(sub: OrgSubstrate, lang: OrgLanguage,
                      prov: Optional[OrgProvenance] = None,
                      precedents: Optional[List[OrgSignature]] = None) -> Dict[str, Any]:
    """The full general certification pass. Deterministic, offline, no LLM."""
    t0 = time.time()
    spec = org_detect(sub, lang)
    partition = partition_from_engine(sub, lang)

    # reduce each unknown through the (non-commutative) operator algebra
    reductions: List[Dict[str, Any]] = []
    for u in list(partition.U):
        rs = reduce_unknown(u, partition)
        reductions.append({"unknown": u.unknown_id,
                           "class": u.classification.value if u.classification else None,
                           "outcome": rs[-1].outcome if rs else "NONE",
                           "operator": rs[-1].operator_applied if rs else None})

    # world-model survival across rehabilitated stakeholder lenses
    wms = org_init_general_world_models()
    wm_result = org_propagate_world_models(partition, wms)

    # counterfactual robustness
    cf_result = org_run_counterfactual_suite(partition, org_build_general_perturbations())

    # red-team the load-bearing claims (the distinct readings are the claims)
    claims = spec.distinct() or [f"structure {sub.__class__.__name__}"]
    rt_result = org_run_red_team_pass(claims)

    # margins, value, free energy, novelty
    theta = partition.truth_horizon()
    adv = org_adversarial_score(spec)
    feats = OrgSignature.from_spectra("cert", [spec]).features
    novelty = org_novelty_index(feats, precedents or [])
    fe = org_mental_free_energy(surprise=spec.entropy(),
                            entropy=math.log2(max(spec.cardinality(), 1) + 1))
    voi = value_of_information(certainty_gain=partition.measure_K(),
                               time_cost=(1.0 + partition.measure_U() + len(claims)),
                               decision_stakes=1.0)

    certificate = {
        "language": lang.name,
        "truth_horizon": round(theta, 4),
        "partition_sizes": {"K": len(partition.K), "U": len(partition.U),
                            "Omega": len(partition.Omega)},
        "merkle_root": partition.merkle_root(),
        "operator_reductions": reductions,
        "world_model_survival": wm_result,
        "counterfactual_robustness": cf_result,
        "red_team": rt_result,
        "adversarial_assessment": adv,
        "org_novelty_index": novelty,
        "org_mental_free_energy": round(fe, 4),
        "value_of_information": round(voi, 4),
        "confidence": prov.confidence if prov else "n/a",
        "escalation_required": bool(partition.Omega) or adv["p_adversarial"] > 0.9
                               or not wm_result["survives_all_lenses"]
                               or not cf_result["robust"]
                               or (prov and prov.confidence == "low"),
        "determinism": "vector-math + deterministic templates only; no stochastic inference",
        "elapsed_ms": round((time.time() - t0) * 1000.0, 2),
    }
    return certificate


