# SATOR: the canonical multidirectional Latin square — the structural fixture.
SATOR_ROWS = ["SATOR", "AREPO", "TENET", "OPERA", "ROTAS"]


def sator_fixture() -> OrgPicture:
    return OrgPicture.from_words(SATOR_ROWS)


def tab_xiii_fixture() -> OrgFigureGraph:
    """A small hexagram-style OrgFigureGraph standing in for Tab. XIII: named nodes
    carrying tokens with two declared walks that share intersection nodes."""
    tokens = {"n0": "AQVINAS", "n1": "DEUS", "n2": "LUX", "n3": "VERA",
              "n4": "VIA", "n5": "VITA"}
    walks = {"recurrens": ["n0", "n1", "n2", "n3"],
             "circumvolans": ["n2", "n4", "n5", "n0"]}
    return OrgFigureGraph(tokens, walks)


def org_load_consolidated_corpus(path: str) -> Dict[str, Record]:
    """Load corpus_all.json into three-root Records (the universal unit)."""
    with open(path, "r", encoding="utf-8") as f:
        doc = json.load(f)
    out: Dict[str, Record] = {}
    for tab, rec in doc.get("plates", {}).items():
        out[tab] = record_from_plate(tab, rec)
    return out


# =============================================================================
#  M30 — THE CHIRON ORGANISM  (the integrating class — wires every layer)
#  One object holding the engines, the blackboard substrate, the Congress
#  (single store), the well (sole I/O), the presidency, the cycle, the
#  self-modification pipeline, the Chiron envelope, and the domain registry.
# =============================================================================

class Chiron:
    """The whole organism. Constructed once; runs cycles; serializes to one
    portable memory file. This is the Chiron Intelligence Program."""

    def __init__(self, memory: Optional[Congress] = None):
        # south pole — the single store (vault/library/bank/crystal/manifest)
        self.congress = memory or Congress()
        # shared sub-engines used across the organism
        self.morphology = OrgResolutionMorphology()
        self.signatures = OrgSignatureLibrary()
        self.atlas = Atlas()
        # the well — sole I/O membrane (L1)
        self.well = HoldingTank()
        # the three equatorial engines (agents)
        self.engines: Dict[str, Engine] = {
            "Infectatrum": InfectatrumEngine(self),
            "OrgInfecticon": InfecticonEngine(self),
            "JDICert": JDICertEngine(self),
        }
        # north pole — direction + value-ledger presider
        self.presidency = Presidency(self)
        # the self-modification pipeline (L8)
        self.self_mod = SelfModification(self)
        # the enclosing generative field
        self.envelope = ChironEnvelope(self)
        # the cross-domain retention core
        self.domains = DomainRegistry(self)
        # the deep field-cognition thinker (UMA/RSLS; numpy-gated)
        self.field = FieldCognition(self)
        # the cycle driver
        self.cycle = Cycle(self)
        # typed channels (standing contracts)
        self.channels: Dict[str, Channel] = {
            "JDICert->OrgInfecticon": Channel("JDICert->OrgInfecticon", "JDICert", "OrgInfecticon"),
            "Infectatrum->Chiron": Channel("Infectatrum->Chiron", "Infectatrum", "Chiron"),
            "JDICert->Chiron": Channel("JDICert->Chiron", "JDICert", "Chiron"),
        }
        self._bootstrap_atlas()

    def _bootstrap_atlas(self) -> None:
        """Register the reference language packs. Caramuel is ONE pack among
        several — the engine is not Caramuel-bound."""
        for lang in (org_latin_meter_language(), org_latin_wordform_language(),
                     python_syntax_language(), balanced_delimiters_language()):
            self.atlas.register(lang)

    # --- the boundary: ingest through the well (L1) --------------------------
    def ingest_text(self, text: str, source: str = "ingest",
                    structure: str = "auto") -> Record:
        """External text -> the well -> a three-root Record. The ONLY inbound
        path. Deterministic standardization (no LLM); JDICert governs it."""
        self.well.receive({"text": text, "source": source})
        self.well.take_inbound()
        return standardize_to_record(text, source=source, structure=structure)

    # --- run the organism on a record ---------------------------------------
    def process_record(self, rec: Record, language: Optional[str] = None,
                       max_cycles: int = 4) -> Dict[str, Any]:
        """Mount a record on the blackboard and run cycles until the goal is met
        or the cycle budget is exhausted. Returns the run trace + the published
        report (what a human pulls from the well)."""
        sub = substrate_from_record(rec)
        # choose a chart: explicit, else infer the best basis from the atlas
        if language and language in self.atlas.langs:
            lang = self.atlas.langs[language]
        else:
            best, _ = self.atlas.infer_basis(sub)
            lang = self.atlas.langs.get(best) or org_latin_wordform_language()

        board = Blackboard(substrate=sub, language=lang, provenance=rec.provenance,
                           record=rec, goal="certify")
        results: List[CycleResult] = []
        for _ in range(max_cycles):
            res = self.cycle.run_once(board)
            results.append(res)
            # process any minted capability proposed this cycle
            self.self_mod.process_pending()
            # stop when JDICert has staged a report and no escalations remain
            if board.by_verb(PROPOSE) and not res.escalations and self.well.outbound:
                break

        # JDICert publishes the certified report to the well on behalf of all
        certificate = run_certification(sub, lang, prov=rec.provenance,
                                        precedents=list(
                                            self.signatures.known.values()))
        # the organism also THINKS the record in the field substrate: encode the
        # record's surface text into ψ and relax toward Ω. The closure result
        # (and the RSLS memory pressure it induces) enriches the certificate.
        surface = " ".join(b.token() for b in rec.bearing.values()) or rec.rid
        field_result = self.field.think(surface)
        certificate["field_cognition"] = field_result.get(
            "field_cognition", "unavailable")
        certificate["congress_memory_pressure"] = self.congress.memory_pressure()
        if isinstance(certificate["field_cognition"], dict):
            certificate["omega_closure"] = certificate["field_cognition"].get(
                "omega_closure", False)
        report_artifact = Artifact.make(
            kind="JDICert:intelligence_report",
            content={"certificate": _determinize(certificate),
                     "record_id": rec.rid,
                     "structure_type": rec.structure_type},
            owners=[("JDICert", "leader", 2.0)],
            prov=rec.provenance, human_facing=True)
        self.congress.bank.credit("JDICert", "leader", report_artifact.aid, 2.0)
        self.well.stage(report_artifact)
        self.congress.seal()

        return {"record_id": rec.rid,
                "chart": lang.name,
                "cycles_run": len(results),
                "cycle_trace": [self._cycle_summary(r) for r in results],
                "certificate": certificate,
                "report_artifact_id": report_artifact.aid}

    _DOMAIN_LABELS = {"numeric": "numeric-sequences", "string": "text-and-language",
                      "graph": "graphs", "code": "code-structures",
                      "figuregraph": "figures-and-grids", "transform": "ciphers-and-maps"}

    def _domain_key(self, text: str, rec: "Record") -> str:
        """Name the domain this material belongs to using the engine's OWN read of
        it (numeric / text / code / graph / figure), so the Congress sorts what it
        learns into meaningful domains rather than one bucket."""
        try:
            parts = str(text).replace(",", " ").split()
            try:
                vals = [float(x) for x in parts]
                seq = [int(v) if float(v).is_integer() else v for v in vals]
            except ValueError:
                seq = None
            inv = collapse(seq if seq is not None else str(text))
            return self._DOMAIN_LABELS.get(inv.domain, inv.domain or "general")
        except Exception:
            return (getattr(rec, "structure_type", None) or "general")

    def _form_domain(self, rec: "Record", name: Optional[str] = None) -> Dict[str, Any]:
        """Auto-form or extend a knowledge domain. A NEW domain is born the first
        time a structurally-distinct kind of material is seen; the same kind
        EXTENDS the existing domain. This is the exact point the Congress grows a
        new domain as it consumes."""
        name = (name or getattr(rec, "structure_type", None) or "general").strip() or "general"
        try:
            sub = substrate_from_record(rec)
            best, _ = self.atlas.infer_basis(sub)
            lang = self.atlas.langs.get(best) or org_latin_wordform_language()
            reg = self.domains
            if not hasattr(reg, "_ex"):
                reg._ex = {}
            was_new = name not in reg.domains
            reg._ex.setdefault(name, []).append((sub, lang))
            fp = reg.internalize(name, reg._ex[name])
            return {"domain": name, "is_new": was_new, "exemplars": fp.n_exemplars,
                    "charts": list(fp.chart_names)}
        except Exception as e:
            return {"domain": name, "is_new": False, "exemplars": 0, "error": str(e)}

    @staticmethod
    def _extract_sequence(text: str, min_run: int = 4):
        """Find the longest run of consecutive numeric tokens embedded in prose, so
        the engine can recover laws hiding inside ordinary text (e.g. a table or a
        sequence quoted in an article), not only inputs that are pure numbers."""
        best, cur = [], []
        for tok in str(text).replace(",", " ").split():
            try:
                v = float(tok)
                cur.append(int(v) if v.is_integer() else v)
            except ValueError:
                if len(cur) > len(best):
                    best = cur
                cur = []
        if len(cur) > len(best):
            best = cur
        return best if len(best) >= min_run else None

    def _engine_read(self, text: str):
        """Collapse the raw input once to get the engine's structural read. Pure
        numeric input collapses directly; otherwise we look for an embedded numeric
        run to collapse; failing that, the literal string is read."""
        parts = str(text).replace(",", " ").split()
        try:
            vals = [float(x) for x in parts]
            seq = [int(v) if float(v).is_integer() else v for v in vals]
        except ValueError:
            seq = self._extract_sequence(text)
        return collapse(seq if seq is not None else str(text))

    def _growth_state(self) -> Dict[str, Any]:
        if not isinstance(getattr(self, "growth", None), dict):
            self.growth = {"integral": 0, "general": 0, "cross_domain": 0, "reuse": 0,
                           "history": [], "laws": []}
        self.growth.setdefault("reuse", 0)
        if not hasattr(self, "_gen_seen"):
            self._gen_seen = set()
        if not hasattr(self, "_law_by_gen"):
            self._law_by_gen = {law["generator"]: law for law in self.growth.get("laws", [])}
        if not hasattr(self, "_fam_domains"):
            self._fam_domains = {}
        if not hasattr(self, "membranes"):
            self.membranes = {}
        if not hasattr(self, "authors"):
            self.authors = {}
        if not hasattr(self, "ingested_sources"):
            self.ingested_sources = []
            self._ingested_set = set()
        if not hasattr(self, "_ingested_set"):
            self._ingested_set = set(self.ingested_sources)
        if not hasattr(self, "_fam_domain_sets"):      # family -> set of domains it appears in
            self._fam_domain_sets = {}
        if not hasattr(self, "concepts"):              # grown cross-domain concepts (tier-1 self-growth)
            self.concepts = {}
        return self.growth

    def recall(self, generator_fp: str):
        """Lookup-before-recompute: O(1) recognition of an already-verified
        generator (the feedback loop — a known law is reused, not re-earned)."""
        self._growth_state()
        return self._law_by_gen.get(str(generator_fp)[:16])

    def recognize(self, surface) -> Dict[str, Any]:
        """Recognition: has this surface's rule already been proven? Recover its
        generator, then look it up in the learned law library (O(1)). Because laws
        now carry their parameters, a recognized rule is a fully replayable record —
        the feedback loop made first-class, and the substrate for composing learned
        rules into new ones."""
        self._growth_state()
        try:
            inv = self._engine_read(surface)
        except Exception as e:
            return {"error": str(e)}
        gen = inv.generator_fingerprint[:16]
        known = self._law_by_gen.get(gen)
        verified = bool(getattr(inv, "verified", False))
        return {"recovered": inv.model_class, "verified": verified,
                "generator": gen, "known": bool(known), "law": known,
                "library_size": len(self._law_by_gen),
                "note": ("recognized — already in the library, reused not re-earned" if known
                         else "new — would be added to the library on ingest" if verified
                         else "no verified rule in this surface to recognize")}

    def set_membrane(self, domain: str, policy: str = "sealed") -> Dict[str, Any]:
        """Knowledge-gating: a SEALED domain will not let its laws transfer outward.
        Selectivity is structure — the system earns generalization rather than leaking it."""
        self._growth_state()
        self.membranes[domain] = ("sealed" if policy == "sealed" else "open")
        return {"domain": domain, "membrane": self.membranes[domain]}

    def record_growth(self, inv, domain: str, source: str = "ingest",
                      author: str = "unknown") -> Dict[str, Any]:
        """Classify a finding as INTEGRAL (a verified, reusable generator that
        extends the law library) or GENERAL knowledge; recognize REUSE of a known
        law (feedback); detect membrane-gated cross-domain transfer; carry the
        author of the digested work; snapshot growth."""
        g = self._growth_state()
        if author and author != "unknown":
            self.authors[domain] = author
        fam = inv.family_fingerprint[:16]; gen = inv.generator_fingerprint[:16]
        transfer = False; reused = False; klass = "general"
        if getattr(inv, "verified", False):
            klass = "integral"; g["integral"] += 1
            if gen in self._gen_seen:
                g["reuse"] += 1; reused = True          # known law recognized O(1)
            else:
                self._gen_seen.add(gen)
                law = {"generator": gen, "family": fam, "domain": domain,
                       "model_class": inv.model_class, "source": source, "author": author,
                       "params": _jsonable(getattr(inv, "params", {}))}   # replayable, not just a fingerprint
                g["laws"].append(law); self._law_by_gen[gen] = law
            prev = self._fam_domains.get(fam)
            # cross-domain transfer only if the source domain's membrane is open
            if prev and prev != domain and self.membranes.get(prev, "open") != "sealed":
                g["cross_domain"] += 1; transfer = True
            self._fam_domains.setdefault(fam, domain)
            self._fam_domain_sets.setdefault(fam, set()).add(domain)   # full domain set per family
        else:
            g["general"] += 1
        g["history"].append({"t": len(g["history"]) + 1, "integral": g["integral"],
                             "general": g["general"], "generators": len(self._gen_seen),
                             "cross_domain": g["cross_domain"], "reuse": g["reuse"],
                             "domains": len(self.domains.domains)})
        if len(g["history"]) > 1000:
            g["history"] = g["history"][-1000:]
        return {"classification": klass, "cross_domain_transfer": transfer, "reused": reused,
                "law": gen if klass == "integral" else None}

    def merge_laws(self, other) -> Dict[str, Any]:
        """SWARM substrate: union another organism's verified laws into this one.
        Idempotent and order-independent — pool intelligence without sharing raw data."""
        g = self._growth_state()
        if isinstance(other, str):
            with open(other, "r", encoding="utf-8") as f:
                other = json.load(f)
        incoming = (other.get("growth", {}) or {}).get("laws", []) if isinstance(other, dict) else []
        added = 0
        for law in incoming:
            gen = law.get("generator")
            if gen and gen not in self._gen_seen:
                self._gen_seen.add(gen); self._law_by_gen[gen] = law
                g["laws"].append(law); added += 1
        return {"incoming": len(incoming), "added": added, "total_laws": len(g["laws"])}

    def checkpoint(self, directory: Optional[str] = None) -> Dict[str, Any]:
        """An immutable, sealed snapshot of the Congress (omega-origin management):
        pin a known-good state you can restore."""
        import time as _t
        d = directory or "."
        path = os.path.join(d, "chiron_checkpoint_%s.json" % _t.strftime("%Y%m%d-%H%M%S"))
        root = self.save_memory(path)
        return {"checkpoint": path, "root": root}

    def compact(self, max_vault: int = 2000, max_ledger: int = 4000,
                max_history: int = 400, max_crystal_cells: int = 2000,
                max_bytes: int = 1200) -> Dict[str, Any]:
        """Distill the Congress so it can grow forever without bloating: trim the
        RAW bulk (oldest vault items, ledger entries, crystal deposits, history) and
        replace bulky per-line node scaffolding with a digest, while KEEPING the
        durable core — every integral generator/law, the domain summaries, the bank
        balances, and the owner-signed provenance root."""
        g = self._growth_state(); before = self.memory_tiers()
        trimmed = {"vault": 0, "ledger": 0, "crystal_cells": 0, "history": 0, "node_graphs_pruned": 0}
        v = getattr(self.congress, "vault", {})
        if isinstance(v, dict) and len(v) > max_vault:
            keep = dict(list(v.items())[-max_vault:]); trimmed["vault"] = len(v) - len(keep)
            self.congress.vault = keep
        # value-dense: a proven rule and an unparsed paragraph should NOT cost the
        # same. In bulky raw entries, replace heavy fields (reading spectra, node
        # lists, scansion) with a digest while keeping the lightweight summary +
        # provenance. Laws, generators and domain summaries live elsewhere — untouched.
        import json as _vj
        if isinstance(getattr(self.congress, "vault", None), dict):
            for h, payload in list(self.congress.vault.items()):
                if not isinstance(payload, dict):
                    continue
                if len(_vj.dumps(payload, default=str)) <= max_bytes:
                    continue
                newp, pruned_any = {}, False
                for k, val in payload.items():
                    if isinstance(val, (list, dict)) and len(_vj.dumps(val, default=str)) > 200:
                        newp[k] = {"digest": org_sha(val)[:16],
                                   "n": (len(val) if hasattr(val, "__len__") else 0), "pruned": True}
                        pruned_any = True
                    else:
                        newp[k] = val
                if pruned_any:
                    self.congress.vault[h] = newp
                    trimmed["node_graphs_pruned"] += 1
        bl = getattr(self.congress.bank, "ledger", [])
        if isinstance(bl, list) and len(bl) > max_ledger:
            trimmed["ledger"] = len(bl) - max_ledger; self.congress.bank.ledger = bl[-max_ledger:]
        cc = getattr(self.congress.crystal, "cells", {})
        if isinstance(cc, dict) and len(cc) > max_crystal_cells:
            items = list(cc.items())[-max_crystal_cells:]; trimmed["crystal_cells"] = len(cc) - len(items)
            self.congress.crystal.cells = defaultdict(list, dict(items))
        if len(g["history"]) > max_history:
            trimmed["history"] = len(g["history"]) - max_history; g["history"] = g["history"][-max_history:]
        self.congress.seal()
        after = self.memory_tiers()
        return {"before": before, "after": after, "trimmed": trimmed,
                "integral_laws_kept": len(g["laws"]), "domains_kept": len(self.domains.domains),
                "note": "raw bulk trimmed; integral generators, domains, balances, and the "
                        "owner-signed provenance root are kept — the distilled core."}

    # =====================================================================
    #  SELF-GROWTH (bounded). Three tiers, ordered by how far they reach:
    #    1) grow_concepts   — new ideas from ALREADY-VERIFIED laws (Congress only)
    #    2) propose_change  — a code patch to ITSELF, quarantined, never auto-applied
    #    3) apply_proposal  — applies a patch ONLY if a reversible checkpoint is taken
    #                         AND the proposed file still passes selftest GREEN; the
    #                         autonomous path is gated behind CHIRON_ALLOW_SELF_EDIT=1.
    #  Nothing is ever removed without a backup; nothing sticks unless it stays green.
    # =====================================================================
    def grow_concepts(self) -> Dict[str, Any]:
        """Tier 1 — grow new concepts from PROVEN structure only. A generator family
        verified in two or more distinct domains becomes a named cross-domain
        CONCEPT. Derived solely from verified laws, so the organism grows its own
        ideas without inventing anything unproven (it cannot run off 'buck wild')."""
        g = self._growth_state()
        minted = []
        for fam, doms in self._fam_domain_sets.items():
            ds = sorted(d for d in doms if d)
            if len(ds) >= 2 and fam not in self.concepts:
                law = next((l for l in g["laws"] if l.get("family") == fam), {})
                c = {"name": "concept:" + str(fam), "family": fam, "domains": ds,
                     "model_class": law.get("model_class"), "owner": OWNER,
                     "kind": "cross-domain-invariant"}
                self.concepts[fam] = c; minted.append(c)
        self.congress.seal()
        return {"concepts_total": len(self.concepts), "newly_minted": len(minted), "minted": minted}

    def self_growth_state(self) -> Dict[str, Any]:
        self._growth_state()
        multi = sum(1 for v in self._fam_domain_sets.values() if len({d for d in v if d}) >= 2)
        return {"concepts": len(self.concepts),
                "concept_names": [c["name"] for c in self.concepts.values()][:50],
                "families_multi_domain": multi,
                "minted_organisms": len(self.self_mod.history),
                "self_edit_enabled": os.environ.get("CHIRON_ALLOW_SELF_EDIT") == "1"}

    def propose_change(self, summary: str, new_source: str, target: str = "chiron.py",
                       directory: str = "proposals") -> Dict[str, Any]:
        """Tier 2 — write a proposed change to ITSELF into a quarantine folder. This
        only records the proposal; it is NEVER applied here. Review + apply is a
        separate, gated step."""
        import hashlib, time as _t
        os.makedirs(directory, exist_ok=True)
        sha = hashlib.sha256(new_source.encode("utf-8")).hexdigest()
        pid = _t.strftime("%Y%m%d-%H%M%S") + "-" + sha[:8]   # content-unique: no same-second collisions
        proposed_path = os.path.join(directory, pid + ".proposed")
        with open(proposed_path, "w", encoding="utf-8") as f:
            f.write(new_source)
        manifest = {"id": pid, "summary": summary, "target": target, "sha256": sha,
                    "proposed_path": proposed_path, "status": "proposed", "owner": OWNER,
                    "created": _t.strftime("%Y-%m-%dT%H:%M:%S")}
        with open(os.path.join(directory, pid + ".json"), "w", encoding="utf-8") as f:
            json.dump(manifest, f, indent=2)
        self.self_mod.history.append({"action": "self-proposal", "id": pid, "summary": summary})
        return manifest

    def list_proposals(self, directory: str = "proposals") -> List[Dict[str, Any]]:
        import glob as _glob
        out = []
        for m in sorted(_glob.glob(os.path.join(directory, "*.json"))):
            try:
                out.append(json.load(open(m, "r", encoding="utf-8")))
            except Exception:
                pass
        return out

    def apply_proposal(self, proposal_id: str, directory: str = "proposals",
                       autonomous: bool = False) -> Dict[str, Any]:
        """Tier 2/3 — apply a proposed self-change, but ONLY if it is safe:
          (a) autonomous application requires CHIRON_ALLOW_SELF_EDIT=1 (off by default),
          (b) the proposed file must pass its OWN selftest GREEN in a clean subprocess,
          (c) the current target is backed up first, so every change is reversible.
        A change that would break the organism, or remove its ability to reject, never
        sticks. This is self-growth that cannot take anything away."""
        import shutil, subprocess, time as _t
        if autonomous and os.environ.get("CHIRON_ALLOW_SELF_EDIT") != "1":
            return {"applied": False, "reason": "autonomous self-edit disabled "
                    "(set CHIRON_ALLOW_SELF_EDIT=1 to enable)"}
        man_path = os.path.join(directory, proposal_id + ".json")
        if not os.path.exists(man_path):
            return {"applied": False, "reason": "no such proposal: " + proposal_id}
        man = json.load(open(man_path, "r", encoding="utf-8"))
        proposed = man.get("proposed_path"); target = man.get("target", "chiron.py")
        if not (proposed and os.path.exists(proposed)):
            return {"applied": False, "reason": "proposed source missing"}
        # (b) GATE: the proposed file must stay GREEN
        try:
            r = subprocess.run([sys.executable, proposed, "selftest"],
                               capture_output=True, text=True, timeout=600)
        except Exception as e:
            return {"applied": False, "reason": "could not run proposed selftest: %s" % e}
        green = (r.returncode == 0) and ("GREEN" in (r.stdout + r.stderr))
        if not green:
            man["status"] = "rejected-selftest-red"
            json.dump(man, open(man_path, "w"), indent=2)
            self.self_mod.history.append({"action": "self-edit-REJECTED", "id": proposal_id})
            return {"applied": False, "reason": "proposed change is not GREEN — refused",
                    "output_tail": (r.stdout or r.stderr or "")[-400:]}
        # (c) REVERSIBLE: back up the live target, then apply
        here = os.path.dirname(os.path.abspath(__file__))
        tgt = target if os.path.isabs(target) else os.path.join(here, target)
        backup = os.path.join(directory, proposal_id + ".backup")
        if os.path.exists(tgt):
            shutil.copyfile(tgt, backup)
        shutil.copyfile(proposed, tgt)
        man["status"] = "applied"; man["backup"] = backup
        man["applied_at"] = _t.strftime("%Y-%m-%dT%H:%M:%S")
        json.dump(man, open(man_path, "w"), indent=2)
        self.self_mod.history.append({"action": "self-edit-APPLIED", "id": proposal_id,
                                      "target": target, "backup": backup})
        return {"applied": True, "target": target, "backup": backup,
                "note": "applied only because selftest stayed GREEN; backup kept for rollback"}

    def rollback_proposal(self, proposal_id: str, directory: str = "proposals") -> Dict[str, Any]:
        """Restore the target file from the backup an apply_proposal left behind."""
        import shutil
        man_path = os.path.join(directory, proposal_id + ".json")
        if not os.path.exists(man_path):
            return {"rolled_back": False, "reason": "no such proposal"}
        man = json.load(open(man_path, "r", encoding="utf-8"))
        backup = man.get("backup"); target = man.get("target", "chiron.py")
        if not (backup and os.path.exists(backup)):
            return {"rolled_back": False, "reason": "no backup to restore"}
        here = os.path.dirname(os.path.abspath(__file__))
        tgt = target if os.path.isabs(target) else os.path.join(here, target)
        shutil.copyfile(backup, tgt)
        man["status"] = "rolled-back"; json.dump(man, open(man_path, "w"), indent=2)
        self.self_mod.history.append({"action": "self-edit-ROLLED-BACK", "id": proposal_id})
        return {"rolled_back": True, "target": target}

    def memory_tiers(self) -> Dict[str, int]:
        """Tiered memory so the Congress stays portable as it grows: raw items ->
        compressed library parts -> verified invariants -> unique generators."""
        g = self._growth_state(); cd = self.congress.state()
        return {"raw": cd.get("vault_items", 0), "compressed": len(self.congress.library),
                "invariant": g["integral"], "generator": len(self._gen_seen)}

    def assimilate(self, text: str, source: str = "ingest", author: str = "unknown",
                   domain_hint: Optional[str] = None) -> Dict[str, Any]:
        """The full consume-and-grow cycle: standardize -> certify -> read the
        structure -> auto-form/extend a domain -> classify integral vs general and
        track growth -> carry the author -> speak it back through its invariant ->
        render a stakeholder certificate -> report where it stands."""
        rec = self.ingest_text(text, source=source)
        out = self.process_record(rec)
        try:
            inv = self._engine_read(text)
        except Exception:
            inv = None
        structural = (self._DOMAIN_LABELS.get(getattr(inv, "domain", None), getattr(inv, "domain", None))
                      if inv is not None else None) or (getattr(rec, "structure_type", None) or "general")
        # A subject hint (e.g. the grower's topic) organizes the Congress by SUBJECT
        # (mathematics, law, biology…) rather than collapsing all prose into one
        # structural bucket. Falls back to the engine's structural read when absent.
        domain = (domain_hint.strip() if isinstance(domain_hint, str) and domain_hint.strip()
                  else structural)
        growth = self._form_domain(rec, name=domain)
        gr = self.record_growth(inv, domain, source, author=author) if inv is not None else {"classification": "general"}
        self._growth_state()                                    # ensure the ingest ledger exists
        if source and source not in self._ingested_set:         # provenance of everything eaten; travels w/ the Congress
            self._ingested_set.add(source); self.ingested_sources.append(source)
        self.congress.seal()
        st = self.state()
        cd = st.get("Congress", {}) if isinstance(st.get("Congress"), dict) else {}
        # true domain total = live this run UNION everything persisted (the summary),
        # so resumed runs report the full count, not just domains touched this session
        all_domains = set(st.get("domains", [])) | set(getattr(self, "_domains_summary", {}))
        gsum = {"domains": len(all_domains), "items": cd.get("vault_items"),
                "minted_organisms": len(self.self_mod.history), "languages": len(st.get("atlas", [])),
                "tiers": self.memory_tiers(), "integral": self.growth["integral"],
                "general": self.growth["general"], "cross_domain_transfers": self.growth["cross_domain"],
                "reuse": self.growth["reuse"], "source_author": author}
        cert_text = _render_certificate(inv, growth, gr, domain, gsum, source, author)
        return {"record_id": rec.rid, "chart": out.get("chart"),
                "structure_type": getattr(rec, "structure_type", None),
                "domain": domain, "structural_domain": structural,
                "growth": growth, "classification": gr.get("classification"),
                "cross_domain_transfer": gr.get("cross_domain_transfer", False),
                "reused": gr.get("reused", False), "source_author": author,
                "human": (human_report(inv) if inv is not None else None),
                "articulation": (articulate(inv) if inv is not None else None),
                "certificate": out.get("certificate"), "certificate_text": cert_text,
                "congress": gsum}

    def articulate(self, text: str, n: int = 12, vocab=None) -> Dict[str, Any]:
        """Push a digested surface back UP through its own invariant — speak it in its
        own language: regenerate + extend, or re-voice the same generator into a new
        vocabulary; report round-trip fidelity; attribute to the source author
        (distinct from the owner who signs the artifact). The inverse of collapse."""
        inv = self._engine_read(text)
        spoken = articulate(inv, n=n, vocab=vocab)
        parts = str(text).replace(",", " ").split()
        try:
            vals = [float(p) for p in parts]; nums = [int(v) if v.is_integer() else v for v in vals]
        except ValueError:
            nums = None
        faithful = None
        if nums is not None:
            try:
                rt = list(inv.predict(len(nums))); faithful = (rt[:len(nums)] == nums)
            except Exception:
                faithful = None
        spoken["round_trip_faithful"] = faithful
        dom = self._DOMAIN_LABELS.get(getattr(inv, "domain", None), getattr(inv, "domain", None))
        spoken["source_author"] = self._growth_state() and self.authors.get(dom, "unknown")
        spoken["owner"] = OWNER
        return spoken

    @staticmethod
    def _cycle_summary(r: CycleResult) -> Dict[str, Any]:
        return {"cycle": r.cycle_index, "leader": r.leader, "roles": r.roles,
                "contributions": r.n_contributions,
                "committed": len(r.committed), "published": len(r.published),
                "escalations": r.escalations}

    # --- the human pull (the ONLY outbound crossing) -------------------------
    def pull_reports(self) -> List[Dict[str, Any]]:
        return [{"aid": a.aid, "kind": a.kind, "content": a.content}
                for a in self.well.pull()]

    # --- portability: save/load the single memory file (L3) ------------------
    def save_memory(self, path: str) -> str:
        doc = self.congress.to_portable()
        g = self._growth_state()
        doc["growth"] = g
        doc["growth_gen_seen"] = sorted(self._gen_seen)
        doc["growth_fam_domains"] = dict(self._fam_domains)
        doc["domains_summary"] = {nm: {"exemplars": getattr(fp, "n_exemplars", 0),
                                       "charts": list(getattr(fp, "chart_names", []))}
                                  for nm, fp in self.domains.domains.items()}
        doc["membranes"] = dict(getattr(self, "membranes", {}))
        doc["authors"] = dict(getattr(self, "authors", {}))
        doc["ingested_sources"] = list(getattr(self, "ingested_sources", []))
        doc["concepts"] = dict(getattr(self, "concepts", {}))
        doc["growth_fam_domain_sets"] = {k: sorted(v) for k, v in getattr(self, "_fam_domain_sets", {}).items()}
        with open(path, "w", encoding="utf-8") as f:
            json.dump(doc, f, sort_keys=True, ensure_ascii=False, indent=0)
        return doc["root"]

    @classmethod
    def load_memory(cls, path: str) -> "Chiron":
        with open(path, "r", encoding="utf-8") as f:
            doc = json.load(f)
        org = cls(memory=Congress.from_portable(doc))
        org.growth = doc.get("growth", {"integral": 0, "general": 0, "cross_domain": 0,
                                        "history": [], "laws": []})
        org._gen_seen = set(doc.get("growth_gen_seen", []))
        org._fam_domains = dict(doc.get("growth_fam_domains", {}))
        org._domains_summary = doc.get("domains_summary", {})
        org.membranes = dict(doc.get("membranes", {}))
        org.authors = dict(doc.get("authors", {}))
        org.ingested_sources = list(doc.get("ingested_sources", []))
        org._ingested_set = set(org.ingested_sources)
        org.concepts = dict(doc.get("concepts", {}))
        org._fam_domain_sets = {k: set(v) for k, v in doc.get("growth_fam_domain_sets", {}).items()}
        org._law_by_gen = {law["generator"]: law for law in org.growth.get("laws", [])}
        return org

    def state(self) -> Dict[str, Any]:
        return {"engines": list(self.engines),
                "atlas": list(self.atlas.langs),
                "Congress": self.congress.state(),
                "congress_memory_pressure": self.congress.memory_pressure(),
                "field_cognition": self.field.state(),
                "domains": list(self.domains.domains),
                "well": {"inbound": len(self.well.inbound),
                         "outbound": len(self.well.outbound)},
                "self_mod_history": len(self.self_mod.history)}


# =============================================================================
#  M30.1 — DETERMINISTIC STANDARDIZER  (replaces the external-LLM standardizer)
#  The intel_standardizer contract, realized IN-PROCESS and deterministically.
#  Raw input -> a three-root Record. No network, no LLM (L5). This is JDICert's
#  intake, rehabilitated off intel-specific semantics.
# =============================================================================

def standardize_to_record(text: str, source: str = "stdin",
                          structure: str = "auto") -> Record:
    """Turn arbitrary text into a three-root Record deterministically.
      - 'wordsquare' : lines of equal length -> a OrgPicture-style figure
      - 'lines'      : each line a node, sequential walk
      - 'tokens'     : whitespace tokens as nodes, sequential walk
      - 'auto'       : org_detect a word-square; else fall back to lines
    Confidence is set by how clean the parse is (honesty: never silently
    'high' on a messy parse)."""
    raw_lines = [ln.rstrip("\n") for ln in text.splitlines() if ln.strip()]
    mode = structure
    if mode == "auto":
        if raw_lines and len({len(ln.replace(" ", "")) for ln in raw_lines}) == 1 \
           and len(raw_lines) == len(raw_lines[0].replace(" ", "")):
            mode = "wordsquare"
        elif raw_lines:
            mode = "lines"
        else:
            mode = "tokens"

    node_ids: List[str] = []
    bearing: Dict[str, Bearing] = {}
    walks: Dict[str, List[str]] = {}

    if mode == "wordsquare":
        words = [ln.replace(" ", "").upper() for ln in raw_lines]
        n = len(words)
        for r in range(n):
            for c in range(len(words[r])):
                nid = f"r{r}c{c}"
                node_ids.append(nid)
                bearing[nid] = Bearing(raw=words[r][c], normalized=words[r][c],
                                       confidence="high", role="cell")
        walks["currens"] = [f"r{r}c{c}" for r in range(n) for c in range(len(words[0]))]
        walks["descendens"] = [f"r{r}c{c}" for c in range(len(words[0])) for r in range(n)]
        st = "wordsquare"
        conf = "high"
    elif mode == "lines":
        for i, ln in enumerate(raw_lines):
            nid = f"L{i}"
            node_ids.append(nid)
            bearing[nid] = Bearing(raw=ln, normalized=ln.strip(),
                                   confidence="med", role="line")
        walks["sequential"] = node_ids[:]
        st = "line-sequence"
        conf = "med"
    else:  # tokens
        toks = text.split()
        for i, tk in enumerate(toks):
            nid = f"t{i}"
            node_ids.append(nid)
            bearing[nid] = Bearing(raw=tk, normalized=tk, confidence="med", role="token")
        walks["sequential"] = node_ids[:]
        st = "token-sequence"
        conf = "med" if toks else "low"

    prov = OrgProvenance(source=source, region=f"mode={mode}", confidence=conf,
                      flags=([] if node_ids else ["empty-input"]))
    rid = org_sha({"text": text[:200], "mode": mode, "source": source})[:12]
    return Record(rid=rid, topology=Topology(node_ids=node_ids, walks=walks),
                  bearing=bearing, provenance=prov, structure_type=st)


# =============================================================================
#  M31 — EMBEDDED TEST GATES  (the honesty + invariant suite, run in-process)
#  Every hard law L1-L9 + L-author has a gate. Plus ported engine gates and the
#  REHABILITATION gate (no prior-domain operational semantics survive). Suite is
#  the anti-tautology guarantee: gates can and do return true negatives.
#  Run: `python3 chiron.py selftest`.
# =============================================================================

class _Gate:
    def __init__(self):
        self.results: List[Tuple[str, bool, str]] = []

    def check(self, name: str, cond: bool, detail: str = "") -> None:
        self.results.append((name, bool(cond), detail))

    def summary(self) -> Tuple[int, int]:
        passed = sum(1 for _, ok, _ in self.results if ok)
        return passed, len(self.results)


def _gate_engine_core(g: _Gate) -> None:
    # --- substrate / ductus / org_detect ---
    pic = sator_fixture()
    g.check("picture rectangular 5x5", pic.nrows == 5 and pic.ncols == 5)
    g.check("currens reads SATOR...", pic.read(org_ductus_path(pic, "currens")).startswith("SATOR"))
    g.check("recurrens is currens reversed",
            pic.read(org_ductus_path(pic, "recurrens")) ==
            pic.read(org_ductus_path(pic, "currens"))[::-1])
    lang = org_latin_wordform_language()
    spec = org_detect(pic, lang)
    g.check("SATOR org_detect finds >=1 reading", spec.cardinality() >= 1)
    g.check("entropy is non-negative", spec.entropy() >= 0.0)

    # --- ANTI-TAUTOLOGY: the gate must be able to REJECT (true negatives) ---
    g.check("wordform gate rejects digits", not lang.admits("12345"))
    g.check("wordform gate rejects empty", not lang.admits(""))
    hexm = org_latin_meter_language()
    g.check("hexameter gate rejects gibberish line", not hexm.admits("X"))
    pysyn = python_syntax_language()
    g.check("python gate admits 'a = 1'", pysyn.admits("a = 1"))
    g.check("python gate rejects 'def ('", not pysyn.admits("def ("))
    bal = balanced_delimiters_language()
    g.check("balanced gate admits '(())'", bal.admits("(())"))
    g.check("balanced gate rejects '(()'", not bal.admits("(()"))

    # --- resolve provably reduces |Sigma| ---
    fg = tab_xiii_fixture()
    spec2 = org_detect(fg, org_latin_wordform_language())
    if spec2.cardinality() >= 1:
        m = OrgResolutionMorphology()
        target, t = org_resolve_commit(spec2, morphology=m)
        g.check("resolve reduces to one reading", len(t.after_distinct) == 1)
        g.check("resolve cost = competitors removed",
                t.cost == max(0, len(t.before_distinct) - 1))

    # --- morphology calculus: monoid identity + metric ---
    m = OrgResolutionMorphology()
    idt = m.identity()
    t_demo = OrgTransformation(["a", "b"], ["a"], "commit->a", 1, {"method": "commit"})
    g.check("compose with identity is identity-left", m.compose(idt, t_demo) is t_demo)
    g.check("distance to self is 0", m.distance(t_demo, t_demo) == 0.0)

    # --- signature JSD bounds ---
    s1 = OrgSignature.from_spectra("a", [spec])
    s2 = OrgSignature.from_spectra("b", [spec])
    g.check("JSD of identical spectra ~ 0", s1.jsd(s2) < 1e-9)
    g.check("JSD is non-negative", s1.jsd(s2) >= 0.0)


def _gate_invariants(g: _Gate) -> None:
    org = Chiron()

    # --- L-author: author signature changes every hash ---
    h1 = org_sha({"x": 1})
    _self = (sys.modules.get("chiron") or sys.modules.get("chiron")
             or sys.modules["__main__"])  # name-agnostic self-ref
    g.check("L-author: author bound into org_sha (deterministic)", h1 == org_sha({"x": 1}))
    g.check("L-author: AUTHOR_SIGNATURE present in manifest render",
            AUTHOR_SIGNATURE in org.congress.manifest.render())

    # --- L6 determinism: same input -> same manifest root ---
    rec = standardize_to_record("SATOR\nAREPO\nTENET\nOPERA\nROTAS", source="t")
    a = Chiron(); ra = a.process_record(rec); root_a = a.congress.manifest.digest()
    b = Chiron(); rb = b.process_record(rec); root_b = b.congress.manifest.digest()
    g.check("L6 determinism: identical certificates",
            ra["certificate"]["merkle_root"] == rb["certificate"]["merkle_root"])
    g.check("L6 determinism: identical manifest roots", root_a == root_b)

    # --- L2 routing: every artifact goes to well or Congress, never elsewhere ---
    art_h = Artifact.make("test", {"x": 1}, [("Infectatrum", "leader", 1.0)],
                          human_facing=True)
    art_b = Artifact.make("test", {"x": 1}, [("Infectatrum", "leader", 1.0)],
                          human_facing=False)
    g.check("L2 human-facing -> well", art_h.destination() == WELL)
    g.check("L2 non-human -> memory", art_b.destination() == CONGRESS)

    # --- L1 membrane: only human-facing artifacts can be staged at the well ---
    tank = HoldingTank()
    staged_ok = True
    try:
        tank.stage(art_b)   # must raise: non-human artifact cannot cross the well
        staged_ok = False
    except ValueError:
        staged_ok = True
    g.check("L1 membrane: non-human artifact rejected at well", staged_ok)
    tank.stage(art_h)
    g.check("L1 membrane: human artifact stages, pulled by human",
            len(tank.pull()) == 1)

    # --- L3 single store: portable round-trip is lossless ---
    root_before = a.congress.seal()
    doc = a.congress.to_portable()
    restored = Congress.from_portable(doc)
    g.check("L3 portable round-trip preserves root",
            restored.seal() == root_before)
    g.check("L3 portable carries author + license",
            doc["author"] == AUTHOR_SIGNATURE and "LICENSE" in doc["license"].upper() or
            "Proprietary" in doc["license"])

    # --- L5 no network: assert no socket/urllib import path is used by core ---
    src = ""
    try:
        with open(__file__, "r", encoding="utf-8") as f:
            src = f.read()
    except Exception:
        pass
    if src:
        # PRESIDENT is the one deliberately network-capable component: isolated
        # in its own module, OFF unless PRESIDENT_ALLOW_NETWORK=1, action set
        # bounded by construction. The core-offline guarantee is measured over
        # the CORE -- the whole file EXCEPT the President submodule source --
        # so excise that block before scanning. (Cutting it is what proves the
        # honest claim; hiding it, as a base64 blob would, is what we refuse.)
        _pdef = "def _build_presi" + "dent_module():"
        _pend = "_sys.mod" + 'ules["president"] = president'
        if _pdef in src:
            _i = src.index(_pdef)
            _j = src.index(_pend, _i) + len(_pend)
            src = src[:_i] + src[_j:]
        # build probe strings from fragments so the GATE's own source does not
        # trip the check (the check must measure the engine, not itself).
        _imp = "im" + "port "
        g.check("L5 no-network: no socket import (core)", (_imp + "soc" + "ket") not in src)
        g.check("L5 no-network: no requests import (core)", (_imp + "requ" + "ests") not in src)
        g.check("L5 no-network: no urllib request open (core)",
                ("url" + "lib.req" + "uest") not in src and ("url" + "open") not in src)
        g.check("L5 no-network: no http client (core)", ("ht" + "tp.cli" + "ent") not in src)

    # --- L7 provenance: certificate is Merkle-bound + provenance carried ---
    g.check("L7 provenance: certificate has merkle_root",
            bool(ra["certificate"].get("merkle_root")))
    g.check("L7 provenance: confidence propagated",
            ra["certificate"]["confidence"] in ("high", "med", "low", "n/a"))

    # --- L8 self-mod discipline: a degenerate mint that admits everything is REJECTED ---
    sm = org.self_mod
    bad = MintProposal("BAD", "grammar", "", spec={})  # empty grammar = degenerate
    ok, reasons = sm._validate(bad)
    g.check("L8 self-mod: degenerate grammar rejected",
            (not ok) and any(("admits everything" in r) or ("did not compile" in r)
                             for r in reasons))
    good = MintProposal("GOOD-CHART", "chart", "sig123", spec={"base": "balanced-delims"})
    ok2, _ = sm._validate(good)
    g.check("L8 self-mod: well-formed chart validates", ok2)

    # --- L4 single script: capability growth is data, not generated .py ---
    sm.submit_mint({"name": "MINT-DELIM", "kind": "chart",
                    "spec": {"base": "balanced-delims"}, "signature": "s"}, None)
    rows = sm.process_pending()
    g.check("L4 single-script: minted unit lands in library (data), not a file",
            "MINT-DELIM" in org.congress.library)
    g.check("L4 single-script: minted chart loaded into live atlas",
            "MINT-DELIM" in org.atlas.langs)


def _gate_rehabilitation(g: _Gate) -> None:
    """The binding rehabilitation rule: NO prior-domain operational semantics survive
    anywhere in the program text or in any runtime artifact."""
    # banned terms are assembled from fragments so this GATE's own source does
    # not trip the check — the check must measure the rest of the engine.
    banned = ["war" + "fare", "wea" + "pon", "muni" + "tion", "kill " + "chain",
              "mis" + "sile", "comba" + "tant", "letha" + "lity",
              "engage " + "target", "fir" + "ing", "stri" + "ke package",
              "target " + "coordinate"]
    src = ""
    try:
        with open(__file__, "r", encoding="utf-8") as f:
            src = f.read().lower()
    except Exception:
        pass
    if src:
        for term in banned:
            g.check(f"rehab: prior-domain term #{banned.index(term)} absent from program",
                    term not in src,
                    detail="prior-domain operational framing must be fully stripped")
    # the world-model set must be the general one
    wms = org_init_general_world_models()
    roles = set(wms.names())
    g.check("rehab: world-models are general stakeholders",
            roles == {"Proponent", "Skeptic", "AffectedParty", "Steward",
                      "LongHorizon", "AdversarialStress"})
    # perturbations carry no operational-domain semantics
    perts = {p.kind for p in org_build_general_perturbations()}
    g.check("rehab: perturbations are general robustness stressors",
            perts == {"data_drift", "assumption_violation", "scope_shift",
                      "resource_shock", "source_retraction", "adversarial_input"})


def _gate_certification(g: _Gate) -> None:
    pic = sator_fixture()
    lang = org_latin_wordform_language()

    # K/U/Omega + truth horizon
    part = partition_from_engine(pic, lang)
    theta = part.truth_horizon()
    g.check("truth horizon finite & bounded", 0.0 <= theta <= 100.0)
    g.check("truth horizon does not explode when U all escalated",
            partition_from_engine(tab_xiii_fixture(), lang).truth_horizon() <= 100.0)

    # operator algebra: Measure resolves an ignorance unknown
    u = OrgUnknown("u1", "node is ambiguous", OrgMysteryClass.XI_IGNORANCE)
    rs = reduce_unknown(u, part)
    g.check("Measure resolves ignorance", any(r.outcome == "RESOLVED" for r in rs))
    # Dialogue escalates a subjective unknown (value-laden)
    u2 = OrgUnknown("u2", "this is a subjective value judgment", OrgMysteryClass.XI_SUBJECTIVITY)
    rs2 = reduce_unknown(u2, part, operator_sequence=["Measure", "Dialogue"])
    g.check("Dialogue escalates subjectivity", any(r.outcome == "ESCALATED" for r in rs2))

    # non-commutativity demonstration (order changes outcome set)
    pa = partition_from_engine(pic, lang)
    ua = OrgUnknown("ua", "apparent contradiction in frame", OrgMysteryClass.XI_PARADOX)
    seq1 = [r.outcome for r in reduce_unknown(ua, pa, ["Reframe", "Measure"])]
    pb = partition_from_engine(pic, lang)
    ub = OrgUnknown("ub", "apparent contradiction in frame", OrgMysteryClass.XI_PARADOX)
    seq2 = [r.outcome for r in reduce_unknown(ub, pb, ["Measure", "Reframe"])]
    g.check("operator algebra is non-commutative (order matters)",
            seq1 != seq2 or seq1[0] != seq2[0])

    # world-model survival + counterfactual + red-team run and are well-formed
    cert = run_certification(pic, lang, prov=OrgProvenance(confidence="high"))
    g.check("certificate has all subsystems",
            all(k in cert for k in ("truth_horizon", "world_model_survival",
                "counterfactual_robustness", "red_team", "adversarial_assessment",
                "merkle_root", "org_novelty_index", "org_mental_free_energy")))
    g.check("certificate escalation flag is boolean",
            isinstance(cert["escalation_required"], bool))

    # LexGuard math sanity
    g.check("margin map: larger constraint value -> larger margin",
            org_margin_map(2.0, 1.0) > org_margin_map(1.0, 1.0))
    g.check("composite Lyapunov detects monotone decrease",
            org_composite_lyapunov([3.0, 2.0, 1.0])["contracting"])
    g.check("composite Lyapunov flags an increase",
            not org_composite_lyapunov([1.0, 2.0])["contracting"])
    g.check("HJI saddle favors robust when angel>devil",
            hji_saddle_value(2.0, 1.0)["favors"] == "robust")
    g.check("calibration separates populations",
            calibrate_threshold([0.8, 0.9], [0.1, 0.2])["separated"])
    gi = org_gap_interval(1.0, 0.1, 0.2)
    g.check("gap interval width = |lower|+|upper|", abs(gi["width"] - 0.3) < 1e-9)

    # Calculus of value + free energy + UMA dynamics
    g.check("value of information positive for real gain",
            value_of_information(1.0, 0.1, 1.0) > 0)
    g.check("novelty index in [0,1+]", org_novelty_index({"a": 1.0}, []) >= 0)
    g.check("mental free energy = surprise - T*entropy",
            abs(org_mental_free_energy(2.0, 1.0, 1.0) - 1.0) < 1e-9)
    fs = FieldState(value=1.0, flux=0.0)
    stepped = org_maxwell_cattaneo_step(fs, dt=0.1)
    g.check("Cattaneo step advances time", stepped.t > fs.t)
    g.check("cone aperture is finite", org_cone_aperture(stepped) >= 0.0)


def _gate_organism(g: _Gate) -> None:
    org = Chiron()

    # ingest -> process -> publish -> pull (the full membrane round-trip)
    rec = org.ingest_text("SATOR\nAREPO\nTENET\nOPERA\nROTAS", source="selftest")
    g.check("ingest yields a three-root record", isinstance(rec, Record))
    g.check("record reduces to three roots",
            hasattr(rec, "topology") and hasattr(rec, "bearing") and hasattr(rec, "provenance"))
    out = org.process_record(rec)
    g.check("process returns a certificate", "certificate" in out)
    g.check("at least one cycle ran", out["cycles_run"] >= 1)
    reports = org.pull_reports()
    g.check("a human-facing report was published and pulled", len(reports) >= 1)
    g.check("only the certifier authored the published report",
            all(r["kind"].startswith("JDICert") for r in reports))

    # the cycle rotates leadership by orientation (not fixed rank)
    leaders_seen = {c["leader"] for c in out["cycle_trace"]}
    g.check("leadership is assigned by orientation", len(leaders_seen) >= 1)

    # the bank accrued capital (economics codifies power)
    g.check("bank accrued process-ownership capital",
            sum(org.congress.bank.capital.values()) > 0)

    # the crystal accumulated structural memory
    g.check("crystal accumulated deposits",
            org.congress.crystal.state()["n_deposits"] > 0)

    # value-ledger presider gates an over-threshold expenditure
    presider = org.presidency.presider
    big = presider.approve("Infectatrum", "Chiron", 999.0, "huge sim")
    g.check("presider denies unfunded over-threshold expenditure", big is False)

    # Chiron envelope: twins characterize (not enumerate) a large space
    tw = org.envelope.twin_paths(tab_xiii_fixture(), tab_xiii_fixture(),
                                 org_latin_wordform_language())
    g.check("twins report magnitude, held not enumerated",
            tw["held_not_enumerated"] and "joint_magnitude" in tw)

    # domain retention: internalize two domains, get a variance map
    org.domains.internalize("latin", [(sator_fixture(), org_latin_wordform_language())])
    org.domains.internalize("code", [(standardize_to_record("a = 1\nb = 2").topology and
                                       substrate_from_record(standardize_to_record("a = 1\nb = 2")),
                                       python_syntax_language())])
    vm = org.domains.variance_map()
    g.check("domain variance map is square + diagonal ~0",
            "latin" in vm and abs(vm["latin"]["latin"]) < 1e-9)

    # portability: save + reload the single memory file, root preserved
    import tempfile
    tmp = os.path.join(tempfile.gettempdir(), "chiron_selftest_mem.json")
    root = org.save_memory(tmp)
    reloaded = Chiron.load_memory(tmp)
    g.check("memory file reloads with identical root",
            reloaded.congress.seal() == root)
    try:
        os.remove(tmp)
    except OSError:
        pass


def _gate_urf_and_field(g: _Gate) -> None:
    # --- URF ontology ---
    H = HarmonyFunctional(benefit=lambda u: 10.0, burden=lambda u: 3.0,
                          safety_tax=lambda u: 2.0)
    g.check("URF harmony H = benefit-burden-tax", abs(H.H(None) - 5.0) < 1e-9)
    g.check("URF free energy = -H", abs(H.free_energy(None) + 5.0) < 1e-9)
    rep = urf_axioms_report(True, True, True, 0.73, 1.0, 2.0)
    g.check("URF axioms A1-A4 satisfied for valid instantiation", rep["all_satisfied"])
    g.check("URF A5 regime switch (cone>2c_diff => generative)",
            rep["A5_anosov_closure"] and rep["regime"].startswith("chaotic"))
    rep_contract = urf_axioms_report(True, True, True, 0.73, 1.0, 1.0)
    g.check("URF contracting regime when cone<=2c_diff",
            not rep_contract["A5_anosov_closure"])

    # --- URF economy: harmony approves good, the wall denies reckless ---
    bk = Bank(); bk.credit("E", "leader", "a", 10.0)
    econ = URFEconomy(bk)
    good = econ.evaluate_expenditure("E", 2.0, 5.0, "beneficial")
    bad = econ.evaluate_expenditure("E", 9.9, 0.5, "reckless")
    g.check("URF economy approves modest beneficial expenditure", good["harmonic"])
    g.check("URF economy denies near-wall low-benefit expenditure", not bad["harmonic"])
    g.check("URF economic wall tax diverges toward saturation",
            econ.safety_tax(0.99) > 5 * econ.safety_tax(0.5))

    # --- presider uses URF: unfunded over-threshold denied; funded harmonic ok ---
    org = Chiron()
    org.congress.bank.credit("Infectatrum", "leader", "seed", 50.0)
    pres = org.presidency.presider
    g.check("presider denies unfunded over-threshold (URF)",
            pres.approve("Infectatrum", "Chiron", 999.0, "too big") is False)
    g.check("presider approves funded harmonic expenditure",
            pres.approve("Infectatrum", "Chiron", 6.0, "good", expected_benefit=20.0) is True)

    # --- field cognition (numpy-gated; honest when absent) ---
    if field_layer_available():
        result = org.field.think("the calculus of value")
        fc = result.get("field_cognition")
        g.check("field cognition returns a structured result", isinstance(fc, dict))
        if isinstance(fc, dict):
            g.check("field reports both faces of the origin",
                    "friction_closed" in fc and "einstein_satisfied" in fc)
            g.check("field sphere geometry is Bessel-exact (j01=pi)",
                    abs(fc["sphere_geometry"]["bessel_zero"] - math.pi) < 1e-9)
            g.check("field cognition is deterministic (same text -> same closure)",
                    org.field.pipeline.run("x").omega ==
                    org.field.pipeline.run("x").omega)
        g.check("memory records pressure from cognition",
                org.congress.memory_saturation >= 0.0)
    else:
        g.check("field layer absent -> honest unavailable marker",
                org.field.think("x").get("field_cognition") == "unavailable")


def run_selftest(verbose: bool = True) -> bool:
    g = _Gate()
    _gate_engine_core(g)
    _gate_invariants(g)
    _gate_rehabilitation(g)
    _gate_certification(g)
    _gate_organism(g)
    _gate_urf_and_field(g)
    passed, total = g.summary()
    if verbose:
        for name, ok, detail in g.results:
            mark = "PASS" if ok else "FAIL"
            line = f"  [{mark}] {name}"
            if not ok and detail:
                line += f"  -- {detail}"
            print(line)
        print(f"\n  {passed}/{total} gates passed.")
        if passed == total:
            print("  ALL GATES GREEN — organism is offline, deterministic, "
                  "rehabilitated, and honest.")
    return passed == total


# =============================================================================
#  M32 — CLI + main()  (the "run in a folder" entrypoint)
#  Sufficient on any shell:  python3 chiron.py run <folder>
#  Ingests every file in the folder through the well, runs the organism, and
#  publishes a single human-facing Intelligence Report (what it returns).
#  Other verbs: selftest, demo, attest, ingest, state.
# =============================================================================

def _read_text_file(path: str) -> Optional[str]:
    """Read a file as text for ingestion. Binary files (PDF, docx, images,
    .DS_Store, archives) are detected by a NUL byte and skipped; any residual
    NUL/noise is stripped so no downstream parser can be crashed by raw bytes."""
    try:
        with open(path, "rb") as f:
            raw = f.read()
    except OSError:
        return None
    if b"\x00" in raw:                       # binary content -> not ingestible as text
        return None
    try:
        text = raw.decode("utf-8", errors="replace")
    except Exception:
        return None
    return text.replace("\x00", "")          # defensive: never hand NUL bytes onward


def cmd_run(folder: str = ".", memory_path: Optional[str] = None,
            chart: Optional[str] = None) -> int:
    """Ingest every file in <folder>, run the organism, publish ONE report."""
    if not os.path.isdir(folder):
        print(f"error: not a directory: {folder}", file=sys.stderr)
        return 2

    org = (Chiron.load_memory(memory_path)
           if memory_path and os.path.exists(memory_path) else Chiron())

    # ingest the ENTIRE tree (whole systems/workflows), skipping hidden dirs/files;
    # binary files are filtered downstream by _read_text_file.
    files = []
    for _root, _dirs, _fs in os.walk(folder):
        _dirs[:] = [d for d in _dirs if not d.startswith(".")]
        for _f in _fs:
            if not _f.startswith("."):
                files.append(os.path.join(_root, _f))
    files = sorted(files)
    ingested: List[Dict[str, Any]] = []
    per_file_certs: List[Dict[str, Any]] = []

    for path in files:
        text = _read_text_file(path)
        if text is None:
            ingested.append({"file": os.path.basename(path), "status": "skipped (binary/unreadable)"})
            continue
        # special-case the transcribed corpus -> full corpus ingestion pipeline
        if os.path.basename(path) == "corpus_all.json":
            res = org.envelope.ingest_corpus(path)
            ingested.append({"file": os.path.basename(path),
                             "status": f"corpus pipeline: {res.get('plates_ingested', 0)} plates"})
            continue
        rec = org.ingest_text(text, source=os.path.basename(path))
        out = org.process_record(rec, language=chart)
        try:
            inv = org._engine_read(text)
            dname = org._DOMAIN_LABELS.get(getattr(inv, "domain", None),
                                           getattr(inv, "domain", None)) or (rec.structure_type or "general")
        except Exception:
            inv, dname = None, (rec.structure_type or "general")
        dom = org._form_domain(rec, name=dname)
        if inv is not None:
            try: org.record_growth(inv, dname, source=os.path.basename(path))
            except Exception: pass
        ingested.append({"file": os.path.basename(path),
                         "record_id": rec.rid,
                         "structure_type": rec.structure_type,
                         "chart": out["chart"],
                         "cycles": out["cycles_run"],
                         "domain": dom.get("domain")})
        per_file_certs.append({"file": os.path.basename(path),
                               "certificate": out["certificate"]})
        # incremental sealing for very large corpora (streaming-friendly)
        if memory_path and len(ingested) % 25 == 0:
            try: org.save_memory(memory_path)
            except Exception: pass

    # JDICert publishes ONE consolidated Intelligence Report to the well
    reports = org.pull_reports()
    root = org.congress.seal()

    # aggregate escalations + robustness across the folder
    escalated = [c["file"] for c in per_file_certs
                 if c["certificate"].get("escalation_required")]
    consolidated = {
        "chiron_intelligence_report": True,
        "author": AUTHOR_SIGNATURE,
        "license": LICENSE_LINE,
        "folder": folder,
        "files_ingested": ingested,
        "n_documents_certified": len(per_file_certs),
        "per_document_certificates": per_file_certs,
        "documents_requiring_escalation": escalated,
        "organism_state": org.state(),
        "attestation_root": root,
    }

    if memory_path:
        saved_root = org.save_memory(memory_path)
        consolidated["memory_saved_to"] = memory_path
        consolidated["memory_root"] = saved_root

    print(json.dumps(consolidated, indent=2, ensure_ascii=False, default=str))
    return 0


