def build_arg_parser() -> argparse.ArgumentParser:
    p = argparse.ArgumentParser(
        prog="chiron",
        description="Chiron Intelligence Program — a portable, offline, "
                    "deterministic symbolic-AI organism. (c) Jacob Iannotti, 2026.")
    sub = p.add_subparsers(dest="command")

    pr = sub.add_parser("run", help="ingest every file in a folder; publish ONE report")
    pr.add_argument("folder", nargs="?", default=".",
                    help="folder of files to ingest (default: the current folder)")
    pr.add_argument("--memory", default=None, help="path to a chiron_memory.json to load/save")
    pr.add_argument("--chart", default=None, help="force a chart/language (else inferred)")

    sub.add_parser("selftest", help="run the embedded invariant + honesty gate suite")
    sub.add_parser("demo", help="run a self-contained demonstration")

    pa = sub.add_parser("attest", help="print the attestation manifest + root")
    pa.add_argument("--memory", default=None)

    pi = sub.add_parser("ingest", help="ingest a single string and certify it")
    pi.add_argument("text", help="the text to ingest")

    sub.add_parser("state", help="print the organism's current state")
    return p


def main(argv: Optional[List[str]] = None) -> int:
    args = build_arg_parser().parse_args(argv)
    if args.command == "run":
        return cmd_run(args.folder, memory_path=args.memory, chart=args.chart)
    if args.command == "selftest":
        return 0 if run_selftest(verbose=True) else 1
    if args.command == "demo":
        return cmd_demo()
    if args.command == "attest":
        return org_cmd_attest(memory_path=args.memory)
    if args.command == "ingest":
        return cmd_ingest(args.text)
    if args.command == "state":
        return cmd_state()
    # default: brief banner + selftest summary
    print(f"Chiron Intelligence Program v{__version__}")
    print(f"{AUTHOR_SIGNATURE}")
    print(f"{LICENSE_LINE}")
    print("\nUsage: python3 chiron.py {run <folder> | selftest | demo | "
          "attest | ingest <text> | state}")
    print("\nRunning embedded self-test...\n")
    ok = run_selftest(verbose=True)
    return 0 if ok else 1



