# =============================================================================
#  U1 — ACOUSTIC SPHERE GEOMETRY  [ported from geometry.py]
#  Everything is derived from the sphere outward; nothing is tuned. The
#  resonant mode is an exact zero of a spherical Bessel function. A pure-python
#  spherical Bessel j_n and bisection root-finder back up scipy so the geometry
#  is exact even on a bare interpreter.
# =============================================================================

def _spherical_j0(x: float) -> float:
    return 1.0 if abs(x) < 1e-12 else math.sin(x) / x


def _spherical_j1(x: float) -> float:
    if abs(x) < 1e-9:
        return x / 3.0
    return math.sin(x) / (x * x) - math.cos(x) / x


def _spherical_jn_py(n: int, x: float) -> float:
    """Pure-python spherical Bessel j_n via upward recurrence (stdlib fallback).
        j_{m+1}(x) = ((2m+1)/x) j_m(x) - j_{m-1}(x)
    Stable for x >= n in the regime where we hunt for zeros (x ~ (n+0.5)π·k)."""
    if n == 0:
        return _spherical_j0(x)
    if n == 1:
        return _spherical_j1(x)
    if abs(x) < 1e-12:
        return 0.0
    jm1, jm = _spherical_j0(x), _spherical_j1(x)
    for m in range(1, n):
        jp1 = ((2 * m + 1) / x) * jm - jm1
        jm1, jm = jm, jp1
    return jm


def _sph_jn(n: int, x: float) -> float:
    if OrgHAVE.get("scipy"):
        return float(_spherical_jn(n, x))
    return _spherical_jn_py(n, x)


def _brentq_py(f: Callable[[float], float], a: float, b: float,
               xtol: float = 1e-12, maxiter: int = 200) -> float:
    """Bisection root-finder (stdlib fallback for scipy.optimize.brentq)."""
    fa, fb = f(a), f(b)
    if fa == 0.0:
        return a
    if fb == 0.0:
        return b
    for _ in range(maxiter):
        m = 0.5 * (a + b)
        fm = f(m)
        if abs(fm) < 1e-15 or (b - a) / 2 < xtol:
            return m
        if (fa < 0) != (fm < 0):
            b, fb = m, fm
        else:
            a, fa = m, fm
    return 0.5 * (a + b)


def _find_root(f: Callable[[float], float], a: float, b: float) -> float:
    if OrgHAVE.get("scipy"):
        return float(_brentq(f, a, b, xtol=1e-12))
    return _brentq_py(f, a, b)


def org_bessel_zeros(n: int, n_zeros: int = 5) -> List[float]:
    """First n_zeros positive zeros of the spherical Bessel function j_n(x).
    Exact (scipy or pure-python bisection); not approximated."""
    zeros: List[float] = []
    x = max(0.1, (n + 0.5) * math.pi * 0.5)
    dx = 0.1
    while len(zeros) < n_zeros:
        while _sph_jn(n, x) * _sph_jn(n, x + dx) > 0:
            x += dx
            if x > 400.0:
                raise RuntimeError(f"no Bessel zero found for n={n}")
        zero = _find_root(lambda t: _sph_jn(n, t), x, x + dx)
        zeros.append(zero)
        x += dx
    return zeros


def org_spherical_bessel_zero(n: int, k: int) -> float:
    """The k-th positive zero of j_n (1-indexed). j_{0,1} = π exactly."""
    return org_bessel_zeros(n, k)[k - 1]


@dataclass
class OrgSphericalMode:
    n: int
    l: int
    bessel_zero: float
    k: float
    f: float
    wavelength: float


@dataclass
class OrgSystemGeometry:
    """Complete geometry derived from the sphere outward; every value exact."""
    L: float
    R: float
    mode: OrgSphericalMode
    L_pendulum: float
    T_pendulum: float
    f_pendulum: float
    r0: float
    r_in: float
    G: float
    d_slit: float
    theta_diffraction: float
    f_lens: float
    f_fan: float
    T_star: float
    nu_star: float

    def to_dict(self) -> Dict[str, Any]:
        return {"L": self.L, "R": self.R,
                "mode": {"n": self.mode.n, "l": self.mode.l,
                         "bessel_zero": self.mode.bessel_zero,
                         "f": self.mode.f, "wavelength": self.mode.wavelength},
                "r0": self.r0, "r_in": self.r_in, "G": self.G,
                "L_pendulum": self.L_pendulum, "T_pendulum": self.T_pendulum,
                "f_fan": self.f_fan, "T_star": self.T_star, "nu_star": self.nu_star}


class OrgAcousticSphereGeometry:
    """Derives the complete system geometry from the sphere outward."""
    C_AIR = 343.0
    G_GRAV = 9.81
    H = 6.626e-34
    K_B = 1.381e-23
    C_LIGHT = 3e8
    WIEN_X = 2.821

    def __init__(self, L: float = 1.0, n: int = 0, l: int = 0,
                 mode_index: int = 1, D_blind: Optional[float] = None):
        self.L = L
        self.R = L / 2.0
        self.n = n
        self.l = l
        self.mode_index = mode_index
        self.D_blind = D_blind if D_blind else L / 4.0

    def solve(self) -> OrgSystemGeometry:
        zeros = org_bessel_zeros(self.n, max(self.mode_index, 1))
        j_nl = zeros[self.mode_index - 1]
        k = j_nl / self.R
        f_mode = self.C_AIR * k / (2 * math.pi)
        lam = self.C_AIR / f_mode
        mode = OrgSphericalMode(self.n, self.l, j_nl, k, f_mode, lam)

        T_pend = 1.0 / f_mode
        L_pend = self.G_GRAV / (4 * math.pi ** 2 * f_mode ** 2)

        r0 = self.R * j_nl / math.pi
        if self.mode_index > 1:
            r_in = self.R * zeros[self.mode_index - 2] / math.pi
        else:
            r_in = r0 * 0.25
        G = max(0.0, 1.0 - (r_in / r0) ** 2)

        theta = math.atan2(r0, self.D_blind)
        d_slit = lam / math.sin(theta)
        f_lens = r0 ** 2 / lam
        f_fan = f_mode
        nu_star = self.K_B * 2 * math.pi * f_fan / self.H
        T_star = self.H * nu_star / (self.K_B * self.WIEN_X)

        return OrgSystemGeometry(
            L=self.L, R=self.R, mode=mode,
            L_pendulum=L_pend, T_pendulum=T_pend, f_pendulum=f_mode,
            r0=r0, r_in=r_in, G=G, d_slit=d_slit, theta_diffraction=theta,
            f_lens=f_lens, f_fan=f_fan, T_star=T_star, nu_star=nu_star)


# =============================================================================
#  U2 — FIELD PROJECTION  ψ <-> z  [ported from projection.py]
#  Band-limited 2D Fourier projection: the continuous complex field ψ (N×N)
#  maps to a real state vector z of its leading Fourier modes (DC excluded),
#  and lifts back exactly. The partial isometry that lets low-dimensional
#  constraint/closure machinery run without losing band-limited content.
# =============================================================================

class OrgFieldProjection:
    def __init__(self, N: int = 32, n_modes: int = 4):
        if not field_layer_available():
            raise RuntimeError("OrgFieldProjection requires numpy (field substrate)")
        self.N = N
        self.n_modes = n_modes
        kx = _np.fft.fftfreq(N, d=1.0 / N).astype(int)
        ky = _np.fft.fftfreq(N, d=1.0 / N).astype(int)
        KX, KY = _np.meshgrid(kx, ky, indexing="ij")
        mask = (_np.abs(KX) <= n_modes) & (_np.abs(KY) <= n_modes)
        mask[0, 0] = False
        self._mask = mask
        self._idx = _np.argwhere(mask)
        self._n_complex = int(self._idx.shape[0])

    @property
    def real_dim(self) -> int:
        return 2 * self._n_complex

    @property
    def complex_dim(self) -> int:
        return self._n_complex

    def project(self, psi) -> Any:
        psi = _np.asarray(psi)
        F = _np.fft.fft2(psi) / (self.N * self.N)
        coeffs = F[self._mask]
        return _np.concatenate([coeffs.real, coeffs.imag])

    def lift(self, z) -> Any:
        z = _np.asarray(z, dtype=float).ravel()
        n = self._n_complex
        coeffs = z[:n] + 1j * z[n:2 * n]
        F = _np.zeros((self.N, self.N), dtype=complex)
        F[self._mask] = coeffs
        return _np.fft.ifft2(F) * (self.N * self.N)


# =============================================================================
#  U3 — GENERIC DYNAMICS  [ported from generic.py]
#  The field's law of motion. GENERIC = reversible (Hamiltonian, skew) part +
#  dissipative (gradient-flow on H, symmetric) part + optional bounded noise.
#  H[ψ] = Σ[|∇ψ|²/2 − |ψ|²/2 + λ|ψ|⁴/4] is the actual energy; the MSR response
#  ψ̂ = −∂H/∂ψ* is the exact field that drives the stress-energy tensor (U7).
#  "Thinking" is this field descending H toward closure.
# =============================================================================

@dataclass
class OrgGENERICConfig:
    dt: float = 0.04
    diffusion: float = 0.05
    advection: float = 0.10
    reaction: float = 0.50          # double-well coefficient λ
    noise: float = 0.0              # 0 = deterministic (default; preserves L6)
    kT: float = 1.0


def org_laplacian_periodic(psi):
    return (_np.roll(psi, 1, axis=0) + _np.roll(psi, -1, axis=0)
            + _np.roll(psi, 1, axis=1) + _np.roll(psi, -1, axis=1) - 4.0 * psi)


def field_hamiltonian(psi, lam: float = 0.5) -> float:
    dpx = _np.roll(psi, -1, axis=0) - psi
    dpy = _np.roll(psi, -1, axis=1) - psi
    grad_sq = _np.abs(dpx) ** 2 + _np.abs(dpy) ** 2
    V = -0.5 * _np.abs(psi) ** 2 + 0.25 * lam * _np.abs(psi) ** 4
    return float(_np.sum(0.5 * grad_sq + V))


def org_msr_response(psi, lam: float = 0.5):
    """ψ̂ = −∂H/∂ψ* = ∇²ψ + ψ/2 − λ|ψ|²ψ (exact Wirtinger derivative)."""
    return org_laplacian_periodic(psi) + 0.5 * psi - lam * _np.abs(psi) ** 2 * psi


def field_entropy(psi) -> float:
    p = _np.abs(psi) ** 2
    Z = float(p.sum())
    if Z <= 0:
        return 0.0
    p = _np.clip(p / Z, 1e-18, None)
    return float(-(p * _np.log(p)).sum())


class OrgGENERICDynamics:
    def __init__(self, cfg: Optional[OrgGENERICConfig] = None):
        self.cfg = cfg or OrgGENERICConfig()
        self._rng = None

    def seed(self, seed: int) -> None:
        if field_layer_available():
            self._rng = _np.random.default_rng(seed)

    def step(self, psi):
        cfg = self.cfg
        psi_hat = org_msr_response(psi, lam=cfg.reaction)
        grad_H = -psi_hat
        rhs = 1j * cfg.advection * grad_H - cfg.diffusion * grad_H
        psi_new = psi + cfg.dt * rhs
        if cfg.noise > 0:
            if self._rng is None:
                self._rng = _np.random.default_rng(0)
            sigma = (2.0 * cfg.diffusion * cfg.kT * cfg.dt) ** 0.5
            eta = (self._rng.standard_normal(psi.shape)
                   + 1j * self._rng.standard_normal(psi.shape))
            psi_new = psi_new + cfg.noise * sigma * eta
        return psi_new

    def hamiltonian(self, psi) -> float:
        return field_hamiltonian(psi, lam=self.cfg.reaction)

    def entropy(self, psi) -> float:
        return field_entropy(psi)

    def dH_dpsi_conj(self, psi):
        return -org_msr_response(psi, lam=self.cfg.reaction)


# =============================================================================
#  U4 — ENGINE3 TEXT ENCODING + CALIBRATED CONSTANTS  [from constants.py/engine.py]
#  The bridge from symbol to field. A string is mapped to a binary weight, then
#  to a complex seed z_c = x·((1−√2) + i√e) (the Silver-angle encoding, kept as
#  a design choice, not a physics claim), then to a Gaussian observation that
#  seeds the field. Calibrated closure thresholds come from 50 GENERIC
#  trajectories (not from any tunable knob).
# =============================================================================

OrgSQRT2 = math.sqrt(2)
OrgSQRT_E = math.sqrt(math.e)
OrgDELTA_S = 1.0 + OrgSQRT2
OrgINV_DELTA_S_SQ = 1.0 / (OrgDELTA_S ** 2)            # 3 − 2√2 ≈ 0.17157
OrgC1_SILVER = 1.0 - OrgSQRT2
OrgSILVER_ANGLE = math.degrees(math.atan2(OrgSQRT_E, OrgC1_SILVER))   # ≈ 104.1°
OrgZ_SEED_REAL = OrgC1_SILVER
OrgZ_SEED_IMAG = OrgSQRT_E

# calibrated thresholds (50-trajectory baseline; physics-grounded, not Silver)
OrgCALIBRATED_E_TARGET = 3.837e-3
OrgCALIBRATED_DZ_DT_FLOOR = 2.253e-3
OrgCALIBRATED_FIELD_SCALE = 1.752e-1
OrgCALIBRATED_H_TARGET = 1.092794e+00
OrgCALIBRATED_H_STD = 2.550512e-01
OrgCALIBRATED_DH_DT_FLOOR = 1.292312e+00
OrgCALIBRATED_DH_DT_P25 = 5.191530e-01


def org_engine3_complex_state(x: float) -> complex:
    return complex(x * OrgZ_SEED_REAL, x * OrgZ_SEED_IMAG)


def org_engine3_E(x: float) -> float:
    z = org_engine3_complex_state(x)
    return (z.real ** 2 + z.imag ** 2) / 2.0


def org_tokenize_to_binary_weight(s: str, anchor: str = "dIse") -> float:
    """Engine3's binary map: len(binary(s)) / len(binary(anchor))."""
    binary = "".join(format(ord(c), "08b") for c in s)
    a_bin = "".join(format(ord(c), "08b") for c in anchor)
    return len(binary) / max(len(a_bin), 1)


def string_to_field_seed(s: str, dim: int, anchor: str = "dIse"):
    """Engine3 → field seed vector y (length dim) + the observation noise var.
    Deterministic; the seed that the field relaxes from."""
    x = org_tokenize_to_binary_weight(s, anchor)
    E_raw = org_engine3_E(x)
    x_norm = x / (x + 1.0)
    y_scale = x_norm * math.sqrt(2.0 * E_raw)
    if field_layer_available():
        y = _np.full(dim, y_scale / max(dim, 1) * math.sqrt(dim))
    else:
        val = y_scale / max(dim, 1) * math.sqrt(dim)
        y = [val] * dim
    noise_var = max(y_scale ** 2 * OrgINV_DELTA_S_SQ, 1e-10)
    return y, noise_var, x


# =============================================================================
#  U5 — CONSTRAINTS + DYKSTRA CASCADE  [ported from constraints.py]
#  The UMA Equalities: Alpha (hyperplane), Beta (ball), Gamma (Fisher-info
#  ellipsoid, projected by an eigenbasis-KKT Lagrange search). Applied in an
#  alternating-projection cascade. These bound the semantic state geometrically
#  — the structural laws the closing field must satisfy.
# =============================================================================

class OrgEqualityConstraint:
    def __init__(self, name: str):
        self.name = name
        self._violation_history: List[float] = []

    def check(self, z) -> float: raise NotImplementedError
    def project(self, z): raise NotImplementedError

    def apply(self, z):
        z_proj = self.project(z)
        viol = self.check(z)
        self._violation_history.append(viol)
        return z_proj, viol

    def is_satisfied(self) -> bool:
        return bool(self._violation_history) and self._violation_history[-1] < 1e-6

    def reset(self) -> None:
        self._violation_history = []

    def as_dict(self) -> Dict[str, Any]:
        return {"name": self.name,
                "final_violation": (self._violation_history[-1]
                                    if self._violation_history else 0.0),
                "satisfied": self.is_satisfied()}


class OrgLinearConstraint(OrgEqualityConstraint):
    """Alpha: a·z = b. Orthogonal hyperplane projection."""
    def __init__(self, a, b: float, name: str = "alpha"):
        super().__init__(name)
        a = _np.asarray(a, dtype=float)
        norm_sq = float(a @ a)
        if norm_sq < 1e-12:
            raise ValueError("constraint normal must be nonzero")
        self._a, self._b, self._norm_sq = a, b, norm_sq

    def check(self, z) -> float:
        return abs(float(self._a @ z) - self._b)

    def project(self, z):
        residual = float(self._a @ z) - self._b
        return z - (residual / self._norm_sq) * self._a


class OrgBallConstraint(OrgEqualityConstraint):
    """Beta: ||z − center|| ≤ r."""
    def __init__(self, r: float, center=None, name: str = "beta"):
        super().__init__(name)
        if r <= 0:
            raise ValueError("ball radius must be positive")
        self._r, self._center = r, center

    def check(self, z) -> float:
        v = z if self._center is None else z - self._center
        return max(0.0, float(_np.linalg.norm(v)) - self._r)

    def project(self, z):
        center = _np.zeros_like(z) if self._center is None else self._center
        v = z - center
        norm = float(_np.linalg.norm(v))
        if norm <= self._r:
            return z
        return center + self._r * v / norm


class OrgQuadraticConstraint(OrgEqualityConstraint):
    """Gamma: (z−c)·Q·(z−c) ≤ κ (Fisher-info ellipsoid). Eigenbasis-KKT projection."""
    def __init__(self, kappa: float, Q=None, center=None, name: str = "gamma"):
        super().__init__(name)
        if kappa <= 0:
            raise ValueError("kappa must be positive")
        self._kappa, self._center, self._Q = kappa, center, Q
        if Q is not None:
            eigs, vecs = _np.linalg.eigh(0.5 * (Q + Q.T))
            self._eigs = _np.clip(eigs, 1e-12, None)
            self._vecs = vecs
        else:
            self._eigs = self._vecs = None

    def _mahal(self, z) -> float:
        v = z if self._center is None else z - self._center
        return float(v @ v) if self._Q is None else float(v @ self._Q @ v)

    def check(self, z) -> float:
        return max(0.0, self._mahal(z) - self._kappa)

    def project(self, z):
        center = _np.zeros_like(z) if self._center is None else self._center
        v = z - center
        if self._mahal(z) <= self._kappa:
            return z
        if self._Q is None:
            norm = float(_np.linalg.norm(v))
            return center + math.sqrt(self._kappa) * v / (norm + 1e-15)
        w = self._vecs.T @ v
        lam_vals, kappa = self._eigs, self._kappa
        mu_lo, mu_hi = 0.0, 1e8
        for _ in range(60):
            mu_mid = 0.5 * (mu_lo + mu_hi)
            w_proj = w / (1 + mu_mid * lam_vals)
            val = float(_np.sum(lam_vals * w_proj ** 2)) - kappa
            if val > 0:
                mu_lo = mu_mid
            else:
                mu_hi = mu_mid
            if mu_hi - mu_lo < 1e-12:
                break
        w_proj = w / (1 + 0.5 * (mu_lo + mu_hi) * lam_vals)
        return center + self._vecs @ w_proj


class OrgConstraintSet:
    """Alternating-projection (Dykstra-style) cascade over the UMA Equalities."""
    def __init__(self, constraints: List[OrgEqualityConstraint],
                 max_iters: int = 20, tol: float = 1e-6):
        self.constraints = constraints
        self.max_iters = max_iters
        self.tol = tol

    def apply(self, z):
        z_curr = z.copy()
        viols: List[float] = []
        for _ in range(self.max_iters):
            total = 0.0
            for c in self.constraints:
                z_curr, v = c.apply(z_curr)
                total += v
            viols.append(total)
            if total < self.tol:
                break
        return z_curr, {"n_iters": len(viols),
                        "final_total_violation": viols[-1] if viols else 0.0,
                        "converged": (viols[-1] < self.tol) if viols else True}

    def reset(self) -> None:
        for c in self.constraints:
            c.reset()

    @classmethod
    def default_semantic_constraints(cls, dim: int, z_target,
                                     ball_radius_factor: float = 3.0,
                                     kappa_factor: float = 9.0,
                                     alpha_direction: int = 0) -> "OrgConstraintSet":
        a = _np.zeros(dim)
        a[alpha_direction] = 1.0
        alpha = OrgLinearConstraint(a, float(z_target[alpha_direction]), name="alpha_dIse")
        r = ball_radius_factor * (float(_np.linalg.norm(z_target)) + 1.0)
        beta = OrgBallConstraint(r=r, center=z_target, name="beta_VH")
        gamma = OrgQuadraticConstraint(kappa=kappa_factor * dim, Q=None,
                                    center=z_target, name="gamma_Jd4m")
        return cls([alpha, beta, gamma])


# =============================================================================
#  U6 — SEMANTIC FRICTION  (closure via dH/dt)  [ported from friction.py]
#  Friction is the decimal walk that measures how close the field is to
#  thermodynamic rest. It closes when energy-rate, friction, and distance to
#  target all fall below their calibrated floors simultaneously — one of the
#  two faces of Ω.
# =============================================================================

@dataclass
class OrgSemanticFrictionConfig:
    step_weight: float = 0.02
    closure_friction_threshold: float = 0.15
    convergence_dz_dt: float = OrgCALIBRATED_DH_DT_FLOOR
    closure_state_tol: float = OrgCALIBRATED_FIELD_SCALE * 2.0
    min_steps_before_closure: int = 8
    dt: float = 0.04


@dataclass
class OrgFrictionRecord:
    t: float
    H: float
    dH_dt: float
    friction: float
    z_distance: float
    closed: bool


class OrgSemanticFriction:
    def __init__(self, z_target, config: Optional[OrgSemanticFrictionConfig] = None,
                 hamiltonian_fn: Optional[Callable[[Any], float]] = None):
        self.z_target = _np.asarray(z_target, dtype=float)
        self.config = config or OrgSemanticFrictionConfig()
        self.hamiltonian_fn = hamiltonian_fn
        self._friction = 1.0
        self._H_prev: Optional[float] = None
        self._records: List[OrgFrictionRecord] = []

    def update(self, z, t: float) -> OrgFrictionRecord:
        cfg = self.config
        z = _np.asarray(z, dtype=float)
        if self.hamiltonian_fn is not None:
            H = float(self.hamiltonian_fn(z))
        else:
            H = float(_np.real(z @ z) / 2.0)
        dH_dt = (H - self._H_prev) / cfg.dt if self._H_prev is not None else 0.0
        self._H_prev = H
        floor = cfg.convergence_dz_dt + 1e-15
        step = cfg.step_weight / (1.0 + abs(dH_dt) / floor)
        self._friction = max(0.0, self._friction - step)
        field_scale = OrgCALIBRATED_FIELD_SCALE + 1e-15
        z_dist = float(_np.linalg.norm(z - self.z_target)) / field_scale
        closed = False
        if len(self._records) >= cfg.min_steps_before_closure:
            closed = (self._friction < cfg.closure_friction_threshold
                      and abs(dH_dt) < cfg.convergence_dz_dt
                      and z_dist < cfg.closure_state_tol / field_scale)
        rec = OrgFrictionRecord(t=t, H=H, dH_dt=dH_dt, friction=self._friction,
                             z_distance=z_dist, closed=closed)
        self._records.append(rec)
        return rec

    @property
    def value(self) -> float:
        return self._friction

    @property
    def is_closed(self) -> bool:
        return bool(self._records and self._records[-1].closed)

    @property
    def closure_step(self) -> Optional[int]:
        for i, r in enumerate(self._records):
            if r.closed:
                return i
        return None

    def summary(self) -> Dict[str, Any]:
        if not self._records:
            return {"status": "no_data"}
        f = self._records[-1]
        return {"friction_final": round(f.friction, 6),
                "H_final": round(f.H, 6), "dH_dt_final": round(f.dH_dt, 6),
                "dH_dt_floor": round(self.config.convergence_dz_dt, 6),
                "z_distance_final": round(f.z_distance, 4),
                "is_closed": self.is_closed, "n_steps": len(self._records)}


# =============================================================================
#  U7 — TENSOR BRIDGE  (the Einstein closure detector)  [ported from tensor_bridge.py]
#  The deepest claim of the system: the field's own MSR stress-energy T_μν,
#  fed through the linearized Einstein equation (∇²h = −16πG T, solved by FFT)
#  to a curvature G_μν, must satisfy T = κ·G. The residual ‖T − κG‖ → 0 is the
#  OTHER face of Ω. Friction → 0 and this residual → 0 are the same event.
# =============================================================================

@dataclass
class OrgTensorRecord:
    t: float
    T: Any
    G: Any
    h: Any
    kappa: float
    residual_norm: float
    relative_residual: float
    einstein_satisfied: bool


def _org_stress_tensor_spatial(psi, psi_hat, dx: float = 1.0):
    N = psi.shape[0]
    dpsi = [_np.gradient(psi.real, dx, axis=i) for i in range(2)]
    dphat = [_np.gradient(psi_hat.real, dx, axis=i) for i in range(2)]
    T = _np.zeros((2, 2, N, N))
    for mu in range(2):
        for nu in range(2):
            T[mu, nu] = dphat[mu] * dpsi[nu] + dphat[nu] * dpsi[mu]
    trace = sum(dphat[i] * dpsi[i] for i in range(2))
    T[0, 0] -= trace
    T[1, 1] -= trace
    return T


def _org_metric_from_T(T_spatial, G_newton: float = 1.0, dx: float = 1.0):
    N = T_spatial.shape[-1]
    kx = 2 * math.pi * _np.fft.fftfreq(N, d=dx)
    KX, KY = _np.meshgrid(kx, kx)
    k2 = KX ** 2 + KY ** 2
    k2[0, 0] = 1.0
    h = _np.zeros_like(T_spatial)
    for mu in range(2):
        for nu in range(2):
            T_k = _np.fft.fft2(T_spatial[mu, nu])
            h_k = -16 * math.pi * G_newton * T_k / k2
            h_k[0, 0] = 0.0
            h[mu, nu] = _np.fft.ifft2(h_k).real
    return h


def _org_einstein_tensor_from_h(h_spatial, dx: float = 1.0):
    G = _np.zeros_like(h_spatial)
    h_trace = h_spatial[0, 0] + h_spatial[1, 1]

    def lap(f):
        return (_np.roll(f, 1, 0) + _np.roll(f, -1, 0)
                + _np.roll(f, 1, 1) + _np.roll(f, -1, 1) - 4 * f) / dx ** 2

    def grad2(f, mu, nu):
        return _np.gradient(_np.gradient(f, dx, axis=mu), dx, axis=nu)

    div_h = [sum(_np.gradient(h_spatial[mu, nu], dx, axis=mu) for mu in range(2))
             for nu in range(2)]
    div2_h = sum(grad2(h_spatial[mu, nu], mu, nu)
                 for mu in range(2) for nu in range(2))
    for mu in range(2):
        for nu in range(2):
            term1 = _np.gradient(div_h[nu], dx, axis=mu)
            term2 = _np.gradient(div_h[mu], dx, axis=nu)
            term3 = -lap(h_spatial[mu, nu])
            term4 = -grad2(h_trace, mu, nu)
            eta_mn = 1.0 if mu == nu else 0.0
            term5 = -eta_mn * (div2_h - lap(h_trace))
            G[mu, nu] = 0.5 * (term1 + term2 + term3 + term4 + term5)
    return G


class OrgTensorBridge:
    """Live <T_μν> ↔ G_μν^(1) residual tracker. einstein_satisfied when the
    relative residual falls below threshold — the relativistic face of Ω."""
    def __init__(self, N: int = 32, residual_threshold: float = 0.1,
                 dx: Optional[float] = None, window: int = 30):
        self.dx = dx if dx else 1.0 / N
        self.threshold = residual_threshold
        self.window = window
        self.records: List[OrgTensorRecord] = []
        self._T_buffer: List[Any] = []

    def update(self, psi, psi_hat, t: float) -> OrgTensorRecord:
        T_spatial = _org_stress_tensor_spatial(psi, psi_hat, self.dx)
        h_spatial = _org_metric_from_T(T_spatial, 1.0, self.dx)
        G_spatial = _org_einstein_tensor_from_h(h_spatial, self.dx)
        T_inst = T_spatial.mean(axis=(-2, -1))
        G = G_spatial.mean(axis=(-2, -1))
        h = h_spatial.mean(axis=(-2, -1))
        self._T_buffer.append(T_inst)
        if len(self._T_buffer) > self.window:
            self._T_buffer.pop(0)
        T = _np.mean(self._T_buffer, axis=0)
        T_norm = float(_np.linalg.norm(T))
        G_norm = float(_np.linalg.norm(G))
        kappa = float(_np.sum(T * G) / (G_norm ** 2)) if G_norm > 1e-15 else 0.0
        residual_norm = float(_np.linalg.norm(T - kappa * G))
        rel = residual_norm / (T_norm + 1e-15)
        rec = OrgTensorRecord(t=t, T=T, G=G, h=h, kappa=kappa,
                           residual_norm=residual_norm, relative_residual=rel,
                           einstein_satisfied=rel < self.threshold)
        self.records.append(rec)
        return rec

    @property
    def is_einstein_satisfied(self) -> bool:
        return bool(self.records and self.records[-1].einstein_satisfied)

    def summary(self) -> Dict[str, Any]:
        if not self.records:
            return {"status": "no_data"}
        f = self.records[-1]
        rh = [r.relative_residual for r in self.records]
        return {"kappa_final": round(f.kappa, 6),
                "relative_residual": round(f.relative_residual, 6),
                "einstein_satisfied": f.einstein_satisfied,
                "residual_min": round(min(rh), 6),
                "n_steps": len(self.records)}


# =============================================================================
#  U8 — RSLS MEMORY SECTOR  (the holographic wall; the Congress's ground)
#  [ported from memory.py + cattaneo.py]
#  M is the thermodynamic memory field — a dissipative scalar tracking local
#  informational entropy. V(M) = −λ log(1 − M/Mmax) is the singular convex
#  barrier (the "holographic wall") that forbids M from exceeding capacity.
#  The Maxwell–Cattaneo flux gives entropy transport a FINITE speed (causal).
#  This sector is the south-pole ground: the organism's deep memory substrate.
# =============================================================================

@dataclass
class OrgMemoryConfig:
    M_max: float = 1.0
    lam: float = 0.12
    tau_M: float = 1.0
    tau_J: float = 0.15
    mu: float = 0.08
    M_max_clip: float = 1e-9

    def check_causality(self) -> bool:
        return (self.mu / (self.tau_J * self.tau_M)) <= 1.0

    @property
    def c_diff(self) -> float:
        return math.sqrt(self.mu / (self.tau_J * self.tau_M))

    @property
    def c_eff(self) -> float:
        return math.sqrt(self.mu / self.tau_J)


def V_barrier(M, cfg: OrgMemoryConfig):
    """Singular convex barrier V(M) = −λ log(1 − M/Mmax). Diverges at saturation."""
    if field_layer_available():
        M_safe = _np.clip(M, 0.0, cfg.M_max - cfg.M_max_clip)
        return -cfg.lam * _np.log(1.0 - M_safe / cfg.M_max)
    M_safe = min(max(M, 0.0), cfg.M_max - cfg.M_max_clip)
    return -cfg.lam * math.log(1.0 - M_safe / cfg.M_max)


def OrgV_prime(M, cfg: OrgMemoryConfig):
    if field_layer_available():
        M_safe = _np.clip(M, 0.0, cfg.M_max - cfg.M_max_clip)
        return cfg.lam / (cfg.M_max - M_safe)
    M_safe = min(max(M, 0.0), cfg.M_max - cfg.M_max_clip)
    return cfg.lam / (cfg.M_max - M_safe)


def V_double_prime(M, cfg: OrgMemoryConfig):
    if field_layer_available():
        M_safe = _np.clip(M, 0.0, cfg.M_max - cfg.M_max_clip)
        return cfg.lam / (cfg.M_max - M_safe) ** 2
    M_safe = min(max(M, 0.0), cfg.M_max - cfg.M_max_clip)
    return cfg.lam / (cfg.M_max - M_safe) ** 2


def clip_M(M, cfg: OrgMemoryConfig):
    """Discrete maximum principle: enforce M ∈ [0, Mmax − ε)."""
    if field_layer_available():
        return _np.clip(M, 0.0, cfg.M_max - cfg.M_max_clip)
    return min(max(M, 0.0), cfg.M_max - cfg.M_max_clip)


def ell_star(M, cfg: OrgMemoryConfig):
    """Emergent relaxation length ℓ_*(M) = (Mmax − M)·√(μ·τ_M/λ)."""
    return (cfg.M_max - clip_M(M, cfg)) * math.sqrt(cfg.mu * cfg.tau_M / cfg.lam)


def cattaneo_step(J, M, dx: float, dt: float, cfg: OrgMemoryConfig):
    """Implicit Maxwell–Cattaneo update for the entropy flux J_r.
    (1 + dt/τ_J)J^{n+1} = J^n − (dt·μ/τ_J)∇M. Unconditionally stable in dt."""
    grad_M = _np.gradient(M, dx)
    return (J - (dt * cfg.mu / cfg.tau_J) * grad_M) / (1.0 + dt / cfg.tau_J)


def cattaneo_cfl(dx: float, cfg: OrgMemoryConfig, safety: float = 0.5) -> float:
    return safety * dx / max(cfg.c_diff, 1e-12)


def subluminal(cfg: OrgMemoryConfig, c_geom: float = 1.0) -> bool:
    """Whitham subcharacteristic condition: entropy-flux speed ≤ geometric speed."""
    return cfg.c_diff <= c_geom


def gradient_stress_nec_min(M, dx: float, cfg: OrgMemoryConfig) -> float:
    """Minimum of the null-energy contraction of the memory-gradient stress
    T^{(∇M)}. NEC-compliant by construction ⇒ this is ≥ 0 (no exotic energy)."""
    grad_M = _np.gradient(M, dx)
    # T_kk for a null vector reduces to (∇M)^2 * mu (non-negative)
    return float(_np.min(cfg.mu * grad_M ** 2))


# =============================================================================
#  U9 — MENGER SPONGE  (the attractor geometry of saturated memory)
#  [ported from menger.py]
#  When the memory field saturates, the predicted geometry of the information
#  attractor is a fractal: the Menger sponge. Survival rule: keep a sub-cube
#  iff at most one coordinate equals the middle (1). Hausdorff dim = log20/log3.
#  Used by the organism as the self-similar address space of saturated memory.
# =============================================================================

HAUSDORFF_DIM = math.log(20.0) / math.log(3.0)   # ≈ 2.7268


def is_surviving(i: int, j: int, k: int) -> bool:
    return (int(i == 1) + int(j == 1) + int(k == 1)) <= 1


_SURVIVING_OFFSETS = [(i, j, k) for i in range(3) for j in range(3) for k in range(3)
                      if is_surviving(i, j, k)]


@dataclass
class Cell:
    i: int
    j: int
    k: int
    depth: int
    side: float
    origin: Tuple[float, float, float]

    def centre(self) -> Tuple[float, float, float]:
        h = self.side / 2.0
        return (self.origin[0] + h, self.origin[1] + h, self.origin[2] + h)

    def volume(self) -> float:
        return self.side ** 3

    def surface_area(self) -> float:
        return 6.0 * self.side ** 2


class OrgMengerSponge:
    """The Menger-sponge lattice. 20 surviving offsets per subdivision."""
    def __init__(self, level: int = 1, side: float = 1.0):
        self.level = level
        self.side0 = side
        self._cells: List[Cell] = []
        self._build(level, side)

    def _build(self, level: int, side: float) -> None:
        self._cells = [Cell(0, 0, 0, 0, side, (0.0, 0.0, 0.0))]
        for d in range(level):
            nxt: List[Cell] = []
            for c in self._cells:
                child = c.side / 3.0
                for (i, j, k) in _SURVIVING_OFFSETS:
                    origin = (c.origin[0] + i * child,
                              c.origin[1] + j * child,
                              c.origin[2] + k * child)
                    nxt.append(Cell(i, j, k, d + 1, child, origin))
            self._cells = nxt

    def n_cells(self) -> int:
        return len(self._cells)

    def hausdorff_dim(self) -> float:
        return HAUSDORFF_DIM

    def volume(self) -> float:
        return float(sum(c.volume() for c in self._cells))

    def surface_area(self) -> float:
        return float(sum(c.surface_area() for c in self._cells))

    def theoretical_n_cells(self) -> int:
        return 20 ** self.level

    def theoretical_volume(self) -> float:
        return (20.0 / 27.0) ** self.level * self.side0 ** 3

    def centres(self):
        cs = [c.centre() for c in self._cells]
        return _np.array(cs) if field_layer_available() else cs


# =============================================================================
#  U10 — STATISTICAL REDUCTION  (KvN → Lindblad → SRB → Born)  [from srb.py]
#  How determinate readouts emerge from the field: the chaotic dynamics carry
#  an SRB (ergodic) measure; the decoherence at the memory wall is a Lindblad
#  channel; in the saturation limit the SRB measure reproduces the Born rule.
#  The organism uses this as its measurement/readout principle and as a
#  chaos-regime diagnostic (the maximum Lyapunov exponent).
# =============================================================================

@dataclass
class LorenzParams:
    sigma: float = 10.0
    rho: float = 28.0
    beta: float = 8.0 / 3.0


def org_lorenz_rhs(state, p: LorenzParams):
    x, y, z = state
    return _np.array([p.sigma * (y - x), x * (p.rho - z) - y, x * y - p.beta * z])


def rk4_step(rhs: Callable, state, dt: float, *args):
    k1 = rhs(state, *args)
    k2 = rhs(state + 0.5 * dt * k1, *args)
    k3 = rhs(state + 0.5 * dt * k2, *args)
    k4 = rhs(state + dt * k3, *args)
    return state + (dt / 6.0) * (k1 + 2 * k2 + 2 * k3 + k4)


def lyapunov_max(rhs: Callable, state0, dt: float = 0.01, n_steps: int = 5000,
                 renormalize_every: int = 5, delta0: float = 1e-8, *args) -> float:
    """Maximum Lyapunov exponent via Benettin's algorithm. Canonical Lorenz
    gives ≈ 0.9056. >0 ⇒ chaotic (predictability horizon is finite)."""
    s_main = state0.copy()
    rng = _np.random.default_rng(0)
    direction = rng.standard_normal(state0.shape)
    direction /= _np.linalg.norm(direction)
    s_pert = s_main + delta0 * direction
    burn_in = max(1, n_steps // 5)
    for _ in range(burn_in):
        s_main = rk4_step(rhs, s_main, dt, *args)
        s_pert = rk4_step(rhs, s_pert, dt, *args)
        sep = s_pert - s_main
        nrm = _np.linalg.norm(sep)
        if nrm > 0:
            s_pert = s_main + sep / nrm * delta0
    log_sum, total_time = 0.0, 0.0
    for _ in range(n_steps):
        for _ in range(renormalize_every):
            s_main = rk4_step(rhs, s_main, dt, *args)
            s_pert = rk4_step(rhs, s_pert, dt, *args)
        sep = s_pert - s_main
        nrm = _np.linalg.norm(sep)
        if nrm > 0:
            log_sum += math.log(nrm / delta0)
            total_time += renormalize_every * dt
            s_pert = s_main + sep / nrm * delta0
    return log_sum / total_time if total_time > 0 else float("nan")


def integrate_lorenz(state0, dt: float = 0.01, n_steps: int = 5000,
                     p: Optional[LorenzParams] = None):
    p = p or LorenzParams()
    s = state0.copy()
    traj = [s.copy()]
    for _ in range(n_steps):
        s = rk4_step(org_lorenz_rhs, s, dt, p)
        traj.append(s.copy())
    return _np.array(traj)


def org_srb_histogram(trajectory, axis: int = 2, n_bins: int = 64):
    coord = trajectory[:, axis]
    hist, edges = _np.histogram(coord, bins=n_bins, density=True)
    centres = 0.5 * (edges[:-1] + edges[1:])
    return centres, hist


def lindblad_step(rho, H, L_list, dt: float):
    """One GKLS master-equation forward-Euler step:
    dρ/dt = −i[H,ρ] + Σ_k (L_k ρ L_k† − ½{L_k†L_k, ρ})."""
    comm = H @ rho - rho @ H
    drho = -1j * comm
    for L in L_list:
        Ld = L.conj().T
        drho = drho + L @ rho @ Ld - 0.5 * (Ld @ L @ rho + rho @ Ld @ L)
    return rho + dt * drho


def integrate_lindblad(rho0, H, L_list, dt: float = 0.01, n_steps: int = 500):
    rho = rho0.astype(complex).copy()
    for _ in range(n_steps):
        rho = lindblad_step(rho, H, L_list, dt)
    return rho


def born_rule_match(srb_density, psi_squared, bin_widths) -> float:
    """L¹ distance between the ergodic (SRB) density and the quantum |ψ|²
    density. Small ⇒ the chaotic measure reproduces the Born rule."""
    p = _np.asarray(srb_density) * _np.asarray(bin_widths)
    q = _np.asarray(psi_squared) * _np.asarray(bin_widths)
    p = p / (p.sum() + 1e-15)
    q = q / (q.sum() + 1e-15)
    return float(_np.sum(_np.abs(p - q)))


def cone_aperture_from_lyapunov(lyap: float, horizon: float = 1.0) -> float:
    """Predictability cone aperture from the Lyapunov exponent: the time beyond
    which prediction is Ω (unknowable). Δt ≈ 1/λ for λ>0, else the full horizon."""
    return round(min(horizon, 1.0 / lyap) if lyap > 1e-9 else horizon, 6)


# =============================================================================
#  U11 — THE UMA COGNITION PIPELINE  (text → field → Ω)
#  The integrator that turns an input into a relaxing field and watches for
#  closure. Seeds the field from the Engine3 encoding at the CALIBRATED scale
#  (so the field stays in the stable basin — no divergence), evolves under
#  GENERIC dynamics with the constraint cascade applied on a schedule, and
#  tracks BOTH faces of Ω: semantic friction and the Einstein residual. The
#  RSLS memory field M accumulates with the field's entropy. Deterministic.
# =============================================================================

@dataclass
class CognitionResult:
    text: str
    closed: bool                  # Ω reached (friction face)
    einstein_satisfied: bool      # Ω reached (relativistic face)
    omega: bool                   # BOTH — the single cognitive event
    closure_step: Optional[int]
    n_steps: int
    H_initial: float
    H_final: float
    friction_final: float
    einstein_residual_final: float
    kappa_final: float
    M_saturation: float           # max of the memory field (0..Mmax)
    ell_star_min: float
    lyapunov_regime: str          # 'contracting' | 'chaotic-edge'
    geometry: Dict[str, Any]
    friction_summary: Dict[str, Any]
    tensor_summary: Dict[str, Any]
    stage: str                    # ingestion | stability | inarticulation | solve


class UMACognition:
    """The field-cognition pipeline. numpy-backed; the organism's deep thinker."""
    def __init__(self, N: int = 16, n_modes: int = 3,
                 generic_cfg: Optional[OrgGENERICConfig] = None,
                 memory_cfg: Optional[OrgMemoryConfig] = None,
                 n_steps: int = 80, seed: int = 42):
        if not field_layer_available():
            raise RuntimeError("UMACognition requires numpy (field substrate)")
        self.N = N
        self.n_modes = n_modes
        self.gcfg = generic_cfg or OrgGENERICConfig(dt=0.04, reaction=0.4, noise=0.0)
        self.mcfg = memory_cfg or OrgMemoryConfig()
        self.n_steps = n_steps
        self.seed = seed
        self.geometry = OrgAcousticSphereGeometry(L=1.0, n=0, l=0, mode_index=1).solve()

    def _seed_field(self, text: str, fp: OrgFieldProjection):
        """Engine3 seed → a STABLE-amplitude band-limited field. The seed is
        scaled to the calibrated field scale so the double-well dynamics keep
        the field bounded (the stable basin), and a deterministic low-mode
        pattern derived from the text gives it structure."""
        y, noise_var, x = string_to_field_seed(text, fp.real_dim)
        z0 = _np.asarray(y, dtype=float)
        # scale into the stable basin
        nrm = float(_np.linalg.norm(z0)) + 1e-15
        z0 = z0 / nrm * OrgCALIBRATED_FIELD_SCALE * math.sqrt(fp.real_dim)
        psi = fp.lift(z0)
        # keep amplitude in the stable well |psi| ~ O(field_scale)
        amp = float(_np.max(_np.abs(psi))) + 1e-15
        psi = psi / amp * OrgCALIBRATED_FIELD_SCALE
        return psi, x

    def run(self, text: str) -> CognitionResult:
        fp = OrgFieldProjection(N=self.N, n_modes=self.n_modes)
        dyn = OrgGENERICDynamics(self.gcfg)
        dyn.seed(self.seed)
        psi, x = self._seed_field(text, fp)
        z_target = fp.project(psi)
        constraints = OrgConstraintSet.default_semantic_constraints(fp.real_dim, z_target)
        fric = OrgSemanticFriction(
            z_target,
            config=OrgSemanticFrictionConfig(dt=self.gcfg.dt),
            hamiltonian_fn=lambda z: field_hamiltonian(fp.lift(z), lam=self.gcfg.reaction))
        bridge = OrgTensorBridge(N=self.N, residual_threshold=0.1)

        H0 = dyn.hamiltonian(psi)
        # the RSLS memory field tracks accumulating informational entropy
        M = _np.zeros((self.N, self.N))
        closure_step: Optional[int] = None

        for i in range(self.n_steps):
            psi = dyn.step(psi)
            psi_hat = org_msr_response(psi, lam=self.gcfg.reaction)
            z = fp.project(psi)
            # apply the constraint cascade on a schedule (every 4 steps)
            if i % 4 == 0:
                z, _rep = constraints.apply(z)
                psi = fp.lift(z)
            frec = fric.update(z, i * self.gcfg.dt)
            bridge.update(psi, psi_hat, i * self.gcfg.dt)
            # memory field accumulates local |psi|^2 (entropy density), clipped by the wall
            M = clip_M(M + 0.02 * (_np.abs(psi) ** 2), self.mcfg)
            if closure_step is None and frec.closed and bridge.is_einstein_satisfied:
                closure_step = i

        H1 = dyn.hamiltonian(psi)
        M_sat = float(_np.max(M))
        ell_min = float(_np.min(ell_star(M, self.mcfg)))
        # chaos-regime diagnostic: is the field's energy trajectory contracting?
        traj = [r.H for r in fric._records]
        regime = "contracting" if (len(traj) > 2 and traj[-1] <= traj[0]) else "chaotic-edge"

        # stage classification (from the inarticulation taxonomy)
        sf = fric.value
        if fric.is_closed:
            stage = "solve"
        elif sf > 0.5:
            stage = "ingestion"
        elif sf >= 0.2:
            stage = "stability"
        else:
            stage = "inarticulation"

        omega = fric.is_closed and bridge.is_einstein_satisfied
        return CognitionResult(
            text=text[:80], closed=fric.is_closed,
            einstein_satisfied=bridge.is_einstein_satisfied, omega=omega,
            closure_step=closure_step, n_steps=self.n_steps,
            H_initial=round(H0, 6), H_final=round(H1, 6),
            friction_final=round(fric.value, 6),
            einstein_residual_final=round(
                bridge.records[-1].relative_residual if bridge.records else 1.0, 6),
            kappa_final=round(bridge.records[-1].kappa if bridge.records else 0.0, 6),
            M_saturation=round(M_sat, 6), ell_star_min=round(ell_min, 6),
            lyapunov_regime=regime, geometry=self.geometry.to_dict(),
            friction_summary=fric.summary(), tensor_summary=bridge.summary(),
            stage=stage)

    def result_to_dict(self, r: CognitionResult) -> Dict[str, Any]:
        return {"text": r.text, "omega_closure": r.omega,
                "friction_closed": r.closed, "einstein_satisfied": r.einstein_satisfied,
                "closure_step": r.closure_step, "n_steps": r.n_steps,
                "H_initial": r.H_initial, "H_final": r.H_final,
                "friction_final": r.friction_final,
                "einstein_residual_final": r.einstein_residual_final,
                "kappa_final": r.kappa_final, "M_saturation": r.M_saturation,
                "ell_star_min": r.ell_star_min, "lyapunov_regime": r.lyapunov_regime,
                "stage": r.stage,
                "sphere_geometry": {"bessel_zero": r.geometry["mode"]["bessel_zero"],
                                    "r0": r.geometry["r0"], "G": r.geometry["G"],
                                    "T_star": r.geometry["T_star"]}}


