@dataclass
class HarmonyFunctional:
    """H[u] = Benefit[u] − Burden[u] − Safety_Tax[u]. The objective every URF
    instantiation maximizes; free energy 𝓕 = −H is what it minimizes."""
    benefit: Callable[[Any], float]
    burden: Callable[[Any], float]
    safety_tax: Callable[[Any], float]

    def H(self, u: Any) -> float:
        return self.benefit(u) - self.burden(u) - self.safety_tax(u)

    def free_energy(self, u: Any) -> float:
        return -self.H(u)


def urf_axioms_report(F_hessian_pd: bool, barrier_diverges: bool,
                      skew_orthogonal: bool, c_diff: float, c_geom: float,
                      org_cone_aperture: float) -> Dict[str, Any]:
    """The five domain-independent URF axioms, as a checkable report.
      A1 convex coercivity  : 𝓕 convex (Hessian PD)
      A2 singular barrier   : V'(d→0) → ∞ at the domain boundary
      A3 skew/gradient split: dynamics = ∇H + Δ·J, with ∇H ⊥ J
      A4 causal transport   : c_diff ≤ c_geom (Whitham subcharacteristic)
      A5 Anosov closure     : ΔΛ > 2·c_diff ⇒ hyperbolic regime, SRB well-defined
    """
    a1 = bool(F_hessian_pd)
    a2 = bool(barrier_diverges)
    a3 = bool(skew_orthogonal)
    a4 = c_diff <= c_geom
    a5 = org_cone_aperture > 2.0 * c_diff
    return {"A1_convex_coercivity": a1, "A2_singular_barrier": a2,
            "A3_skew_gradient_split": a3, "A4_causal_transport": a4,
            "A5_anosov_closure": a5,
            "all_satisfied": all([a1, a2, a3, a4]),  # A5 is the regime switch, optional
            "regime": "chaotic/generative" if a5 else "contracting/harmonic"}


def generic_decomposition_step(u, grad_H, J_skew, dt: float, Delta: float):
    """One domain-independent GENERIC step: u ← u + dt(∇H + Δ·J·∇H), the skew
    (regime-generating) part Δ·J and the gradient (harmony-seeking) part ∇H.
    Pure-python vector form; works on lists or numpy arrays."""
    if field_layer_available() and hasattr(u, "shape"):
        return u + dt * (grad_H + Delta * (J_skew @ grad_H))
    out = []
    for i, ui in enumerate(u):
        skew_i = sum(J_skew[i][j] * grad_H[j] for j in range(len(grad_H)))
        out.append(ui + dt * (grad_H[i] + Delta * skew_i))
    return out


