@dataclass
class EconomicState:
    wealth: float
    risk_consumed: float            # K ∈ [0, K_max)
    K_max: float = 1.0

    def headroom(self) -> float:
        return max(0.0, self.K_max - self.risk_consumed)


class URFEconomy:
    """The Congress's economy as a URF manifold. Wraps the Bank: every
    over-threshold expenditure is scored by the Harmony functional and gated by
    the singular risk barrier (you cannot spend past the wall)."""
    def __init__(self, bank: Bank, lam: float = 0.12, K_max: float = 1.0):
        self.bank = bank
        self.lam = lam
        self.K_max = K_max
        self.cfg = OrgMemoryConfig(M_max=K_max, lam=lam)

    def safety_tax(self, risk_consumed: float) -> float:
        """The economic holographic wall: V(K) = −λ log(1 − K/Kmax). Diverges as
        risk budget is exhausted — the system cannot over-leverage."""
        return float(V_barrier(risk_consumed, self.cfg))

    def harmony(self, benefit: float, burden: float, risk_consumed: float) -> float:
        return benefit - burden - self.safety_tax(risk_consumed)

    def evaluate_expenditure(self, engine: str, amount: float,
                             expected_benefit: float, reason: str) -> Dict[str, Any]:
        """Score a proposed expenditure by harmony delta + barrier headroom.
        Returns the URF verdict the presidential value-ledger presider uses."""
        capital = self.bank.weight_of(engine)
        # risk consumed by this engine ≈ fraction of its capital committed
        risk_now = min(self.K_max - self.cfg.M_max_clip,
                       (amount / (capital + 1e-9)) * self.K_max) if capital > 0 else self.K_max
        burden = amount
        H_now = self.harmony(expected_benefit, burden, risk_now)
        tax = self.safety_tax(risk_now)
        # harmonic iff benefit exceeds burden+tax and we are not at the wall
        harmonic = H_now > 0 and risk_now < 0.95 * self.K_max
        return {"engine": engine, "amount": round(amount, 6),
                "expected_benefit": round(expected_benefit, 6),
                "safety_tax": round(tax, 6), "harmony": round(H_now, 6),
                "risk_consumed": round(risk_now, 6),
                "harmonic": harmonic, "reason": reason,
                "verdict": "approve" if harmonic else "deny (disharmonic/over-wall)"}


