def uma_field_smoke(seed_offset: int = 0) -> float:
    """Deterministic UMA kernel smoke: init -> evolve -> Hamiltonian."""
    cfg = Config()
    client = UMAClient(cfg)
    rng = np.random.default_rng(7 + seed_offset)
    psi0 = (rng.standard_normal((cfg.grid.N, cfg.grid.N))
            + 1j * rng.standard_normal((cfg.grid.N, cfg.grid.N))) * 0.05
    client.initialize(psi0)
    for _ in range(3):
        client.evolve()
    return float(client.hamiltonian())

