def run_selftest(verbose: bool = True) -> bool:  # noqa: F811 (unified gate)
    """Unified CHIRON selftest: organism gates + every integrated engine
    suite + convergence-wiring gates. One green or it isn't done."""
    ok = _organism_run_selftest(verbose=verbose)

    extra = []  # (name, passed, detail)

    buf = _io.StringIO()
    with _contextlib.redirect_stdout(buf):
        pc, tc = jdicert_run_tests()
    extra.append((f"certifier suite green ({pc}/{tc})", pc == tc, ""))

    buf = _io.StringIO()
    try:
        with _contextlib.redirect_stdout(buf):
            rc = infectatrum_run_tests()
        extra.append(("Infectatrum integrated suite green", rc == 0, ""))
    except SystemExit as e:
        extra.append(("Infectatrum integrated suite green", int(e.code or 0) == 0, ""))

    h1, h2 = uma_field_smoke(), uma_field_smoke()
    extra.append(("UMA field kernel deterministic (H repeatable)",
                  h1 == h2 and np.isfinite(h1), f"H={h1}"))

    d = local_standardize("Subject record: a community facility upgrade "
                          "proposal with uncertain occupancy data.")
    d.setdefault("domain_tag", "general_consequential")
    d, _errs = pipeline_preprocess(d)
    okv, fails = validate_case_context_dict(d)
    extra.append(("primer intake standardizes deterministically", okv,
                  "; ".join(fails)))

    try:
        cert = _jdicert_certify_case(None, "Proposal: automated approval of a "
                                     "high-impact community decision with "
                                     "incomplete evidence.")
        extra.append(("organism certifier delegates to real certify()",
                      cert.verdict.value in ("ESCALATE_HUMAN", "REJECT_INPUT",
                                             "CERTIFIED_GO"),
                      cert.verdict.value))
        extra.append(("real certify() escalates under incomplete evidence",
                      cert.verdict.value != "CERTIFIED_GO", cert.verdict.value))
    except Exception as e:  # pragma: no cover
        extra.append(("organism certifier delegates to real certify()", False, str(e)))
        extra.append(("real certify() escalates under incomplete evidence", False, str(e)))

    ep, et = 0, len(extra)
    for name, passed, detail in extra:
        if passed:
            ep += 1
        if verbose:
            mark = "PASS" if passed else "FAIL"
            line = f"  [{mark}] {name}"
            if not passed and detail:
                line += f"  -- {detail}"
            print(line)
    if verbose:
        print(f"\n  convergence gates: {ep}/{et} passed.")
        if ok and ep == et:
            print("  CHIRON UNIFIED SUITE GREEN — one organism, one file, "
                  "real engines, rehabilitated.")
    return ok and ep == et


