def _plain_model(mc):
    """A human description of a model class (no internal jargon)."""
    if not mc:
        return "a structure"
    m = str(mc).lower()
    table = {"constant": "a constant value",
             "arithmetic": "a steady step (each value changes by a fixed amount)",
             "geometric": "a constant ratio (each value is the previous one times a fixed factor)",
             "periodic": "a repeating cycle", "alternating": "an alternating pattern"}
    if m in table:
        return table[m]
    if m.startswith("polynomial"):
        d = "".join(ch for ch in m if ch.isdigit())
        return "a polynomial trend" + (f" (degree {d})" if d else "")
    if m.startswith("linear_recurrence"):
        return "a recurrence (each value built from the ones before it, Fibonacci-like)"
    if "factorial" in m or "multiplicative" in m:
        return "a factorial-style product rule"
    if "holonomic" in m or "recursive" in m:
        return "a deep recursive rule (Catalan-type)"
    if "interleav" in m:
        return "several independent patterns interleaved together"
    return "a rule (" + str(mc).replace("_", " ") + ")"


def _render_certificate(inv, growth, gr, domain, congress, source="ingest", author="unknown"):
    """Render a run as a stakeholder certificate: an executive headline over an
    engineer appendix — a durable, auditable monument to what was found."""
    import datetime as _dt
    verified = bool(getattr(inv, "verified", False))
    mc = getattr(inv, "model_class", "unknown")
    klass = (gr or {}).get("classification", "general")
    when = _dt.datetime.now().strftime("%Y-%m-%d %H:%M")
    if verified:
        headline = f"A repeatable rule was recovered and PROVEN — {_plain_model(mc)}."
        decision = ("Supports decisions that depend on this structure holding: the rule predicted "
                    "held-out values exactly, so it can be relied on and reused.")
        confidence = "High — held-out verified, exact arithmetic."
        cost = "Low cost of error: the proof is reproducible; one failed prediction would falsify it."
    elif mc in ("incompressible", "too_short", "non_finite"):
        headline = "No reliable rule was found; Chiron declines rather than guess."
        decision = "Do not stake a decision on hidden structure here yet — gather more data."
        confidence = "n/a — declined honestly."
        cost = "High cost if forced: acting on absent structure is a guess."
    else:
        headline = f"A candidate rule was found but not yet proven — {_plain_model(mc)}."
        decision = "May guide exploration; do not stake an irreversible decision on it yet."
        confidence = "Medium — fits what was seen, not yet verified on held-out data."
        cost = "Moderate: treat as a lead and confirm before committing."
    L = [f"# CHIRON Certificate",
         f"*{when} · source: {source} · digested author: {author} · owner/architect: {OWNER}*", "",
         "## Executive", f"**Finding.** {headline}",
         f"**Decision it supports.** {decision}",
         f"**Confidence.** {confidence}", f"**Cost of being wrong.** {cost}",
         f"**Classification.** {klass} — " + ("extends Chiron's reusable law library."
            if klass == "integral" else "retained as knowledge in the Congress.")]
    if (gr or {}).get("cross_domain_transfer"):
        L.append("**Cross-domain transfer.** This generator was already known in another domain — "
                 "the same rule spans domains.")
    L.append(f"**Where it stands.** Domain '{domain}'. The Congress now holds "
             f"{congress.get('domains')} domain(s), {congress.get('items')} item(s), and "
             f"{congress.get('integral')} integral law(s).")
    L += ["", "## Engineer appendix"]
    if inv is not None:
        L.append(f"- model class: `{mc}`")
        L.append(f"- verified: `{verified}` · exact: `{getattr(inv, 'exact', None)}` · "
                 f"MDL margin: `{round(getattr(inv, 'margin', 0.0), 2)} bits`")
        L.append(f"- family fingerprint: `{inv.family_fingerprint[:16]}`")
        L.append(f"- generator fingerprint: `{inv.generator_fingerprint[:16]}`")
        try:
            L.append(f"- residual: {classify_residual(inv).get('note', '')}")
        except Exception:
            pass
    t = congress.get("tiers", {})
    L.append(f"- memory tiers: raw {t.get('raw')} · compressed {t.get('compressed')} · "
             f"invariant {t.get('invariant')} · generator {t.get('generator')}")
    L.append("- provenance: owner-signed; Congress sealed (Merkle root advances each run).")
    L.append("- reproduce: `python3 chiron.py collapse <the same input>` (offline, deterministic).")
    return "\n".join(L)


def articulate(inv, n=12, vocab=None):
    """Inverse of collapse — push an Invariant back UP into a surface, spoken in the
    digested thing's own language: regenerate and extend the original, or re-voice the
    same generator into a new vocabulary. collapse + articulate are one faithful codec."""
    dom = getattr(inv, "domain", None)
    out = {"domain": dom, "model_class": getattr(inv, "model_class", None),
           "verified": getattr(inv, "verified", None),
           "generator_fingerprint": (getattr(inv, "generator_fingerprint", "") or "")[:16]}
    if vocab is not None and dom in ("figuregraph", "graph"):
        try:
            out["spoken"] = cast(inv, vocab); out["mode"] = "re-voiced into a new vocabulary"
        except Exception as e:
            out["spoken"] = None; out["mode"] = "cast unavailable"; out["note"] = str(e)
        return out
    try:
        def _clean(x):
            try:
                if hasattr(x, "denominator"):
                    return int(x) if x.denominator == 1 else float(x)
            except Exception:
                pass
            return x
        out["spoken"] = [_clean(x) for x in inv.predict(int(n))]
        out["mode"] = "regenerated + extended in its own language"
    except Exception as e:
        out["spoken"] = None; out["mode"] = "not runnable"; out["note"] = str(e)
    return out


def run_gauntlet():
    """A labeled benchmark: recover known generators across families, with ZERO
    false-verify on controls. Deterministic; the score Chiron can publish."""
    cases = [
        ("constant", [7, 7, 7, 7, 7, 7], True),
        ("arithmetic", [2, 5, 8, 11, 14, 17, 20], True),
        ("arithmetic", [100, 90, 80, 70, 60, 50], True),
        ("geometric", [3, 6, 12, 24, 48, 96], True),
        ("geometric", [1, 2, 4, 8, 16, 32, 64], True),
        ("polynomial", [0, 1, 4, 9, 16, 25, 36], True),
        ("polynomial", [1, 8, 27, 64, 125, 216], True),
        ("polynomial", [2, 5, 10, 17, 26, 37, 50], True),
        ("linear_recurrence", [1, 1, 2, 3, 5, 8, 13, 21, 34], True),
        ("linear_recurrence", [2, 1, 3, 4, 7, 11, 18, 29], True),
        ("linear_recurrence", [0, 1, 1, 2, 4, 7, 13, 24, 44], True),
        ("holonomic", [1, 1, 2, 5, 14, 42, 132, 429, 1430], True),
        ("alternating", [1, -1, 1, -1, 1, -1, 1, -1], True),
        ("periodic", [3, 1, 4, 3, 1, 4, 3, 1, 4], True),
        ("control_primes", [2, 3, 5, 7, 11, 13, 17, 19, 23], False),
        ("control_random", [5, 2, 9, 1, 7, 3, 8, 6], False),
    ]
    rec_t = rec_v = ctl = ctl_f = 0; by = {}
    for fam, seq, recoverable in cases:
        try:
            inv = collapse(seq); v = bool(inv.verified)
        except Exception:
            v = False
        if recoverable:
            rec_t += 1; rec_v += 1 if v else 0
            by.setdefault(fam, {"tested": 0, "recovered": 0})
            by[fam]["tested"] += 1; by[fam]["recovered"] += 1 if v else 0
        else:
            ctl += 1; ctl_f += 1 if v else 0
    return {"recoverable_tested": rec_t, "recovered": rec_v,
            "recovery_rate": round(rec_v / rec_t, 3) if rec_t else 0,
            "controls_tested": ctl, "false_verify": ctl_f, "by_family": by,
            "verdict": "PASS" if (rec_v >= int(0.9 * rec_t) and ctl_f == 0) else "REVIEW"}


# =============================================================================
#  OPTIONAL NATIVE HOT-PATH (monolithic + portable). The C source lives INSIDE
#  this file as a string; on first use it is compiled to a shared library beside
#  the script IF a C compiler is present. If compilation is unavailable, an exact
#  pure-Python fallback is used — so Chiron still runs anywhere with zero installs,
#  and is faster where a toolchain exists. The kernel computes the finite-difference
#  degree of an integer sequence (the hot inner step of polynomial recovery).
# =============================================================================
_CHIRON_FASTOPS_C = r"""
/* Chiron native hot-path. Owner: Jacob Iannotti. */
long long chiron_poly_degree(long long* a, int n) {
    for (int L = 0; L < n; ++L) {
        int m = n - L, eq = 1;
        for (int i = 1; i < m; ++i) { if (a[i] != a[0]) { eq = 0; break; } }
        if (eq) return (long long)L;
        for (int i = 0; i < m - 1; ++i) { a[i] = a[i+1] - a[i]; }
    }
    return -1;
}
"""
_NATIVE = {"tried": False, "fn": None}


def _native_poly_degree_fn():
    """Compile + load the native kernel once; return a callable or None."""
    if _NATIVE["tried"]:
        return _NATIVE["fn"]
    _NATIVE["tried"] = True
    try:
        import ctypes, subprocess, tempfile
        here = os.path.dirname(os.path.abspath(__file__))
        so = os.path.join(here, "chiron_fastops.so")
        if not os.path.exists(so):
            cc = os.environ.get("CC", "cc")
            with tempfile.NamedTemporaryFile("w", suffix=".c", delete=False) as f:
                f.write(_CHIRON_FASTOPS_C); cpath = f.name
            r = subprocess.run([cc, "-O2", "-shared", "-fPIC", "-o", so, cpath],
                               capture_output=True, text=True, timeout=60)
            try:
                os.remove(cpath)
            except OSError:
                pass
            if r.returncode != 0:
                return None
        lib = ctypes.CDLL(so)
        lib.chiron_poly_degree.restype = ctypes.c_longlong
        lib.chiron_poly_degree.argtypes = [ctypes.POINTER(ctypes.c_longlong), ctypes.c_int]

        def _fn(seq):
            n = len(seq)
            arr = (ctypes.c_longlong * n)(*[int(x) for x in seq])
            return int(lib.chiron_poly_degree(arr, n))
        _NATIVE["fn"] = _fn
    except Exception:
        _NATIVE["fn"] = None
    return _NATIVE["fn"]


def _py_poly_degree(seq):
    """Exact pure-Python equivalent of the native kernel (the always-available path)."""
    a = [int(x) for x in seq]; n = len(a)
    for L in range(n):
        m = n - L
        if all(a[i] == a[0] for i in range(1, m)):
            return L
        a = [a[i+1] - a[i] for i in range(m - 1)]
    return -1


def poly_degree(seq):
    """Finite-difference degree of an integer sequence (−1 if not polynomial).
    Uses the native kernel when available, else the identical Python fallback."""
    if all(float(x).is_integer() for x in seq):
        fn = _native_poly_degree_fn()
        if fn is not None:
            try:
                return fn(seq)
            except Exception:
                pass
    return _py_poly_degree(seq)


def _native_cli(argv):
    """bench-native: prove the optional C hot-path matches Python (and time both)."""
    import json as _j, time as _t
    seq = [i*i*i - 2*i + 7 for i in range(64)]            # a degree-3 polynomial
    py = _py_poly_degree(seq)
    fn = _native_poly_degree_fn()
    native_ok = fn is not None
    nat = fn(seq) if native_ok else None
    iters = 20000
    t0 = _t.perf_counter()
    for _ in range(iters):
        _py_poly_degree(seq)
    t_py = _t.perf_counter() - t0
    out = {"native_available": native_ok, "agree": (nat == py) if native_ok else None,
           "degree": py, "python_seconds_20k": round(t_py, 4)}
    if native_ok:
        t0 = _t.perf_counter()
        for _ in range(iters):
            fn(seq)
        t_nat = _t.perf_counter() - t0
        out["native_seconds_20k"] = round(t_nat, 4)
        out["speedup"] = round(t_py / t_nat, 2) if t_nat else None
    else:
        out["note"] = "no C compiler found — pure-Python fallback in use (engine unaffected)"
    print(_j.dumps(out, indent=2)); return 0


def _growth_cli(argv):
    """gauntlet | merge | checkpoint | compact."""
    import json as _j
    verb, rest = argv[0], list(argv[1:])
    mempath = None
    for flag in ("--memory", "--congress"):
        if flag in rest:
            i = rest.index(flag); mempath = rest[i + 1]; del rest[i:i + 2]
    if verb == "gauntlet":
        print(_j.dumps(run_gauntlet(), indent=2)); return 0
    org = (Chiron.load_memory(mempath) if mempath and os.path.exists(mempath) else Chiron())
    if verb == "merge":
        if not rest:
            print("usage: chiron.py merge <other_congress.json> [--memory chiron_memory.json]"); return 2
        r = org.merge_laws(rest[0])
        if mempath:
            org.save_memory(mempath)
        print(_j.dumps(r, indent=2)); return 0
    if verb == "checkpoint":
        print(_j.dumps(org.checkpoint(rest[0] if rest else "."), indent=2)); return 0
    if verb == "compact":
        print(_j.dumps(org.compact(), indent=2)); return 0
    if verb == "recall":
        if not rest:
            print('usage: chiron.py recall "<surface>" --memory chiron_memory.json'); return 2
        print(_j.dumps(org.recognize(" ".join(rest)), indent=2)); return 0
    if verb == "self-growth":
        print(_j.dumps(org.self_growth_state(), indent=2)); return 0
    if verb == "grow-concepts":
        r = org.grow_concepts()
        if mempath:
            org.save_memory(mempath)
        print(_j.dumps(r, indent=2)); return 0
    if verb == "proposals":
        print(_j.dumps(org.list_proposals(rest[0] if rest else "proposals"), indent=2)); return 0
    if verb == "propose":
        if not rest:
            print("usage: chiron.py propose <new_source.py> [target=chiron.py] [\"summary\"]"); return 2
        src = open(rest[0], "r", encoding="utf-8").read()
        target = rest[1] if len(rest) > 1 else "chiron.py"
        summary = rest[2] if len(rest) > 2 else ("operator proposal for " + target)
        print(_j.dumps(org.propose_change(summary, src, target=target), indent=2)); return 0
    if verb == "apply-proposal":
        if not rest:
            print("usage: chiron.py apply-proposal <id> [--auto]"); return 2
        auto = "--auto" in rest; rid = [a for a in rest if a != "--auto"][0]
        print(_j.dumps(org.apply_proposal(rid, autonomous=auto), indent=2)); return 0
    if verb == "rollback-proposal":
        if not rest:
            print("usage: chiron.py rollback-proposal <id>"); return 2
        print(_j.dumps(org.rollback_proposal(rest[0]), indent=2)); return 0
    print("unknown verb:", verb); return 2


def _operator_recommendation(human):
    """Turn a finding into an actionable recommendation for the operator."""
    if not human:
        return ("No compressible generator recovered from this input. Recommendation: "
                "treat as raw knowledge in the Congress; ingest more context or a larger "
                "sample to expose structure.")
    mv = human.get("machine_view", {}) if isinstance(human, dict) else {}
    verified = bool(human.get("verified")) if isinstance(human, dict) else False
    mc = mv.get("model_class", "unknown")
    if verified:
        return (f"VERIFIED generator '{mc}' recovered and proved on held-out terms. "
                "Recommendation: promote to an integral organism (it extends the engine's "
                "reusable law library) and cast it across adjacent domains to hunt twins.")
    return (f"Candidate generator '{mc}' found but not yet proved. Recommendation: retain as "
            "general-knowledge organism, gather more terms, and re-collapse to earn verification.")


def _serve_dashboard(argv):
    """Launch the offline CHIRON operator console (stdlib http.server, bound to
    127.0.0.1 only -- no network egress). Every action runs through the unified
    engine and the Congress. Operator-directed; nothing leaves the host unless the
    operator explicitly enables network search elsewhere."""
    import json as _json, os as _os
    import http.server as _http, urllib.parse as _urlparse
    port, congress_path = 8765, None
    a = list(argv); i = 0
    while i < len(a):
        if a[i] in ("--port", "-p") and i + 1 < len(a): port = int(a[i + 1]); i += 2; continue
        if a[i] in ("--congress", "--memory") and i + 1 < len(a): congress_path = a[i + 1]; i += 2; continue
        i += 1
    here = _os.path.dirname(_os.path.abspath(__file__)) if "__file__" in globals() else _os.getcwd()
    if congress_path is None:
        cand = _os.path.join(here, "chiron_memory.json")
        congress_path = cand if _os.path.exists(cand) else None
    org_box = {"org": (Chiron.load_memory(congress_path)
                       if congress_path and _os.path.exists(congress_path) else Chiron()),
               "mtime": (_os.path.getmtime(congress_path)
                         if congress_path and _os.path.exists(congress_path) else 0),
               "checked": 0.0}
    gate_cache = {}
    _RELOAD_MIN_SECS = 5.0   # never reparse the (large) Congress more than this often

    def _fresh():
        """Return the in-memory Congress, reloading from disk only if a grower has
        written to it AND we haven't reloaded very recently. Reparsing a multi-MB
        Congress on every click would freeze the UI and race the grower's writes,
        so reloads are rate-limited — the console still refreshes within a few seconds."""
        import time as _t
        if not (congress_path and _os.path.exists(congress_path)):
            return org_box["org"]
        now = _t.time()
        if now - org_box["checked"] < _RELOAD_MIN_SECS:
            return org_box["org"]                       # serve the cached copy — fast, no disk
        org_box["checked"] = now
        try:
            m = _os.path.getmtime(congress_path)
            if m != org_box["mtime"]:
                org_box["org"] = Chiron.load_memory(congress_path)
                org_box["mtime"] = m
        except Exception:
            pass                                        # keep the last good copy on any read race
        return org_box["org"]

    def _seq(s):
        if isinstance(s, list): return s
        parts = str(s).replace(",", " ").split()
        try:
            v = [float(x) for x in parts]
        except ValueError:
            return None
        return [int(x) if float(x).is_integer() else x for x in v]

    def _api(path, payload):
        try:
            if path == "/api/meta":
                return {"system": "CHIRON", "owner": OWNER,
                        "nuclei": ["invariant engine", "discovery", "growth", "twin / transfer",
                                   "certifier", "self-critique", "honesty layer",
                                   "executive"],
                        "laws": ["L1 single membrane", "L2 two destinations", "L3 single store",
                                 "L4 single script", "L5 no network (operator-gated)", "L6 determinism",
                                 "L7 provenance", "L8 bounded self-modification"],
                        "verbs": ["collapse", "same-origin", "cast", "audit", "explain", "topk",
                                  "twins", "ingest", "run", "attest", "state", "selftest", "serve"]}
            if path == "/api/state":
                return {"congress": _fresh().state(), "congress_path": congress_path}
            if path == "/api/collapse":
                surf = _seq(payload.get("surface", ""))
                inv = collapse(surf if surf is not None else payload.get("surface", ""))
                return {"invariant": inv.to_dict(), "human": human_report(inv)}
            if path == "/api/articulate":
                try:
                    return {"articulation": org_box["org"].articulate(
                        payload.get("surface", ""), n=int(payload.get("n", 12)))}
                except Exception as e:
                    return {"error": str(e)}
            if path == "/api/topk":
                return {"candidates": top_generators(_seq(payload.get("surface", "")) or [])}
            if path == "/api/guide":
                return collapse_guided(payload.get("surface", ""),
                                       expect=(payload.get("expect") or None),
                                       prefer=(payload.get("prefer") or None))
            if path == "/api/audit":
                return {"audit": audit(payload.get("text", "")).to_dict()}
            if path == "/api/same-origin":
                ia = collapse(_seq(payload.get("a", "")) or payload.get("a", ""))
                ib = collapse(_seq(payload.get("b", "")) or payload.get("b", ""))
                return {"same_family": same_family(ia, ib), "same_generator": same_generator(ia, ib),
                        "same_structure": same_structure(ia, ib)}
            if path == "/api/ingest":
                text = payload.get("text", ""); org = org_box["org"]
                if not str(text).strip():
                    return {"error": "nothing to ingest"}
                try:
                    res = org.assimilate(text, source="dashboard")
                except Exception as e:
                    return {"error": "ingest failed: " + str(e)}
                if congress_path:
                    try: org.save_memory(congress_path)
                    except Exception: pass
                human = None
                try:
                    _s = _seq(text); human = human_report(collapse(_s if _s is not None else text))
                except Exception:
                    human = None
                g = res.get("growth", {}); cg = res.get("congress", {})
                rel = ("Sorted into the '%s' domain (%s; now %s example%s). The Congress now holds "
                       "%s domain(s) and %s item(s). %s"
                       % (g.get("domain", "?"),
                          "a NEW domain" if g.get("is_new") else "an existing domain",
                          g.get("exemplars", "?"), "" if g.get("exemplars") == 1 else "s",
                          cg.get("domains", "?"), cg.get("items", "?"),
                          ("Saved to " + congress_path) if congress_path
                          else "(not persisted — start serve with --congress to write the JSON into your project folder)"))
                return {"ingested": True, "human": human, "growth": g, "congress": cg,
                        "classification": res.get("classification"),
                        "cross_domain_transfer": res.get("cross_domain_transfer"),
                        "certificate_text": res.get("certificate_text"),
                        "congress_path": congress_path, "relation": rel,
                        "recommendation": _operator_recommendation(human)}
            if path == "/api/congress":
                org = _fresh(); reg = org.domains
                doms = [{"name": nm, "exemplars": getattr(fp, "n_exemplars", 0),
                         "charts": list(getattr(fp, "chart_names", []))}
                        for nm, fp in reg.domains.items()]
                live = {d["name"] for d in doms}
                for nm, sm in getattr(org, "_domains_summary", {}).items():
                    if nm not in live:
                        doms.append({"name": nm, "exemplars": sm.get("exemplars", 0),
                                     "charts": sm.get("charts", []), "persisted": True})
                st = org.state(); cd = st.get("Congress", {}) if isinstance(st.get("Congress"), dict) else {}
                gw = org._growth_state()
                try: variance = reg.variance_map()
                except Exception: variance = {}
                return {"domains": doms, "variance": variance,
                        "organisms": list(org.self_mod.history),
                        "languages": st.get("atlas", []), "vault_items": cd.get("vault_items"),
                        "tiers": org.memory_tiers(), "integral": gw["integral"],
                        "general": gw["general"], "cross_domain": gw["cross_domain"],
                        "laws": len(gw["laws"]), "congress_path": congress_path}
            if path == "/api/growth":
                org = _fresh(); gw = org._growth_state()
                _tot = gw["integral"] + gw["general"]
                return {"history": gw["history"], "tiers": org.memory_tiers(),
                        "integral": gw["integral"], "general": gw["general"],
                        "cross_domain": gw["cross_domain"], "reuse": gw.get("reuse", 0),
                        "yield_pct": round(100.0 * gw["integral"] / _tot, 1) if _tot else 0.0,
                        "laws_count": len(gw["laws"]), "membranes": getattr(org, "membranes", {})}
            if path == "/api/self-growth":
                org = _fresh()
                return {"state": org.self_growth_state(),
                        "concepts": list(getattr(org, "concepts", {}).values()),
                        "congress_path": congress_path}
            if path == "/api/source":
                # operator redirects what the grower consumes: writes a control file
                # the grower picks up on its next pass (wikipedia / web / api / oeis).
                ctrl = (os.path.join(os.path.dirname(os.path.abspath(congress_path)), "chiron_control.json")
                        if congress_path else None)
                if not ctrl:
                    return {"error": "start serve with --congress <file> to control the feed"}
                if payload and payload.get("name"):
                    name = payload["name"]; value = str(payload.get("value", "")).strip()
                    if name == "web":
                        src = {"name": "web", "seeds": [s for s in re.split(r"[\s,]+", value) if s],
                               "same_domain_only": bool(payload.get("same_domain_only")),
                               "domain_label": payload.get("domain_label") or "web"}
                    elif name == "api":
                        src = {"name": "api", "list_url": value,
                               "items_path": payload.get("items_path", ""),
                               "id_field": payload.get("id_field", "id")}
                    elif name == "oeis":
                        src = {"name": "oeis", "search_url": "https://oeis.org/search",
                               "query": value or "keyword:core"}
                    else:
                        src = {"name": "wikipedia", "api_url": "https://en.wikipedia.org/w/api.php"}
                    src["verify_ssl"] = True
                    src.setdefault("user_agent", "Chiron-Grow/1.0 (operator-directed; dashboard)")
                    with open(ctrl, "w", encoding="utf-8") as f:
                        _json.dump({"source": src}, f, indent=2)
                    return {"ok": True, "source": src,
                            "note": "the grower switches to this feed on its next pass"}
                try:
                    return {"current": _json.load(open(ctrl, encoding="utf-8")).get("source")}
                except Exception:
                    return {"current": None}
            if path == "/api/ledger":
                gw = _fresh()._growth_state()
                return {"laws": gw["laws"], "history": gw["history"]}
            if path == "/api/gauntlet":
                return {"gauntlet": run_gauntlet()}
            if path == "/api/ingest_path":
                import os as _os2
                tgt = str(payload.get("path", "")).strip(); org = org_box["org"]
                if not tgt or not _os2.path.exists(tgt):
                    return {"error": "path not found on this machine: " + (tgt or "(empty)")}
                before = org.state(); paths = []
                if _os2.path.isdir(tgt):
                    for _r, _d, _fs in _os2.walk(tgt):
                        _d[:] = [d for d in _d if not d.startswith(".")]
                        paths += [_os2.path.join(_r, f) for f in _fs if not f.startswith(".")]
                else:
                    paths = [tgt]
                n_ok = n_skip = 0; errs = []
                for p in sorted(paths):
                    txt = _read_text_file(p)
                    if txt is None:
                        n_skip += 1; continue
                    try:
                        _rec = org.ingest_text(txt, source=_os2.path.basename(p))
                        try: org._form_domain(_rec, name=org._domain_key(txt, _rec))
                        except Exception: pass
                        n_ok += 1
                    except Exception as _e:
                        n_skip += 1
                        if len(errs) < 3:
                            errs.append(_os2.path.basename(p) + ": " + str(_e))
                after = org.state()
                if congress_path:
                    try: org.save_memory(congress_path)
                    except Exception: pass
                ad = after.get("Congress", {}) if isinstance(after.get("Congress"), dict) else {}
                return {"ingested": True, "path": tgt, "files_ingested": n_ok, "files_skipped": n_skip,
                        "errors": errs, "congress_path": congress_path,
                        "congress": {"domains": len(after.get("domains", [])), "items": ad.get("vault_items")},
                        "recommendation": ("Read %d file(s) into the Congress; skipped %d binary/unreadable. "
                                           "The Congress now holds %d domain(s). %s"
                                           % (n_ok, n_skip, len(after.get("domains", [])),
                                              ("Saved to " + congress_path) if congress_path else "(not persisted)"))}
            if path == "/api/selftest":
                if "green" not in gate_cache:
                    gate_cache["green"] = bool(run_selftest(verbose=False))
                return {"green": gate_cache["green"]}
            return {"error": "unknown endpoint: " + path}
        except Exception as e:
            return {"error": str(e)}

    class H(_http.BaseHTTPRequestHandler):
        def log_message(self, *a): pass
        def _send(self, code, body, ctype="application/json"):
            b = body if isinstance(body, (bytes, bytearray)) else str(body).encode("utf-8")
            self.send_response(code); self.send_header("Content-Type", ctype)
            self.send_header("Content-Length", str(len(b)))
            self.send_header("Cache-Control", "no-store"); self.end_headers()
            self.wfile.write(b)
        def do_GET(self):
            p = _urlparse.urlparse(self.path).path
            if p in ("/", "/index.html", "/dashboard.html"):
                f = _os.path.join(here, "dashboard.html")
                body = open(f, "rb").read() if _os.path.exists(f) else _FALLBACK_DASH
                return self._send(200, body, "text/html; charset=utf-8")
            if p.startswith("/api/"):
                return self._send(200, _json.dumps(_api(p, {}), default=str))
            return self._send(404, _json.dumps({"error": "not found"}))
        def do_POST(self):
            p = _urlparse.urlparse(self.path).path
            n = int(self.headers.get("Content-Length", 0) or 0)
            raw = self.rfile.read(n) if n else b""
            try: payload = _json.loads(raw.decode("utf-8")) if raw else {}
            except Exception: payload = {}
            return self._send(200, _json.dumps(_api(p, payload), default=str))

    httpd = _http.ThreadingHTTPServer(("127.0.0.1", port), H)
    url = f"http://127.0.0.1:{port}"
    print("=" * 64, flush=True)
    print(f"  CHIRON console is RUNNING — open this in your browser:\n      {url}", flush=True)
    print(f"  Congress: {congress_path or '(ephemeral — pass --congress chiron_memory.json to persist)'}", flush=True)
    print("  (this window stays open while the console runs; press Ctrl-C to stop)", flush=True)
    print("=" * 64, flush=True)
    if os.environ.get("CHIRON_NO_BROWSER") != "1":     # auto-open unless suppressed
        try:
            import webbrowser, threading
            threading.Timer(1.0, lambda: webbrowser.open(url)).start()
        except Exception:
            pass
    try:
        httpd.serve_forever()
    except KeyboardInterrupt:
        print("\nCHIRON console stopped.")
    return 0


# ============================================================================
#  KEYED CONGRESS STORAGE — authenticated, offline, stdlib-only. The key is a
#  separate file that must sit beside the monolith to open a sealed Congress;
#  move it out for security. Confidentiality via SHA-256 keystream, integrity
#  and authentication via HMAC-SHA256 (wrong/absent key -> refuses to open).
# ============================================================================
def _chiron_key(path=None, create=True):
    import os as _os
    here = _os.path.dirname(_os.path.abspath(__file__)) if "__file__" in globals() else _os.getcwd()
    path = path or _os.path.join(here, "chiron.key")
    if _os.path.exists(path):
        raw = open(path, "rb").read().strip()
        key = bytes.fromhex(raw.decode()) if len(raw) == 64 else raw
        return ((key + b"\0" * 32)[:32], path)
    if not create:
        raise FileNotFoundError("Congress key not found: " + path)
    key = _os.urandom(32)
    open(path, "wb").write(key.hex().encode())
    try: _os.chmod(path, 0o600)
    except Exception: pass
    return key, path


def _keystream(key, nonce, n):
    import hashlib as _h
    out = bytearray(); ctr = 0
    while len(out) < n:
        out += _h.sha256(key + nonce + ctr.to_bytes(8, "big")).digest(); ctr += 1
    return bytes(out[:n])


def _seal_bytes(plain, key):
    import os as _os, hmac as _hmac, hashlib as _h
    nonce = _os.urandom(16)
    ct = bytes(p ^ k for p, k in zip(plain, _keystream(key, nonce, len(plain))))
    return b"CHIRONSEAL1" + nonce + _hmac.new(key, nonce + ct, _h.sha256).digest() + ct


def _unseal_bytes(blob, key):
    import hmac as _hmac, hashlib as _h
    if not blob.startswith(b"CHIRONSEAL1"):
        raise ValueError("not a Chiron sealed container")
    body = blob[11:]; nonce, tag, ct = body[:16], body[16:48], body[48:]
    if not _hmac.compare_digest(tag, _hmac.new(key, nonce + ct, _h.sha256).digest()):
        raise ValueError("authentication failed — wrong key or tampered Congress")
    return bytes(c ^ k for c, k in zip(ct, _keystream(key, nonce, len(ct))))


def _crypto_cli(argv):
    """seal | unseal — keyed, authenticated Congress storage (stdlib only)."""
    verb, rest = argv[0], list(argv[1:])
    keypath = None
    if "--key" in rest:
        i = rest.index("--key"); keypath = rest[i + 1]; del rest[i:i + 2]
    if not rest:
        print("usage: chiron.py %s <file> [--key chiron.key]" % verb); return 2
    src = rest[0]
    try:
        key, kp = _chiron_key(keypath, create=(verb == "seal"))
    except FileNotFoundError as e:
        print("ERROR:", e); return 2
    data = open(src, "rb").read()
    if verb == "seal":
        out = src.rsplit(".", 1)[0] + ".sealed"
        open(out, "wb").write(_seal_bytes(data, key))
        print("sealed -> %s   key: %s" % (out, kp))
        print("move the key out of the folder to lock the Congress; restore it to open.")
        return 0
    try:
        plain = _unseal_bytes(data, key)
    except ValueError as e:
        print("ERROR:", e); return 2
    out = src.rsplit(".", 1)[0] + ".json"
    open(out, "wb").write(plain); print("unsealed -> %s" % out); return 0


