# ===========================================================================
#  FACES OF THE LAW
# ===========================================================================
def collapse(surface, surface_b=None) -> Invariant:
    if surface_b is not None:
        return collapse_transform(str(surface), str(surface_b))
    if isinstance(surface, Invariant):
        return surface
    if isinstance(surface, dict) and "walks" in surface:
        return collapse_figuregraph(surface["walks"], surface.get("tokens"),
                                    surface.get("invariants"))
    if isinstance(surface, dict) and "edges" in surface:
        nodes = surface.get("nodes") or sorted({n for e in surface["edges"] for n in e})
        return collapse_graph(nodes, [tuple(e) for e in surface["edges"]])
    if isinstance(surface, dict) and "code" in surface:
        return collapse_code(surface["code"], surface.get("language", "python"))
    if isinstance(surface, (list, tuple)):
        if all(isinstance(x, (int, float, Fraction)) for x in surface):
            return collapse_numeric(list(surface))
        return collapse_string("".join(map(str, surface)))
    if isinstance(surface, str):
        return collapse_string(surface)
    raise VeritasError(f"cannot collapse {type(surface)}")


def collapse_code(src: str, language="python") -> Invariant:
    if language != "python":
        return Invariant("code", "unsupported_language", {"language": language},
                         {"family": "none"}, 1e9, 1e9, [src], True, False, 0.0, 0.0,
                         f"Code adapter supports Python; '{language}' not parsed.")
    import ast as _ast
    try:
        tree = _ast.parse(src)
    except SyntaxError as e:
        return Invariant("code", "unparseable", {"error": str(e)}, {"family": "none"},
                         1e9, 1e9, [src], True, False, 0.0, 0.0, f"Did not parse: {e}")
    seq = []
    for node in _ast.walk(tree):
        t = type(node).__name__
        if t in ("Name", "arg"):
            seq.append("VAR")
        elif t in ("Constant", "Num", "Str"):
            seq.append("LIT")
        else:
            seq.append(t)
    from collections import Counter
    st = {"family": "code", "n_nodes": len(seq),
          "histogram": dict(sorted(Counter(seq).items())),
          "skeleton_hash": hashlib.sha1("".join(seq).encode()).hexdigest()[:16],
          "verified": True}
    return Invariant("code", "ast_skeleton", {"language": language}, st,
                     st["n_nodes"] * 1.5, len(src) * 2.0, [], True, True, 1.0, 0.0,
                     f"Structure-only AST skeleton: {st['n_nodes']} nodes "
                     f"(identifiers/literals abstracted). Same skeleton => clone "
                     f"through renaming/reformatting.")


def same_family(a, b):
    m = a.family_fingerprint == b.family_fingerprint
    return {"same_family": m, "claim_strength": "weak (model class only)"}


def same_generator(a, b):
    m = a.generator_fingerprint == b.generator_fingerprint
    return {"same_generator": m, "claim_strength": "strong (class + parameters)"}


def same_structure(a, b):
    if a.domain != b.domain:
        return {"same_structure": False,
                "explanation": f"different domains ({a.domain} vs {b.domain}); structure incomparable"}
    if a.domain in ("figuregraph",):
        m = a.family_fingerprint == b.family_fingerprint
    elif a.domain == "graph":
        sa, sb = a.structure, b.structure
        m = (sa["degree_sequence"] == sb["degree_sequence"]
             and sa["triangles"] == sb["triangles"]
             and sa["closed_walks"] == sb["closed_walks"])
    elif a.domain == "code":
        m = a.structure.get("skeleton_hash") == b.structure.get("skeleton_hash")
    else:
        m = a.family_fingerprint == b.family_fingerprint
    return {"same_structure": bool(m),
            "explanation": ("identical structural skeleton (relabel-invariant)" if m
                            else "structural skeletons differ")}


def cast(inv, new_tokens):
    if inv.domain == "figuregraph":
        walks = inv.params["walks"]
        return {"new_surface_walks": {w: [new_tokens.get(n, n) for n in p] for w, p in walks.items()},
                "shares_skeleton": True, "shares_skeleton_with_source": True,
                "family_fingerprint": inv.family_fingerprint[:16]}
    if inv.domain == "graph":
        return {"new_edges": [[new_tokens.get(u, u), new_tokens.get(v, v)] for u, v in inv.params["edges"]],
                "shares_skeleton": True, "shares_skeleton_with_source": True}
    raise VeritasError("cast defined for figuregraph/graph")


def transcode(source, target, rounds=4):
    s_nodes = source.get("nodes") or sorted({n for e in source["edges"] for n in e})
    t_nodes = target.get("nodes") or sorted({n for e in target["edges"] for n in e})
    s_sig = wl_signatures(s_nodes, [tuple(e) for e in source["edges"]], rounds)
    t_sig = wl_signatures(t_nodes, [tuple(e) for e in target["edges"]], rounds)
    t_by = {}
    for nd, sg in t_sig.items():
        t_by.setdefault(sg, []).append(nd)
    mapping, ambiguous, unplaced = {}, {}, []
    for nd, sg in s_sig.items():
        c = t_by.get(sg, [])
        if len(c) == 1:
            mapping[nd] = c[0]
        elif len(c) > 1:
            ambiguous[nd] = c
        else:
            unplaced.append(nd)
    return {"mapping": mapping, "ambiguous": ambiguous, "unplaced": unplaced,
            "confidence": round(len(mapping) / max(1, len(s_nodes)), 4),
            "method": "Weisfeiler-Leman structural-role correspondence"}


